--
-- Estructura para la vista `RXN_LIVE_VW_CLIENTES`
--
DROP TABLE IF EXISTS `RXN_LIVE_VW_CLIENTES`;

CREATE ALGORITHM=UNDEFINED DEFINER=`rxn_suite_core`@`%` SQL SECURITY DEFINER VIEW `RXN_LIVE_VW_CLIENTES`  AS SELECT `crm_clientes`.`id` AS `id`, `crm_clientes`.`empresa_id` AS `empresa_id`, `crm_clientes`.`razon_social` AS `razon_social`, `crm_clientes`.`documento` AS `documento`, `crm_clientes`.`email` AS `email`, `crm_clientes`.`telefono` AS `telefono`, CASE WHEN `crm_clientes`.`activo` = 1 THEN 'Activo' ELSE 'Inactivo' END AS `estado`, cast(`crm_clientes`.`created_at` as date) AS `fecha_registro`, 1 AS `cantidad` FROM `crm_clientes` WHERE `crm_clientes`.`deleted_at` is null ;

-- --------------------------------------------------------

--
-- Estructura para la vista `RXN_LIVE_VW_PEDIDOS_SERVICIO`
--
DROP TABLE IF EXISTS `RXN_LIVE_VW_PEDIDOS_SERVICIO`;

CREATE ALGORITHM=UNDEFINED DEFINER=`rxn_suite_core`@`%` SQL SECURITY DEFINER VIEW `RXN_LIVE_VW_PEDIDOS_SERVICIO`  AS SELECT `ps`.`empresa_id` AS `empresa_id`, `ps`.`cliente_nombre` AS `razon_social`, `ps`.`articulo_codigo` AS `codigo_articulo`, `ps`.`articulo_nombre` AS `articulo_factura`, `ps`.`cliente_id` AS `cliente_id`, `ps`.`numero` AS `id_pedidoservicio`, cast(`ps`.`fecha_inicio` as date) AS `fecha`, `ps`.`solicito` AS `solicitante`, `ps`.`usuario_id` AS `id_tecnico`, `ps`.`usuario_nombre` AS `usuario`, replace(replace(`ps`.`diagnostico`,'\r',' '),'\n',' ') AS `diagnostico`, `ps`.`tiempo_decimal` AS `totalpds`, `c`.`codigo_tango` AS `cod_tango`, coalesce(nullif(`ps`.`tango_nro_pedido`,''),`ps`.`nro_pedido`) AS `nro_pedido_tango`, `ps`.`clasificacion_codigo` AS `clasificacion`, `ps`.`tango_estado` AS `tango_estado`, CASE `ps`.`tango_estado` WHEN 2 THEN 'Aprobado' WHEN 3 THEN 'Cumplido' WHEN 4 THEN 'Cerrado' WHEN 5 THEN 'Anulado' ELSE 'Sin sync' END AS `tango_estado_label`, `ps`.`tango_estado_sync_at` AS `tango_estado_sync_at`, 1 AS `cantidad` FROM (`crm_pedidos_servicio` `ps` left join `crm_clientes` `c` on(`ps`.`cliente_id` = `c`.`id`)) WHERE `ps`.`deleted_at` is null ;

-- --------------------------------------------------------

--
-- Estructura para la vista `RXN_LIVE_VW_VENTAS`
--
DROP TABLE IF EXISTS `RXN_LIVE_VW_VENTAS`;

CREATE ALGORITHM=UNDEFINED DEFINER=`rxn_suite_core`@`%` SQL SECURITY DEFINER VIEW `RXN_LIVE_VW_VENTAS`  AS SELECT `p`.`id` AS `pedido_id`, `p`.`empresa_id` AS `empresa_id`, `p`.`total` AS `total`, `p`.`estado_tango` AS `estado_sincronizacion`, replace(replace(`p`.`observaciones`,'\r',' '),'\n',' ') AS `observaciones`, trim(concat(coalesce(`c`.`nombre`,''),' ',coalesce(`c`.`apellido`,''))) AS `cliente_nombre`, `c`.`email` AS `cliente_email`, cast(`p`.`created_at` as date) AS `fecha`, 1 AS `cantidad` FROM (`pedidos_web` `p` left join `clientes_web` `c` on(`p`.`cliente_web_id` = `c`.`id`)) WHERE `p`.`activo` = 1 ;

