(48, 1, 9, 'Vir Quaglia', 'PDS #16051 — BIOMAT INSTRUMENTAL S R L', 'Araceli\n\nA solicitud por email se creo la cuenta 512003 en Tesorería, la descripción es “Ingreso recupero siniestros por ART”.y se parametrizo con su correspondiente cuenta contable 512003 RECUPERO SINIESTROS ART.', NULL, '2026-04-09 11:57:00', '2026-04-09 12:15:00', 0, '#0d6efd', 'completado', 'pds', 51, '4aar7eh9vk0r1orm6gtfivhpoo', 'primary', '2026-04-12 13:37:33', NULL, '[{\"auth_id\":1,\"google_event_id\":\"4aar7eh9vk0r1orm6gtfivhpoo\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:33\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:33', NULL),
(49, 1, 8, 'Seba Mora', 'PDS #16052 — ALAMBRES RUMBOS S.A.', 'Romina | VQ\n\nActualización por inconvenientes con ARBA / Se realiza backup de Empresas. Se descarga último hotfix.  Se instala hotfix 3813. Se actualizan las empresas.', NULL, '2026-04-08 18:30:00', '2026-04-08 21:30:00', 0, '#0d6efd', 'completado', 'pds', 52, '22gbvkrb5m9sccq9b5urkt6e74', 'primary', '2026-04-12 13:37:34', NULL, '[{\"auth_id\":1,\"google_event_id\":\"22gbvkrb5m9sccq9b5urkt6e74\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:34\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:34', NULL),
