(52, 1, 8, 'Seba Mora', 'PDS #16055 — HILADOS INDUSTRIALES S.R.L.', 'SDM\n\nInstalación de nueva licencia de Tango para 4 Puestos \r\n#imagen1', NULL, '2026-04-09 14:39:00', '2026-04-09 14:48:00', 0, '#0d6efd', 'completado', 'pds', 55, 'rrgr16b3o16qbktkcehbrjgjio', 'primary', '2026-04-12 13:37:34', NULL, '[{\"auth_id\":1,\"google_event_id\":\"rrgr16b3o16qbktkcehbrjgjio\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:34\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:34', NULL),
(53, 1, 1, 'Charly Yaciofani', 'PDS #16056 — CREACIONES MA YO FAVEN S R L', 'Lista admin\n\nAlgunos intercambios internos, se ingresa a server a controlar, el estado de Tango, se revisa servicio SQL y visor de eventos, no se encuentran problemas.', NULL, '2026-04-08 08:40:00', '2026-04-08 08:43:00', 0, '#0d6efd', 'completado', 'pds', 56, 'uukmao5do1elo9c990pqikvbgo', 'primary', '2026-04-12 13:37:35', NULL, '[{\"auth_id\":1,\"google_event_id\":\"uukmao5do1elo9c990pqikvbgo\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:35\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:35', NULL),
(54, 1, 1, 'Charly Yaciofani', 'PDS #16057 — ASOPROFARMA ASOCIACION PROPIETARIOS DE FARMACIAS COOPERATIVA', 'Joel\n\nNo se imputa, ases comercial: Se avisa a Joel que es necesario actualizar, que la versión actual del sistema está sin soporte, sería importante migrar cuanto antes. Se comenta que los menús y el sistema en general no varía, solo se migran diferentes ventanas al proceso web, pero que en esencia el sistema sigue siendo el mismo, se aguardará el ok para migrar.', NULL, '2026-04-08 10:15:00', '2026-04-08 11:10:00', 0, '#0d6efd', 'completado', 'pds', 57, 'qqafsb435c9o1hq3p52nqb7he8', 'primary', '2026-04-12 13:37:35', NULL, '[{\"auth_id\":1,\"google_event_id\":\"qqafsb435c9o1hq3p52nqb7he8\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:35\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:35', NULL),
(55, 1, 1, 'Charly Yaciofani', 'PDS #16058 — LADY WAY SRL', 'Susana\n\nIntercambios con Susana, se avisa que se requiere migrar, sin embargo en la versión D5 el sistema requiere de suscribirse a la \"mejora\" de Tango API para poder facturar y emitir pedidos a través de la APP de consumo de API. Se pasará presupuesto con estos detalles para poder agendar migración', NULL, '2026-04-08 08:31:00', '2026-04-08 08:39:00', 0, '#0d6efd', 'completado', 'pds', 58, 'i98ca8gqus86vacpqv54plok8s', 'primary', '2026-04-12 13:37:35', NULL, '[{\"auth_id\":1,\"google_event_id\":\"i98ca8gqus86vacpqv54plok8s\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:35\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:35', NULL),
(56, 1, 1, 'Charly Yaciofani', 'PDS #16059 — AQUILES SERVICE S.A.', 'Hernan | Flavia\n\nVarios intercambios con Hernan por tema sesiones de CRM, se pide que se controle a través del proceso de licencias de CRM ( #imagen1 y  #imagen2 ). Varios intercambios más porque después de intentar re-establecer la información de la licencia el sistema sigue pegado, por lo que se ingresa a server y se termina matando la sesión pegada a través de SP_WHO2.\r\nOtros intercambios con Flavia por tema eliminación de campo vinculación de cliente contra el de Tango, se consulta con CRM, se analiza la respuesta, pero no se encuentran indicios que alguien lo haya eliminado. Se continuará luego', NULL, '2026-04-08 09:27:04', '2026-04-08 15:02:00', 0, '#0d6efd', 'completado', 'pds', 59, 'qicc37vbgg1pk95j93v45l630c', 'primary', '2026-04-12 13:37:35', NULL, '[{\"auth_id\":1,\"google_event_id\":\"qicc37vbgg1pk95j93v45l630c\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:35\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:35', NULL),
(57, 1, 1, 'Charly Yaciofani', 'PDS #16060 — AGRUPACION DE COLABORACION GRUPO PARAMEDIC', 'Pablo\n\nAlgunos intercambios con Pablo por tema alta de usuario y acceso a la configuración de usuario, se avisa que ese circuito nunca se modificó y se accede a través del administrador general, se pide que se revise que el \"solo procesos web\" esté deshabilitado  #imagen1', NULL, '2026-04-08 10:36:00', '2026-04-08 11:29:00', 0, '#0d6efd', 'completado', 'pds', 60, '4ifkphpgcilpd72rp2ulaenspg', 'primary', '2026-04-12 13:37:36', NULL, '[{\"auth_id\":1,\"google_event_id\":\"4ifkphpgcilpd72rp2ulaenspg\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:36\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:36', NULL),
(58, 1, 1, 'Charly Yaciofani', 'PDS #16061 — FUNDATEC FUNDACION UNIDAD ACADEMICA RIO GRANDE DE', 'Claudia\n\nVarios intercambios con Claudia por tema cursos de Tango, se avisa que acaba de pasar horizontes y que las inscripciones ya cerraron, se avisará la próxima, aunque se cree que van a volver a abrir. Se intercambia sobre la posibilidad de capacitar a medida, se comenta que se podría armar algo. Finalmente comenta que impartirá capacitación interna por lo que se propone crear una empresa copia para usar lo mismos datos actuales, sin movimientos. Se crea base de datos copia y se generan los permisos para el usuario de Claudia.', NULL, '2026-04-10 08:55:00', '2026-04-10 12:02:00', 0, '#0d6efd', 'completado', 'pds', 61, 'pp8vhe3v4b75gdctcrqck42q5c', 'primary', '2026-04-12 13:37:36', NULL, '[{\"auth_id\":1,\"google_event_id\":\"pp8vhe3v4b75gdctcrqck42q5c\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:36\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:36', NULL),
(59, 1, 1, 'Charly Yaciofani', 'PDS #16062 — AGRUPACION DE COLABORACION GRUPO PARAMEDIC', 'Fernando\n\nAlgunos intercambios con Fernando por tema generación de ARBA, pasa captura de dónde está queriendo generar el informe, se confirma, se avisa que Ax tmb estuvo trabajando sobre esta funcionalidad debido a que se fue implementando \"sobre la marcha\". Cualquier cosa que avise y lo reportamos.', NULL, '2026-04-09 17:18:00', '2026-04-09 18:08:00', 0, '#0d6efd', 'completado', 'pds', 62, 'ai7gi1igcg5sgeg60jglr59oh0', 'primary', '2026-04-12 13:37:37', NULL, '[{\"auth_id\":1,\"google_event_id\":\"ai7gi1igcg5sgeg60jglr59oh0\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:37\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:37', NULL),
(60, 1, 8, 'Seba Mora', 'PDS #16063 — HILADOS INDUSTRIALES S.R.L.', 'Matias | General\n\nMatias indica que no pueden acceder a Tango.  Se ingresa al server y se detecta que fueron infectados con un ransomware  #imagen1 , por lo que deben reinstalar el servidor de manera completa o bien, brindar otro equipo para avanzar con la reinstalación completa de Tango.\r\nBrindan acceso a otro equipo. Se renombra equipo a TANGOSERVER.  Se descarga Tango, SQL, SQL Management, backups de base de datos en Nexo.\r\nSe procede a instalar SQL, SQL Management y Tango con el último Hotfix 3841-  Se restauran las empresas, se reconfigura servidor.  Se realiza configuración para que al buscar HILADOS_INDUSTR se conecte a TANGOSERVER.  Se actualizan empresas. Se dan de alta usuarios de red.  Se corrobora acceso de los otros equipos al Tango.\r\nFuera de hora: Se instala Softether para generar acceso VPN. Se resuelve inconveniente con RDP ya que el server no permitia las conexiones por RDP.  Queda armar el instructivo para instalar cliente VPN en equipos para luego acceder por RDP al servidor', NULL, '2026-04-10 09:35:00', '2026-04-10 18:35:00', 0, '#0d6efd', 'completado', 'pds', 63, 'k4kpj5iehkrcoto3c2sp21r7oc', 'primary', '2026-04-12 13:37:37', NULL, '[{\"auth_id\":1,\"google_event_id\":\"k4kpj5iehkrcoto3c2sp21r7oc\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:37\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:37', NULL),
(61, 1, 8, 'Seba Mora', 'PDS #16064 — IRON GROUP S.A.', 'Paula | VQ\n\nProblemas con ARBA | Backup de empresas, descarga e instalación de Hotfix 3847 en empresa Iron Group S.A. | Paula prueba el envío de información a ARBA, sale OK-  Se instala actualización en resto de las empresas', NULL, '2026-04-10 16:20:00', '2026-04-10 20:00:00', 0, '#0d6efd', 'completado', 'pds', 64, 'pmoqocrvefibplms0e103asc9g', 'primary', '2026-04-12 13:37:37', NULL, '[{\"auth_id\":1,\"google_event_id\":\"pmoqocrvefibplms0e103asc9g\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:37\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:37', NULL),
(62, 1, 7, 'Sergio Majeras', 'PDS #16065 — AQUILES SERVICE S.A.', 'Flavia\n\nConfiguración de usuario FLAVIA y habilitación en todos los perfiles de la empresa. Se cambia el usuario de NEXO al user SUPERVISOR activando el aquiles.soporte@rxn. Se configura TIENDAS y se destilda masivamente el parámetro de \"Publica en Tango Tiendas\" para que se puedan obtener las publicaciones, relacionarlas con los artículos e ir completando la lista de precios creadas para ML.', NULL, '2026-04-10 19:01:00', '2026-04-10 20:49:00', 0, '#0d6efd', 'completado', 'pds', 65, 't6k9tvnsvfs4njnt2fc8gpgph4', 'primary', '2026-04-12 13:37:38', NULL, '[{\"auth_id\":1,\"google_event_id\":\"t6k9tvnsvfs4njnt2fc8gpgph4\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:38\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:38', NULL),
(63, 1, 1, 'Charly Yaciofani', 'PDS #16066 — HILADOS INDUSTRIALES S.R.L.', 'Matias\n\nConsulta de Matías por tema Tango que no se puede usar desde ninguna terminal, se pide que se consulte al chat gral de RXN para avanzar ahí con Seba.', NULL, '2026-04-10 09:00:00', '2026-04-10 09:01:00', 0, '#0d6efd', 'completado', 'pds', 66, '5h9r7f1aapiveh7ghg2l5u3do4', 'primary', '2026-04-12 13:37:38', NULL, '[{\"auth_id\":1,\"google_event_id\":\"5h9r7f1aapiveh7ghg2l5u3do4\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:38\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:38', NULL),
(64, 1, 1, 'Charly Yaciofani', 'PDS #16067 — BIOMAT INSTRUMENTAL S R L', 'Gabriel\n\nConsulta de Gabriel por tema emisión de comprobantes electrónicos, pasa captura de pantalla (#imagen1), se avisa que es inconveniente de los servidores de ARCA por lo que tendría que probar de obtener CAE intermitentemente.', NULL, '2026-04-10 11:01:00', '2026-04-10 11:04:00', 0, '#0d6efd', 'completado', 'pds', 67, 'ctsov9q0sg9iio2e43j6cpvii8', 'primary', '2026-04-12 13:37:38', NULL, '[{\"auth_id\":1,\"google_event_id\":\"ctsov9q0sg9iio2e43j6cpvii8\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:38\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:38', NULL),
(65, 1, 1, 'Charly Yaciofani', 'PDS #16068 — SEGURCOOP COOPERATIVA DE SEGUROS LIMITADA', 'Ana\n\nContacto de Ana, avisa que es requerido instalar el último HF en Tango según lo solicitado por Gaby (RXN), se ingresa a server y previo respaldo se ejecuta sobre todas las bases de datos, se avisa que el cliente de Tango pedirá actualizar, tema cerrado.', NULL, '2026-04-10 10:54:00', '2026-04-10 12:14:00', 0, '#0d6efd', 'completado', 'pds', 68, 'sjumbk2k74vuu2c1ebg1m3bmak', 'primary', '2026-04-12 13:37:38', NULL, '[{\"auth_id\":1,\"google_event_id\":\"sjumbk2k74vuu2c1ebg1m3bmak\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:38\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:38', NULL),
(66, 1, 1, 'Charly Yaciofani', 'PDS #16069 — TECCAM SRL', 'Carolina\n\nIntercambios con Carolina por tema CAE que no se puede obtener, se avisa que el inconveniente es de ARCA y debe probar intermitentemente.', NULL, '2026-04-10 12:16:00', '2026-04-10 12:21:00', 0, '#0d6efd', 'completado', 'pds', 69, '75suj5epd5ovhf420spmomm7fk', 'primary', '2026-04-12 13:37:39', NULL, '[{\"auth_id\":1,\"google_event_id\":\"75suj5epd5ovhf420spmomm7fk\",\"calendar_id\":\"primary\",\"synced_at\":\"2026-04-12 13:37:39\"}]', '2026-04-12 15:50:53', '2026-04-12 16:37:39', NULL);
