(78, 1, 758, NULL, 'ALASUR Tango 035810/002  24.01.000  CUOTAS', 'Estimado cliente:\nLos códigos de cuota que a continuación se detallan corresponden al sistema:\nNúmero de llave: 035810/002 \n\nTerminales:5\n\nVersión:24.01.000\n\nMódulos:Compras - Contabilidad - Contabilidad Astor - Live web. - Stock - Tablero de control - Tesorería - Ventas.\n\nFunciones opcionales: APIS Tipo ABM\n\nNexo: Tango Backup: Si - Tango Clientes: Si - Tango Cobranzas: Si - Tango Connect: Si - Tango Fichadas: Si - Tango Update: Si - Tango Reportes: Si - Espacio Nexo: 1000 Mb - Espacio Backup: 4000 Mb - Tango Tablero: Si	 	Vea aquí como ingresar su cuota\n\n \nSi no puede ver este video, acceda al instructivo desde aquí.\n\n \ncuotas@axoft.com\n\nCuota:	Código:	\n	\n1-66488630	  03.01 x mail a Administracion Alasur <admalasur@gmail.com>\n2-44930499	  07.02 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar>\n3-12136310	  17.03 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n4-30875336	  25.04 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n5-79753349	  03.06 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n6-27474680	  04.07 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n7-54153369	  07.08 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n8-76050303	  10.09 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n9-52836280	  16.10 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n10-93413680	  25.11 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n11-72561643	  02.01 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar\n12-60148283	  06.02 x mail a Local Roca Alasur SA <localroca@alasursa.com.ar', '', 1, '2026-04-02 15:40:29', '2026-04-02 15:40:29', NULL),
(79, 1, 785, NULL, 'AXOFT - Script LIVE - ARISTON - Sales Report 2014', 'SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED\nSET DATEFORMAT DMY\nSET DATEFIRST 7\nSELECT~~~~\nGVA12.FECHA_EMIS,\n\'ARA5\' AS SALES_COMPANY_CODE,\nCASE GVA53.T_COMP WHEN \'FAC\' THEN \'I\' WHEN \'N/D\' THEN \'I\' ELSE \'C\' END AS DOCUMENT_KIND,\n\'\' AS CREDIT_NOTE_TYPE,\n\'\' AS ORDER_REASON,\nLEFT(GVA53.N_COMP, 1) + RIGHT(GVA53.N_COMP, 9) AS DOCUMENT_NUMBER,\nGVA53.N_RENGL_V AS DOCUMENT_ITEM,\nCASE WHEN DATEPART(DAY, GVA12.FECHA_EMIS)~~< 10 THEN \'0\' + CAST(DATEPART(DAY, GVA12.FECHA_EMIS) AS CHAR(1)) ELSE CAST(DATEPART(DAY, GVA12.FECHA_EMIS) AS CHAR(2)) END +\nCASE WHEN DATEPART(MONTH, GVA12.FECHA_EMIS)~~< 10 THEN \'0\' + CAST(DATEPART(MONTH, GVA12.FECHA_EMIS) AS CHAR(1)) ELSE CAST(DATEPART(MONTH, GVA12.FECHA_EMIS) AS CHAR(2)) END +\n+ CAST(DATEPART(YEAR, GVA12.FECHA_EMIS) AS CHAR(4)) AS DOCUMENT_DATE,\n\'\' AS PAYMENT_CONDITION,\nCASE GVA12.MON_CTE WHEN 1 THEN \'ARS\' ELSE \'USD\' END AS DOCUMENT_CURRENCY,\n\'\' AS POSTAL_CODE_SHIP_PARTY,\n\'700959\' AS CUSTOMER_CODE_SHIP_PARTY,\n\'700959\' AS CUSTOMER_CODE_SOLD_PARTY,\n\'700959\' AS CUSTOMER_CODE_BILL_PARTY,\n\'700959\' AS CUSTOMER_CODE_PAYER,\n\'\' AS SALESMAN,\n\'\' AS SALESMAN_TO,\n\'\' AS SALES_ORGANIZATION,\n\'\' AS DISTRIBUTION_CHANNEL,\n\'\' AS DIVISION,\n\'\' AS SALES_OFFICE,\n\'\' AS SALES_GROUP,\n\'AR\' AS COUNTRY_CODE_SHIP_PARTY,\n\'AM\' AS MARKET, \'RDC\' AS AREA,\nRXN_ARTICULOS.COD_ARTICU AS [PRODUCT_CODE],\nRXN_ARTICULOS.PRODUCTION_PLANT AS [PRODUCTION_PLANT],\nRXN_ARTICULOS.PLANT AS [SALES_PLANT],\nRXN_ARTICULOS.BRAND AS [BRAND],\nSUBSTRING(RXN_ARTICULOS.COD_FLIAPROD, 1, 2) AS [BUSINESS_LINE],\nSUBSTRING(RXN_ARTICULOS.COD_FLIAPROD, 6, 2) AS [CATEGORY],\nSUBSTRING(RXN_ARTICULOS.COD_FLIAPROD, 11, 3) AS [FAMILY_PRODUCT],\nSUM(CASE WHEN GVA12.T_COMP <> \'FAC\' AND GVA15.TIPO_COMP = \'C\' THEN (- 1) ELSE (1) END * GVA53.CANTIDAD) AS [QUANTITY],\n\'PCE\' AS [UNIT_MEASURE],\n0 AS [GROSS_AMOUNT_DOC_CURR], 0 AS [DISCOUNT_DOC_CURR],0 AS [ADDITIONAL_AMOUNT_DOC_CURR], 0 AS [NET_AMOUNT_DOC_CURR],\nSUM(CASE WHEN GVA12.T_COMP <> \'FAC\' AND GVA15.TIPO_COMP = \'C\' THEN (- 1) ELSE (1)\n~~~~~~~~~~~~~~~~~~~~~~END * CASE GVA12.COTIZ WHEN 0 THEN 0 ELSE CASE \'BIMONCTE\' WHEN \'BIMONCTE\' THEN (CASE GVA12.MON_CTE WHEN 1 THEN GVA53.IMP_NETO_P\n~~~~~~~~~~~~~~~~~~~~~~ ELSE GVA53.IMP_NETO_P * GVA12.COTIZ END)\n~~~~~~~~~~~~~~~~~~~~~~WHEN \'BIORIGEN\' THEN (CASE GVA12.MON_CTE WHEN 1 THEN GVA53.IMP_NETO_P / GVA12.COTIZ ELSE GVA53.IMP_NETO_P END)\n~~~~~~~~~~~~~~~~~~~~~~WHEN \'BICOTIZ\' THEN (CASE GVA12.MON_CTE WHEN 1 THEN GVA53.IMP_NETO_P / 1 ELSE GVA53.IMP_NETO_P * GVA12.COTIZ / 1 END) END END)\n~~~~~~~~~~~~~~~~~~~~~~AS [GROSS_AMOUNT_COMP_CURR],\n0 AS [DISCOUNT_COMP_CURR],\n0 AS [ADDITIONAL_AMOUNT_COMP_CURR],\nSUM(CASE WHEN GVA12.T_COMP <> \'FAC\' AND GVA15.TIPO_COMP = \'C\' THEN (- 1) ELSE (1)\n~~~~~~~~~~~~~~~~~~~~~~END * CASE GVA12.COTIZ WHEN 0 THEN 0 ELSE CASE \'BIMONCTE\' WHEN \'BIMONCTE\' THEN (CASE GVA12.MON_CTE WHEN 1 THEN GVA53.IMP_NETO_P\n~~~~~~~~~~~~~~~~~~~~~~ ELSE GVA53.IMP_NETO_P * GVA12.COTIZ END)\n~~~~~~~~~~~~~~~~~~~~~~WHEN \'BIORIGEN\' THEN (CASE GVA12.MON_CTE WHEN 1 THEN GVA53.IMP_NETO_P / GVA12.COTIZ ELSE GVA53.IMP_NETO_P END)\n~~~~~~~~~~~~~~~~~~~~~~WHEN \'BICOTIZ\' THEN (CASE GVA12.MON_CTE WHEN 1 THEN GVA53.IMP_NETO_P / 1 ELSE GVA53.IMP_NETO_P * GVA12.COTIZ / 1 END) END END)\n~~~~~~~~~~~~~~~~~~~~~~AS [NET_AMOUNT_COMP_CURR],\n0 AS [GROSS_AMOUNT_GROUP_CURR],\n0 AS [DISCOUNT_GROUP_CURR],\n0 AS [ADDITIONAL_AMOUNT_GROUP_CURR],\n0 AS [NET_AMOUNT_GROUP_CURR],\n0 AS [GROUP_STAND_COST_DOC_CURR],\nRXN_ARTICULOS.STD_ARS * (SUM(CASE WHEN GVA12.T_COMP <> \'FAC\' AND GVA15.TIPO_COMP = \'C\' THEN (- 1) ELSE (1) END * GVA53.CANTIDAD)) AS [GROUP_STAND_COST_COMP_CURR],\n0 AS [GROUP_STAND_COST_GROUP_CURR],\nRXN_ARTICULOS.WAP_PPP AS [COMPANY_STAND_COST_DOC_CURR],\nRXN_ARTICULOS.WAP_PPP AS [COMPANY_STAND_COST_COMP_CURR],\n0 AS [COMPANY_STAND_COST_GROUP_CURR]\n\nFROM~~~~~~~~ STA11 WITH (NOLOCK) LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~RXN_ARTICULOS ON STA11.SINONIMO = RXN_ARTICULOS.COD_ARTICU LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~GVA12 WITH (NOLOCK) INNER JOIN\n~~~~~~~~~~~~~~~~~~~~~~GVA53 WITH (NOLOCK) ON GVA53.T_COMP = GVA12.T_COMP AND GVA53.N_COMP = GVA12.N_COMP INNER JOIN\n~~~~~~~~~~~~~~~~~~~~~~GVA23 WITH (NOLOCK) ON GVA12.COD_VENDED = GVA23.COD_VENDED LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~GVA14 WITH (NOLOCK) ON GVA12.COD_CLIENT = GVA14.COD_CLIENT LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~GVA15 ON GVA15.IDENT_COMP = GVA12.T_COMP ON STA11.COD_ARTICU = GVA53.COD_ARTICU\nWHERE~~~~ (GVA53.COD_ARTICU <> \'ART. AJUSTE\') AND (GVA53.COD_ARTICU <> \'\') AND\n( (GVA12.FECHA_EMIS BETWEEN \'01/01/2014\' AND \'31/03/2014\'))~~AND\n~~~~~~~~~~~~~~~~~~~~~~(GVA53.RENGL_PADR = 0) OR\n~~~~~~~~~~~~~~~~~~~~~~(GVA53.COD_ARTICU <> \'ART. AJUSTE\') AND (GVA53.COD_ARTICU <> \'\') AND~~~~~~~~~~~~~~~~~~~~~~ (GVA53.INSUMO_KIT_SEPARADO = 1)\nGROUP BY GVA12.FECHA_EMIS, GVA53.T_COMP, GVA53.N_COMP, GVA53.N_RENGL_V, GVA12.MON_CTE, GVA12.COD_VENDED,\n~~~~~~~~~~~~~~~~~~~~~~CASE GVA12.COD_VENDED WHEN \'**\' THEN \'CONTADO\' ELSE GVA23.NOMBRE_VEN END, GVA12.COD_CLIENT,\n~~~~~~~~~~~~~~~~~~~~~~CASE GVA12.COD_CLIENT WHEN \'000000\' THEN \'OCASIONAL\' ELSE GVA14.RAZON_SOCI END, GVA53.COD_ARTICU, STA11.DESCRIPCIO,\n~~~~~~~~~~~~~~~~~~~~~~RXN_ARTICULOS.COD_ARTICU, RXN_ARTICULOS.PRODUCTION_PLANT, RXN_ARTICULOS.PLANT, RXN_ARTICULOS.BRAND, RXN_ARTICULOS.COD_FLIAPROD, RXN_ARTICULOS.STD_ARS, RXN_ARTICULOS.WAP_PPP', '', 1, '2026-04-02 15:40:29', '2026-04-02 15:40:29', NULL),
