(166, 1, 760, NULL, 'BOTTCHER - Mail Soporte', 'Cuenta de mail para temas de SOPORTE\n~~~~~bottcher.soporte@e-reaxion.com.ar~-> BOtt2016 (no darle este pass a nadie)\n\nQue hace un re-envío a la lista\n~~~~~lista.bottcher.soporte@e-reaxion.com.ar\n\nCuyos destinatarios son:\n~~~~~soporte@reaxion.com.ar\n~~~~~tesoreria@bottcher-systems.com.ar\n~~~~~compras@bottcher-systems.com.ar\n~~~~~mariaclaudia@bottcher-systems.com.ar', '', 1, '2026-04-02 15:40:29', '2026-04-02 15:40:29', NULL),
(167, 1, 760, NULL, 'BOTTCHER - Precios por cliente', '/*Selección de los valores de sólo los artículos que tienen precio*/\nSELECT GVA13.COD_ARTICU, GVA13.COD_CLIENT, GVA13.NRO_LISTA\n,\nSTA11.DESCRIPCIO AS [Descripcion]\n,\nCASE WHEN GVA17.PRECIO IS NULL THEN 0 ELSE GVA17.PRECIO END AS [PRECIO_REAL]\n, GVA13.PRECIO AS [PRECIO DE LISTA]\nFROM GVA13 INNER JOIN\n\nGVA10 ON\n\nGVA10.NRO_DE_LIS = GVA13.NRO_LISTA\n/*Compruebo que haya más de una lista*/\n--WHERE NRO_LISTA <> 1\n/*Hasta aquí se traen los valores de la lista de precios contra el número de lista de GVA10*/\n/*Se requiere traer sólo el precio del artículo en la tabla GVA17 \"el precio real de la lista\"*/\nLEFT OUTER JOIN GVA17 ON GVA13.COD_ARTICU = GVA17.COD_ARTICU AND GVA10.NRO_DE_LIS = GVA17.NRO_DE_LIS\n\n/*Se agrega la descripción del artículo*/\n\nINNER JOIN\n\nSTA11 ON STA11.COD_ARTICU = GVA13.COD_ARTICU\n\n/*Selecciono el cliente 2 Larri solamente*/\n--WHERE GVA13.COD_CLIENT = \'3DONEL\'\n\n/*Ordeno por cod_client desc*/\n\nORDER BY COD_CLIENT DESC\n\n/* SELECT * FROM GVA13 WHERE COD_CLIENT = \'3DONEL\' */', '', 1, '2026-04-02 15:40:29', '2026-04-02 15:40:29', NULL),
(168, 1, 760, NULL, 'BOTTCHER - Nexo', 'Cuenta de mail para temas de ADMINISTRACION\n~~~~~bottcher.admin@e-reaxion.com.ar~-> boTT2016 (no darle este pass a nadie)\n\nQue hace un re-envío a la lista\n~~~~~lista.bottcher.admin@e-reaxion.com.ar\n\nCuyos destinatarios son:\n~~~~~administracion@reaxion.com.ar\n~~~~~tesoreria@bottcher-systems.com.ar\n~~~~~compras@bottcher-systems.com.ar\n~~~~~ventas@bottcher-systems.com.ar\n~~~~~aschwald@bottcher-systems.com.ar\n~~~~~mariaclaudia@bottcher-systems.com.ar\n\nCuenta de NEXO para entrar y ver/Descargar comprobantes:\n~~~~~bottcher.admin@e-reaxion.com.ar~-> bOTtRXN2016 (Se les puede dar esta clave)\n~~~~~bottcher.soporte@e-reaxion.com.ar~-> BottRXN2016', '', 1, '2026-04-02 15:40:29', '2026-04-02 15:40:29', NULL),
