(203, 1, 848, NULL, 'NIKITOS - Consultas Externas', '/* Pedidos desde la Vista Interempresa completo */\n\nselect Empresa, [Talon. pedido], [Desc. Talonario], [Nro. Pedido], Estado, [Fecha Pedido], [Cód. Condición de Venta], [Condición de Venta], [Cód. Vendedor], [Nombre Vendedor], [Cód. cliente], [Razón social], [Saldo (CTE)], [Familia cliente], [Grupo Cliente], [Cód. Transporte], [Transporte], [Cód. Clasificación (Comprobante)], [Cód. Clasificación (Renglón)],[Descripción Clasificación (Comprobante)], [Cód. Artículo], [Descripción], [Familia (artículo)], [Grupo (artículo)], [Cantidad pedida], [Cantidad Pendiente de Descargar], [Cantidad Pendiente de Facturar], [Total Pendiente], [Estado Aprob CONDICIONES], [Estado Aprob CANTIDADES], [Estado Aprob PRECIOS]\nfrom~~[zzzBOCA].[DBO].[INTEREMPRESA_Pedidos]\n\n/* Pedidos pendientes de autorización <CONDICIONES> Estela1 */\n\nSET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED\nSET DATEFORMAT DMY\nSET DATEFIRST 7\nselect [Cód. cliente], [Razón social], Empresa, [Talon. pedido], [Desc. Talonario], [Nro. Pedido], Estado, [Fecha Pedido], [Condición de Venta], [Cód. Vendedor], [Nombre Vendedor], [Cód. Transporte], [Transporte], [Cód. Artículo], [Descripción], [Cantidad pedida], [Cantidad Pendiente de Descargar], [Cantidad Pendiente de Facturar], [Total Pendiente], [Saldo (CTE)], [Estado Aprob CONDICIONES], [Estado Aprob CANTIDADES], [Estado Aprob PRECIOS]\nfrom~~[zzzBOCA].[DBO].[INTEREMPRESA_Pedidos]\nwhere [Estado Aprob CONDICIONES] = \'I\'\norder by [Cód. cliente]\n\n/* Pedidos pendientes de carga <STOCK> Autorizados por CtaCte~~*/\n\nSET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED\nSET DATEFORMAT DMY\nSET DATEFIRST 7\nSELECT~~~~~~~~InterEmpresa_Pedidos.[Cód. cliente], InterEmpresa_Pedidos.[Razón social], InterEmpresa_Pedidos.Empresa, InterEmpresa_Pedidos.[Talon. pedido],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Desc. Talonario], InterEmpresa_Pedidos.[Nro. Pedido], InterEmpresa_Pedidos.Estado, InterEmpresa_Pedidos.[Fecha Pedido],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Condición de Venta], InterEmpresa_Pedidos.[Cód. Vendedor], InterEmpresa_Pedidos.[Nombre Vendedor],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cód. Transporte], InterEmpresa_Pedidos.Transporte, InterEmpresa_Pedidos.[Cód. Artículo], InterEmpresa_Pedidos.Descripción,\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cantidad pedida], InterEmpresa_Pedidos.[Cantidad Pendiente de Descargar],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cantidad Pendiente de Facturar], InterEmpresa_StockAcum.Stock, InterEmpresa_StockAcum.[Stock comprometido], InterEmpresa_StockAcum.[Stock a recibir], InterEmpresa_Pedidos.[Total Pendiente], InterEmpresa_Pedidos.[Saldo (CTE)],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Estado Aprob CONDICIONES], InterEmpresa_Pedidos.[Estado Aprob CANTIDADES], InterEmpresa_Pedidos.[Estado Aprob PRECIOS]\n~~~~~~~~~~~~~~~~~~~~~~~~ FROM~~~~~~~~~~~~InterEmpresa_Pedidos LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_StockAcum ON InterEmpresa_Pedidos.[Cód. Artículo] = InterEmpresa_StockAcum.[Cód. Artículo]\nWHERE~~~~~~~~(InterEmpresa_Pedidos.[Estado Aprob CONDICIONES] = \'A\') and (InterEmpresa_Pedidos.[Estado Aprob CANTIDADES] = \'I\')\nORDER BY InterEmpresa_Pedidos.[Cód. cliente]\n\n/* Pedidos pendientes de carga con Stock <PRECIOS> para último Control por CtaCte~~*/\n\nSET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED\nSET DATEFORMAT DMY\nSET DATEFIRST 7\nSELECT~~~~~~~~InterEmpresa_Pedidos.[Cód. cliente], InterEmpresa_Pedidos.[Razón social], InterEmpresa_Pedidos.Empresa, InterEmpresa_Pedidos.[Talon. pedido],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Desc. Talonario], InterEmpresa_Pedidos.[Nro. Pedido], InterEmpresa_Pedidos.Estado, InterEmpresa_Pedidos.[Fecha Pedido],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Condición de Venta], InterEmpresa_Pedidos.[Cód. Vendedor], InterEmpresa_Pedidos.[Nombre Vendedor],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cód. Transporte], InterEmpresa_Pedidos.Transporte, InterEmpresa_Pedidos.[Cód. Artículo], InterEmpresa_Pedidos.Descripción,\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cantidad pedida], InterEmpresa_Pedidos.[Cantidad Pendiente de Descargar],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cantidad Pendiente de Facturar], InterEmpresa_StockAcum.Stock, InterEmpresa_StockAcum.[Stock comprometido], InterEmpresa_StockAcum.[Stock a recibir], InterEmpresa_Pedidos.[Total Pendiente], InterEmpresa_Pedidos.[Saldo (CTE)],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Estado Aprob CONDICIONES], InterEmpresa_Pedidos.[Estado Aprob CANTIDADES], InterEmpresa_Pedidos.[Estado Aprob PRECIOS]\n~~~~~~~~~~~~~~~~~~~~~~~~ FROM~~~~~~~~~~~~InterEmpresa_Pedidos LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_StockAcum ON InterEmpresa_Pedidos.[Cód. Artículo] = InterEmpresa_StockAcum.[Cód. Artículo]\nWHERE~~~~~~~~(InterEmpresa_Pedidos.[Estado Aprob CONDICIONES] = \'A\') and (InterEmpresa_Pedidos.[Estado Aprob CANTIDADES] = \'A\')~~and (InterEmpresa_Pedidos.[Estado Aprob PRECIOS] = \'I\')\nORDER BY InterEmpresa_Pedidos.[Cód. cliente]\n\n/* Pedidos Aprovados para ser remitidos~~*/\n\nSET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED\nSET DATEFORMAT DMY\nSET DATEFIRST 7\nSELECT~~~~~~~~InterEmpresa_Pedidos.[Cód. cliente], InterEmpresa_Pedidos.[Razón social], InterEmpresa_Pedidos.Empresa, InterEmpresa_Pedidos.[Talon. pedido],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Desc. Talonario], InterEmpresa_Pedidos.[Nro. Pedido], InterEmpresa_Pedidos.Estado, InterEmpresa_Pedidos.[Fecha Pedido],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Condición de Venta], InterEmpresa_Pedidos.[Cód. Vendedor], InterEmpresa_Pedidos.[Nombre Vendedor],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cód. Transporte], InterEmpresa_Pedidos.Transporte, InterEmpresa_Pedidos.[Cód. Artículo], InterEmpresa_Pedidos.Descripción,\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cantidad pedida], InterEmpresa_Pedidos.[Cantidad Pendiente de Descargar],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Cantidad Pendiente de Facturar], InterEmpresa_StockAcum.Stock, InterEmpresa_StockAcum.[Stock comprometido], InterEmpresa_StockAcum.[Stock a recibir], InterEmpresa_Pedidos.[Total Pendiente], InterEmpresa_Pedidos.[Saldo (CTE)],\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_Pedidos.[Estado Aprob CONDICIONES], InterEmpresa_Pedidos.[Estado Aprob CANTIDADES], InterEmpresa_Pedidos.[Estado Aprob PRECIOS]\n~~~~~~~~~~~~~~~~~~~~~~~~ FROM~~~~~~~~~~~~InterEmpresa_Pedidos LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~~~ InterEmpresa_StockAcum ON InterEmpresa_Pedidos.[Cód. Artículo] = InterEmpresa_StockAcum.[Cód. Artículo]\nWHERE~~~~~~~~(InterEmpresa_Pedidos.[Estado Aprob CONDICIONES] = \'A\') and (InterEmpresa_Pedidos.[Estado Aprob CANTIDADES] = \'A\')~~and (InterEmpresa_Pedidos.[Estado Aprob PRECIOS] = \'A\')\nORDER BY InterEmpresa_Pedidos.[Cód. cliente]', '', 1, '2026-04-02 15:40:29', '2026-04-02 15:40:29', NULL),
