(206, 1, 848, NULL, 'AXOFT - Script para copiar relacion artículos por clientes (NIKITOS)', '/* Pasaje de Descuentos de un articulo a otro*/\n\n/* Declaracion de Variables~~*/\nDECLARE @ORIGEN [varchar](15)\nDECLARE @DESTINO [varchar](15)\nSET @ORIGEN~~= \'030040236204000\'\nSET @DESTINO = \'030050100000081\'\n\n/* Borrado de tabla temporal */\nDelete from GVA11_RXN\n\n/* Filtrado y copiado a~~de tabla temporal */\nINSERT INTO GVA11_RXN (FILLER, BONIF, COD_ARTICU, COD_CLIENT, DESC_SINON, SINONIMO, COD_GVA14_CLIENTE)\nSELECT~~~~~~~~~~~~FILLER, BONIF, COD_ARTICU, COD_CLIENT, DESC_SINON, SINONIMO, COD_GVA14_CLIENTE\nFROM GVA11\nWHERE~~~~ COD_ARTICU = @ORIGEN\n\n/* Cambio de codigo de articulo por el destino */\nUPDATE GVA11_RXN SET COD_ARTICU = @DESTINO\n\n/* Copio los nuevos articulos al GVA11 */\nINSERT INTO GVA11 (FILLER, BONIF, COD_ARTICU, COD_CLIENT, DESC_SINON, SINONIMO, COD_GVA14_CLIENTE)\nSELECT~~~~~~~~~~~~FILLER, BONIF, COD_ARTICU, COD_CLIENT, DESC_SINON, SINONIMO, COD_GVA14_CLIENTE\nFROM GVA11_RXN\n/* FIN */', '', 1, '2026-04-02 15:40:30', '2026-04-02 15:40:30', NULL),
