(208, 1, 848, NULL, 'Nikitos - SQL -> Eliminación de relación artículo cliente', '/*Eliminación de Relación artículo cliente.*/\nSELECT * FROM GVA11 WHERE COD_ARTICU = \'020030310024100\' AND COD_CLIENT = \'CH0071\'\n\nSELECT * FROM GVA11~~WHERE COD_ARTICU = \'020030310024100\' ORDER BY COD_CLIENT\n\nDELETE FROM GVA11 WHERE COD_ARTICU = \'020030310024100\'\n/*Fin de la eliminación.*/\n\n/*Ultima actualización*/\n\n/*Eliminación de Relación de Artículos por Cliente\nS.F Walmart [COD_CLIENT] = \'H0201\'\nBOCA =~~\'H0201\' (\'H020101\' -> No)\nLOPREITE = \'H0201\'\n\nControl de Cliente y relación\n\nSELECT * FROM RODOLFO_H_LOPREITE.dbo.GVA11 WHERE COD_CLIENT = \'H0201\'\n\nSelección de datos Cliente y Artículo - Modificar valor empresa\nde acuerdo a la necesidad\nSELECT * FROM BOCA.dbo.GVA11 WHERE COD_ARTICU = \'050040000000045\' AND COD_CLIENT = \'H0201\'\n\nSelección de empresa exceptuando los registro del cliente Wal-Mart\nSELECT * FROM BOCA.dbo.GVA11 WHERE COD_ARTICU = \'001010100202012\'\nEXCEPT\nSELECT * FROM BOCA.dbo.GVA11 WHERE COD_CLIENT = \'H0201\'\n\nEliminación de clientes exceptuando a Wal-Mart\nDELETE FROM BOCA.dbo.GVA11 WHERE COD_ARTICU = \'050010000000011\' AND COD_CLIENT NOT LIKE \'H0201\'\n\nBASES -> RODOLFO_H_LOPREITE /--/ [S.F.] /--/ BOCA\n*/\n\nDELETE FROM BOCA.dbo.GVA11 WHERE COD_ARTICU = \'001010100202012\' AND COD_CLIENT NOT LIKE \'H0201\'', '', 1, '2026-04-02 15:40:30', '2026-04-02 15:40:30', NULL),
