(225, 1, 848, NULL, 'NIKITOS - Controlar correcta imputación', '/*Verifica sobre una base de datos las imputaciones de más realizadas a facturas*/\nselect abs(GVA12.IMPORTE - IMPUTACIONES) IMPUTADO_DE_MAS, GVA12.T_COMP, GVA12.N_COMP, GVA12.FECHA_EMIS, GVA12.COD_CLIENT, GVA12.IMPORTE, IMP.IMPUTACIONES,gva12.unidades, imp.IMP_CAN_UN, GVA12.MON_CTE\nfrom\ngva12\ninner join gva14 on gva14.cod_client = gva12.cod_client\nINNER JOIN\n(\nSELECT T_COMP_CAN T_COMP, N_COMP_CAN N_COMP, SUM(IMPORT_CAN) IMPUTACIONES, SUM(IMP_CAN_UN) IMP_CAN_UN\nFROM GVA07\nGROUP BY\nT_COMP_CAN , N_COMP_CAN\n) AS IMP\nON IMP.T_COMP = GVA12.T_COMP AND IMP.N_COMP = GVA12.N_COMP\nwhere GVA12.TCOMP_IN_V IN (\'RC\', \'CC\')\nAND\n((IMPORTE< IMP.IMPUTACIONES and gva14.clausula = 0) or\n(gva12.unidades<> imp.IMP_CAN_UN and gva14.clausula= 1))', '', 1, '2026-04-02 15:40:30', '2026-04-02 15:40:30', NULL),
