(254, 1, 784, NULL, 'AXOFT - Script para copiar empresas - 14.11', 'AXOFT - Script para copiar empresas - 9.91\n\nuse ESTANCIA_MARIA_BEHETY_SA\ngo\n\n/****** Talonarios de compra ******/\nDELETE FROM CPA56\nINSERT INTO CPA56(FILLER, DESCRIPCIO, DESTINO, EDITA_NRO, N_TYP, NRO_DESDE, NRO_HASTA, PROXIMO, RENGLONES, SUCURSAL, TALONARIO, TIPO_COMP,\n~~~~~~~~~~~~~~~~~~~~~~DOC_ELECTR, MET_CON_DE, IMP_DE, T_DOC_DTE, DI_IMG_TYP, IMG_PATH_PDF, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF)\nSELECT~~~~~~~~~~~~FILLER, DESCRIPCIO, DESTINO, EDITA_NRO, N_TYP, NRO_DESDE, NRO_HASTA, PROXIMO, RENGLONES, SUCURSAL, TALONARIO, TIPO_COMP,\n~~~~~~~~~~~~~~~~~~~~~~DOC_ELECTR, MET_CON_DE, IMP_DE, T_DOC_DTE, DI_IMG_TYP, IMG_PATH_PDF, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF\nFROM [MARIA_BEHETY].[dbo].[CPA56]\nGO\n\n/****** Copia Talonarios de Ventas ******/\nDELETE FROM GVA43\nINSERT INTO GVA43(FILLER, CAI, CF_COPIAS, COMPROB, CONT_FISCA, DESCRIP, DESTINO, DUPLICA, EDITA_NRO, FECHA_VTO, MODELO_CF, NRO_DESDE, NRO_HASTA,\n~~~~~~~~~~~~~~~~~~~~~~PROXIMO, RENGLONES, SUCURSAL, T_FORM, TALONARIO, TIPO, EXCLUSIVO, COD_CAJA, T_MANUAL, NROAUTORIZ, LLAVE1, LLAVE2, FECH_AVISO, VAL_FECHA,\n~~~~~~~~~~~~~~~~~~~~~~DOC_ELECTR, MET_CON_DE, DI_IMG_TYP, DESTINO_DE, IMP_DE, MAIL_DE, EXPORTA, T_DOC_DTE, SUCURSAL_DESTINO, USA_TGIMPRE, IMG_PATH_PDF,\n~~~~~~~~~~~~~~~~~~~~~~UTILIZA_BONO_FISCAL, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF, TIPO_TALONARIO, OBSERVACIONES, NUMERACION_PREIMPRESA,\n~~~~~~~~~~~~~~~~~~~~~~IMPRESION_COMPROBANTES)\nSELECT~~~~~~~~~~~~FILLER, CAI, CF_COPIAS, COMPROB, CONT_FISCA, DESCRIP, DESTINO, DUPLICA, EDITA_NRO, FECHA_VTO, MODELO_CF, NRO_DESDE, NRO_HASTA,\n~~~~~~~~~~~~~~~~~~~~~~PROXIMO, RENGLONES, SUCURSAL, T_FORM, TALONARIO, TIPO, EXCLUSIVO, COD_CAJA, T_MANUAL, NROAUTORIZ, LLAVE1, LLAVE2, FECH_AVISO, VAL_FECHA,\n~~~~~~~~~~~~~~~~~~~~~~DOC_ELECTR, MET_CON_DE, DI_IMG_TYP, DESTINO_DE, IMP_DE, MAIL_DE, EXPORTA, T_DOC_DTE, SUCURSAL_DESTINO, USA_TGIMPRE, IMG_PATH_PDF,\n~~~~~~~~~~~~~~~~~~~~~~UTILIZA_BONO_FISCAL, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF, TIPO_TALONARIO, OBSERVACIONES, NUMERACION_PREIMPRESA,\n~~~~~~~~~~~~~~~~~~~~~~IMPRESION_COMPROBANTES\nFROM [MARIA_BEHETY].[dbo].[GVA43]\nGO\n\n/****** Formatos de impresión ******/\n\nIF~~EXISTS (SELECT * FROM sys.foreign_keys WHERE object_id = OBJECT_ID(N\'[dbo].[FK_SBA02_TYPS]\') AND parent_object_id = OBJECT_ID(N\'[dbo].[SBA02]\'))\nALTER TABLE [dbo].[SBA02] DROP CONSTRAINT [FK_SBA02_TYPS]\n\nSET IDENTITY_INSERT TYPS ON\nDELETE FROM TYPS\nINSERT INTO TYPS(ID_TYPS, FILLER, MEMO_TYP, NOMBRE_TYP, ID_PROCESO, OBSERVACIONES, DESC_TYPS)\nSELECT ID_TYPS, FILLER, MEMO_TYP, NOMBRE_TYP, ID_PROCESO, OBSERVACIONES, DESC_TYPS\nFROM [MARIA_BEHETY].[dbo].[TYPS]\nGO\nSET IDENTITY_INSERT TYPS OFF\nGo\nALTER TABLE DBO.SBA02\n~~ ADD CONSTRAINT FK_SBA02_TYPS FOREIGN KEY (ID_TYPS)\n~~~~~~REFERENCES DBO.TYPS (ID_TYPS)\nGO\n\n/****** Proximos numeros ******/\nDELETE FROM PROXIMO_NUMERO\nINSERT INTO PROXIMO_NUMERO (TABLA, CAMPO, PROXIMO_NUMERO, PROXIMO_TEXTO)\nSELECT~~TABLA, CAMPO, PROXIMO_NUMERO, PROXIMO_TEXTO\nFROM [MARIA_BEHETY].[dbo].[PROXIMO_NUMERO]\nGO', '', 1, '2026-04-02 15:40:30', '2026-04-02 15:40:30', NULL),
