(266, 1, 873, NULL, 'AXOFT - Script para saber bases Contabilidad ACTUAL', 'IF EXISTS (SELECT 1 FROM SYSOBJECTS WHERE XTYPE = \'U\' AND NAME LIKE \'SIZETABLAS\')\nDROP TABLE SIZETABLAS\nGO\n\nCREATE TABLE SIZETABLAS (NAME VARCHAR(100), ROWS INT, RESERVED VARCHAR (100), DATA VARCHAR (100),\nINDEX_SIZE VARCHAR (100), UNUSED VARCHAR (100))\nGO\n\nDECLARE @TABLA AS VARCHAR (100), @SQL AS VARCHAR (1000)\nDECLARE RS CURSOR LOCAL FOR\nSELECT NAME FROM SYSOBJECTS WHERE XTYPE = \'U\' and left(name,4) = \'ACT_\'\nORDER BY 1\nOPEN RS\nFETCH NEXT FROM RS INTO @TABLA\nWHILE @@FETCH_STATUS = 0\nBEGIN\nSET @SQL = \'INSERT INTO SIZETABLAS (NAME, ROWS, RESERVED, DATA, INDEX_SIZE, UNUSED)\nEXEC SP_SPACEUSED \'+\'\'\'\'+@TABLA+\'\'\'\'+\' \'\n\nEXEC (@SQL)\nFETCH NEXT FROM RS INTO @TABLA\nEND\nCLOSE RS\nDEALLOCATE RS\n\nUPDATE SIZETABLAS SET DATA = REPLACE (DATA, \' KB\' , \'\')\nGO\n\nSELECT * FROM SIZETABLAS\nWHERE ROWS = (SELECT MAX (CAST (ROWS AS NUMERIC)) FROM SIZETABLAS)\n\nSELECT * FROM SIZETABLAS order by CAST (DATA AS NUMERIC) desc\n\n//----------------------------\n\nuse PROFEED_SA_2006\ngo\nselect * from ACT_CNA30\ngo\nuse PROFEED_SALADILLO_CONTAB_2015\ngo\nselect * from ACT_CNA30\ngo\n\n//------------------------------------\nuse PROFEED_SA_2006\ngo\nDELETE FROM ACT_CNA30\nINSERT INTO ACT_CNA30 (FILLER, COD_COSTO, FECHA_AS, IMPORTE, N_ASIENTO, RENGLON, UNIDADES)\nSELECT~~~~FILLER, COD_COSTO, FECHA_AS, IMPORTE, N_ASIENTO, RENGLON, UNIDADES\nFROM [PROFEED_SALADILLO_CONTAB_2015].[dbo].[ACT_CNA30]\nGO\n\n//------------------------------------\nuse PROFEED_SA_2006\ngo\nDELETE FROM ACT_CNA30\nDELETE FROM ACT_CNA10\nDELETE FROM ACT_CNA02\nDELETE FROM ACT_CNA06\ngo', '', 1, '2026-04-02 15:40:30', '2026-04-02 15:40:30', NULL),
