INSERT INTO `crm_notas` (`id`, `empresa_id`, `cliente_id`, `tratativa_id`, `titulo`, `contenido`, `tags`, `activo`, `created_at`, `updated_at`, `deleted_at`) VALUES
(398, 1, 726, NULL, 'AXOFT - Typs - Libro Sueldos - Cabecera', '1º) Título del bug: Nueva rúbrica Libroley Provincia de Buenos Aires (Resolución 310/9) - Nuevo alcance - Sueldos Tango y Sueldos Astor (29580, 24171)\n\n2º) Fecha: 22/02/2010\n\n3º) Origen: Servicios\n\n4º) Modulo:~~Sueldos Tango y Sueldos Astor\n\n5º) Descripción del Bug: Se adecuo el formato de los reportes utilizados en la emisión del Libroley para que sea compatible con las nuevas hojas en papel de seguridad entregadas por el Ministerio de Trabajo de la Provincia de Buenos Aires (Resol. Nro. 310). A continuación se detallan los pasos a seguir en ambos módulos:\n\nSueldos Tango\n\nLuego de instalar el hotfix correspondiente a su versión edite el Archivo ConfigAstor.ini que se encuentra en “C:\\Documents and Settings\\All Users\\Application Data\\Axoft\\HLNumber\\”, donde HLNumber corresponde al número de llave.\n\nAgregue en “ConfigAstor.ini” el siguiente texto: (asi está CAREY)\n\n[LibroleyTYP]\nAltoMargenSuperior=7\nAnchoMargenIzquierdoEncabezado=8\nAnchoMargenIzquierdoPie=15\n\nPara determinar la cantidad de espacios o líneas que deben quedar en blanco en el margen superior, margen izquierdo del encabezado y margen izquierdo del pie del reporte, asigne a cada variable un valor numérico, igual o mayor a “0” (sin decimales).\n\nLuego desde el menú de Sueldos Tango ingrese a: Archivos – Actualizaciones – Formularios – Libro Ley, para realizar las modificaciones en el cuerpo del reporte y adaptarlo a la hoja pre impresa.\n\nSueldos Astor\n\nFormato TYP:\nLuego de instalar el hotfix correspondiente a su versión edite el Archivo ConfigAstor.ini que se encuentra en “C:\\Documents and Settings\\All Users\\Application Data\\Axoft\\HLNumber\\ “donde HLNumber corresponde al número de llave.\n\nAgregue en “ConfigAstor.ini” el siguiente texto: (asi está CARTI)\n\n[LibroleyTYP]\nCantLineasEncabezado=\nAltoMargenSuperior=3\nMargenIzquierdo=3\nImprimeNumeroHoja=0\n\nAsigne a cada variable un valor numérico con hasta 2 (Dos) decimales separados indistintamente por punto (.) o coma (,) el cual representa una determinada cantidad de centímetros a dejar en blanco en el margen superior y margen izquierdo.\nPara la variable CantLineasEncabezado completar con un número entero la cantidad de líneas a dejar en blanco en el encabezado.\nPara indicar si se imprime el número de hoja, asigne a la variable “ImprimeNumeroHoja” el valor uno (1) si imprime el numero de hoja y el valor cero (0) para el caso contrario.\n\nLuego desde el menú de Sueldos Astor ingrese a Archivo – Liquidación – Formularios (versión 9.30) o desde Procesos Generales – Tablas generales – Formularios – Sueldos (versión 9.50) para realizar las modificaciones en el cuerpo del Libroley y adaptarlo a la hoja pre impresa.\n\nFormato RPT:\nSi utiliza el informe incluido por defecto en Sueldos Astor, puede solicitar a Servicios (servicios@axoft.com) los reportes Libroley_LegajosSU_BsAs.rpt o Libroley_LegajosSU_Reducido_Bs_As.rpt adaptados al formato requerido por la Resolución.\n\nNota: Consulte el tipo de reporte utilizado en la generación del Libro Ley en Sueldos Astor, ingresando a Parámetros de Sueldos – Formularios - Modelos de impresión.\n\n6º) Corregido para la versión: Próxima versión\n\n7º) Solución alternativa:~~Solicitar a Servicios el hotfix interno corregido.\n\n8º) Ejecutable corregido: 9.30.001: ftp://ftp.axoft.com/version_interna/Astor/Version_9.30.002/Version044/HotFix_9_30_002_0440.exe\n\n~~~~~~~~9.50.000 y 9.50.001: ftp://ftp.axoft.com/version_interna/Astor/Version_9.50.002/Version014/HotFix_9_50_002_0141.exe', '', 1, '2026-04-02 15:40:31', '2026-04-02 15:40:31', NULL),
(399, 1, 726, NULL, 'CAREY - Mail Soporte', 'Cuenta de mail para temas de SOPORTE\n~~~~~carey.soporte@e-reaxion.com.ar~-> caRE2016 (no darle este pass a nadie)\n\nQue hace un re-envío a la lista\n~~~~~lista.carey.soporte@e-reaxion.com.ar\n\nCuyos destinatarios son:\n~~~~~soporte@reaxion.com.ar\n~~~~~gabriela@carey.com.ar\n~~~~~higar@carey.com.ar', '', 1, '2026-04-02 15:40:31', '2026-04-02 15:40:31', NULL),
(400, 1, 726, NULL, 'CAREY - Eliminación masiva de artículos', '/*\n\nEl interior de este archivo fue actualizado el 24/02/2018\n\nSe agrega el conteo de datos en la tabla pedidos pare decidir la eliminación de los archivos\n\nEl siguiente Script surge de la siguiente situación.\nAl eliminar un artículo que existe en la tabla Pedidos, el sistema deja de mostrar la descripción al\nmomento de facturar o remitir, porque falta el registro en STA11\n\nSolución correr el siguiente, que controla los artículos a eliminar en STA11, si existe en GVA03 los cuenta y\nsi es mayor a 0 elimina los artículos de la base.\n\n*/\nDECLARE @CodArticu VARCHAR(50)\nDECLARE @Id_sta11 INT\nDECLARE @ArtEliminado VARCHAR(200)\nDECLARE @Ctrl VARCHAR(200)\nDECLARE @SumaCampos INT\nDECLARE @ArtEliminadoSucu VARCHAR(200)\n/*Recuento de renglones*/\nDECLARE @N_REG INT\nDECLARE @N_REN_INT INT\n/*Recuento de renglones*/\n\nDECLARE RecorreArticulos CURSOR\nFOR\n/*Area de consulta para eliminación y filtros, se tiene que devolver solo el código de artículo*/\nSELECT COD_ARTICU, ID_STA11, 0 +ROW_NUMBER() OVER(ORDER BY ID_STA11) AS N_REG~~FROM STA11\nWHERE --COD_ARTICU in (\'X4125\')\nCOD_ARTICU LIKE \'%/7.\' OR COD_ARTICU LIKE \'%/0.\'\n~~OR COD_ARTICU LIKE \'%/09\'~~~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/28\'~~~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/34\'~~~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/36\'~~~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/37\'~~~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/310\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/314\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/315\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/322\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/327\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/329\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/330\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/338\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/340\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/349\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/350\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/627\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/637\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/638\'~~~~~~~~~~~~~~\n~~OR COD_ARTICU LIKE \'%/656\'~~~~~~\n/*Fin del area de consulta y filtro*/\n\nOPEN RecorreArticulos\nFETCH NEXT FROM RecorreArticulos\nINTO @CodArticu, @Id_sta11, @N_REG\nWHILE @@FETCH_STATUS = 0\nBEGIN\n--SELECT @CodArticu, @Id_sta11\n--PRINT(@CodArticu) + \' <- Registro procesado a continuación de muestra la ID del artículo\';\n--PRINT(@Id_sta11)\n/*Creación del SubCursor para la consulta en otras tablas*/\nDECLARE artPorSucu CURSOR\nFOR SELECT COUNT(COD_ARTICU) FROM GVA03 WHERE COD_ARTICU = @CodArticu\nOPEN artPorSucu\nFETCH NEXT FROM artPorSucu\nINTO @ArtEliminado\nIF @ArtEliminado =0\n/*Si NO existe en la tabla de pedidos se elimina*/\nBEGIN\n/*Control de eliminacion*/\nPRINT (@CodArticu) + \' Eliminado del sistema \'\n\n--/*Delete recursivo en las diferentes Tablas*/\n--PRINT(@CodArticu) + \' <- Registro procesado a continuación de muestra la ID del artículo\';\n--PRINT(@Id_sta11)\n--/*Creación del SubCursor para la consulta en otras tablas*/\n--DECLARE ctaAuditoriaSucu CURSOR\n--FOR SELECT COUNT(COD_STA11) FROM CTA_ARTICULO_POR_SUCURSAL WHERE COD_STA11 = @CodArticu\n--OPEN ctaAuditoriaSucu\n--FETCH NEXT FROM ctaAuditoriaSucu\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando: \"Borrar cta_articulo por sucursal\"\';\n--Delete CTA_ARTICULO_POR_SUCURSAL WHERE COD_STA11 = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE ctaAuditoriaSucu\n--DEALLOCATE ctaAuditoriaSucu\n--/*Eliminación del GVA11*/\n--DECLARE borraGva11 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM GVA11 WHERE COD_ARTICU = @CodArticu\n--OPEN borraGva11\n--FETCH NEXT FROM borraGva11\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar Gva11\"\';\n--Delete GVA11 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraGva11\n--DEALLOCATE borraGva11\n--/*Eliminación del CPA15*/\n--DECLARE borraCpa15 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM CPA15 WHERE COD_ARTICU = @CodArticu\n--OPEN borraCpa15\n--FETCH NEXT FROM borraCpa15\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar CPA15\"\';\n--Delete CPA15 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraCpa15\n--DEALLOCATE borraCpa15\n--/*Eliminación del STA11ITC*/\n--DECLARE borraSta11Itc CURSOR\n--FOR SELECT COUNT(CODE) FROM STA11ITC WHERE CODE = @CodArticu\n--OPEN borraSta11Itc\n--FETCH NEXT FROM borraSta11Itc\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA11ITC\"\';\n--Delete STA11ITC Where CODE = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta11Itc\n--DEALLOCATE borraSta11Itc\n--/*Eliminación del STA05*/\n--DECLARE borraSta05 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM STA05 WHERE COD_ARTICU = @CodArticu\n--OPEN borraSta05\n--FETCH NEXT FROM borraSta05\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA05\"\';\n--Delete STA05 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta05\n--DEALLOCATE borraSta05\n--/*Eliminación del STA07*/\n--DECLARE borraSta07 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM STA07 WHERE COD_ARTICU = @CodArticu\n--OPEN borraSta07\n--FETCH NEXT FROM borraSta07\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA07\"\';\n--Delete STA07 Where COD_ARTICU =~~@CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta07\n--DEALLOCATE borraSta07\n--/*Eliminación del STA10*/\n--DECLARE borraSta10 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM STA10 WHERE COD_ARTICU = @CodArticu\n--OPEN borraSta10\n--FETCH NEXT FROM borraSta10\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA10\"\';\n--Delete STA10 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta10\n--DEALLOCATE borraSta10\n--/*Eliminación del STA12*/\n--DECLARE borraSta12 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM STA12 WHERE COD_ARTICU = @CodArticu\n--OPEN borraSta12\n--FETCH NEXT FROM borraSta12\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA12\"\';\n--Delete STA12 Where COD_ARTICU =~~@CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta12\n--DEALLOCATE borraSta12\n--/*Eliminación del STA19*/\n--DECLARE borraSta19 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM STA19 WHERE COD_ARTICU = @CodArticu\n--OPEN borraSta19\n--FETCH NEXT FROM borraSta19\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA19\"\';\n--Delete STA19 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta19\n--DEALLOCATE borraSta19\n--/*Eliminación del STA21*/\n--DECLARE borraSta21 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM STA21 WHERE COD_ARTICU = @CodArticu\n--OPEN borraSta21\n--FETCH NEXT FROM borraSta21\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA21\"\';\n--Delete STA21 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta21\n--DEALLOCATE borraSta21\n--/*Eliminación del GVA17*/\n--DECLARE borraGva17 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM GVA17 WHERE COD_ARTICU = @CodArticu\n--OPEN borraGva17\n--FETCH NEXT FROM borraGva17\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar GVA17\"\';\n--Delete GVA17 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraGva17\n--DEALLOCATE borraGva17\n--/*Eliminación del CPA44*/\n--DECLARE borraCpa44 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM CPA44 WHERE COD_ARTICU = @CodArticu\n--OPEN borraCpa44\n--FETCH NEXT FROM borraCpa44\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar CPA44\"\';\n--Delete CPA44 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraCpa44\n--DEALLOCATE borraCpa44\n--/*Eliminación del CPA88*/\n--DECLARE borraCpa88 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM CPA88 WHERE COD_ARTICU = @CodArticu\n--OPEN borraCpa88\n--FETCH NEXT FROM borraCpa88\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar CPA88\"\';\n--Delete CPA88 Where COD_ARTICU = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraCpa88\n--DEALLOCATE borraCpa88\n--/*Eliminación del ARTICULO CUENTA*/\n--DECLARE articuloCuenta CURSOR\n--FOR SELECT COUNT(COD_STA11) FROM ARTICULO_CUENTA WHERE COD_STA11 = @CodArticu\n--OPEN articuloCuenta\n--FETCH NEXT FROM articuloCuenta\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar ARTICULO CUENTA\"\';\n--Delete ARTICULO_CUENTA Where COD_STA11 = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE articuloCuenta\n--DEALLOCATE articuloCuenta\n--/*Eliminación de STA11*/\n--DECLARE borraSta11 CURSOR\n--FOR SELECT COUNT(COD_ARTICU) FROM STA11 WHERE COD_ARTICU = @CodArticu\n--OPEN borraSta11\n--FETCH NEXT FROM borraSta11\n--INTO @ArtEliminado\n--/*Control de eliminacion*/\n--PRINT(@ArtEliminado) + \'<-Arts borrados /-/ Se procesó el comando \"Borrar STA11\"\';\n--Delete STA11 Where COD_STA11 = @CodArticu\n--/*Control de eliminacion*/\n--CLOSE borraSta11\n--DEALLOCATE borraSta11\n--/*Creación del SubCursor para la consulta en otras tablas*/\n--PRINT(@CodArticu) + \' <- Fin del bucle para el registro\';\n--/*Delete recursivo en las diferentes Tablas*/\n\nEND\nELSE\nBEGIN\nPRINT (@CodArticu) + \' No se elimino!. Existe en la tabla de pedidos la cantidad de veces-> \' + @ArtEliminado\nEND\nCLOSE artPorSucu\nDEALLOCATE artPorSucu\n\nFETCH NEXT FROM RecorreArticulos\nINTO @CodArticu, @Id_sta11, @N_REG\nEND\nCLOSE RecorreArticulos\nDEALLOCATE RecorreArticulos', '', 1, '2026-04-02 15:40:31', '2026-04-02 15:40:31', NULL),
