(415, 1, 726, NULL, 'CAREY - BackUp Pasteur', 'BackUp Diario:\n--------------\nTodos los días a las 22:00 hs y 15 minutos después de reiniciar el sistema.\n-Se ejecuta un comando en SQL que genera Backups de TODAS las bases de SQL en el directorio c:\\BackUp (son archivos .BAK sin compresión.\n-Se crea una carpeta en el disco D:\\BackUp y como nombre utiliza la fecha obtenida del sistema para guardar los resguardos comprimidos con línea de comando del ejecutable rar.exe y con contraseña.\n-Se comprimen los siguientes directorios:\n-D:\\Tango\\Re@xion\n-Se comprimen y se guardan en esta carpeta las bases de datos de uso diario (al final del archivo se le agrega la hora de compresión):\n-Diccionario\n-LocalesCarey\n-MayoFaven2011\n-MayoFaven2012\n-PreciosNuevos\n-Sueldos\n-Sueldos_Astor\n\nBackUp Mensual:\n--------------\nTodos los 1eros días de cada mes a las 03:00 hs:\n-Se crea una carpeta en el disco D:\\BackUp y como nombre utiliza la fecha obtenida del sistema para guardar los resguardos comprimidos con línea de comando del ejecutable rar.exe y con contraseña.\n-Se comprimen los siguientes directorios:\n-D:\\Tango\\Re@xion\n-Se comprimen y se guardan en esta carpeta todas las bases de datos generadas la noche anterior.\n\nQueda por analizar qué hacemos con el directorio D:\\Tango\\FAC_Elec por el volumen almacenado allí (donde se guardan las facturas electrónicas ya emitidas', '', 1, '2026-04-02 15:40:31', '2026-04-02 15:40:31', NULL),
(416, 1, 726, NULL, 'AXOFT - Script para Carey por correr la fecha de maquina', 'La operadora cambió la fecha del equipo y la adelantó 1 mes:\n\nselect fecha_emis, (fecha_emis - 31) from gva12 where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\n\nupdate gva12 set fecha_emis = (fecha_emis - 31) where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\n\nselect n_comp,~~fecha_mov, (fecha_mov - 31) from gva53 where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\nupdate gva53 set fecha_mov = (fecha_mov - 31) where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\n\nselect n_comp, ncomp_in_s, fecha_mov, (fecha_mov - 31) from sta14 where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\n\nupdate sta14 set fecha_mov = (fecha_mov - 31) where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\n\nupdate sta20 set sta20.fecha_mov = STA14.FECHA_MOV\nFROM~~~~~~~~ STA14 LEFT OUTER JOIN\n~~~~~~~~~~~~~~~~~~~~~~STA20 ON STA14.TCOMP_IN_S = STA20.TCOMP_IN_S AND STA14.NCOMP_IN_S = STA20.NCOMP_IN_S\nWHERE~~~~ (STA14.N_COMP >= \'B002200061686\') AND (STA14.N_COMP <= \'B002200062218\')*/\n\nselect n_comp, fecha, (fecha - 31) from sba04 where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\nupdate sba04 set fecha = (fecha - 31) where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\n\nselect n_comp, fecha, (fecha - 31) from sba05 where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'\nupdate sba05 set fecha = (fecha - 31) where n_comp >= \'B002200061686\' and n_comp <= \'B002200062218\'', '', 1, '2026-04-02 15:40:31', '2026-04-02 15:40:31', NULL),
