(499, 1, 653, NULL, 'BLEAR - Modificación de Remitos Pendientes', '--SELECT * FROM STA14\n/*\nPrevia selección -> 60600 Registros\nSelección desde la columna FECHA_MOV entre \'1800-01-01 00:00:00.000\' y \'2016-12-31 00:00:00.000\'\nDespués de la selección 60595 Registros.\nEstado P -> Pendiente\n\n*/\n\n--SELECT * FROM STA14 WHERE FECHA_MOV BETWEEN \'1800/01/01\' AND \'31/12/2015\' AND ESTADO_MOV = \'P\' --N_COMP = \'R000600003767\'\n\n/*Updateo de prueba para verificar resultado\nA -> Anulado\nF - Facturado ->Es el estado con el que no te aparece al momento de facturar.\n309 Remitos pendies de facturar a la fecha -> 16/03/2016.\n*/\nUPDATE STA14 SET ESTADO_MOV = \'F\' WHERE FECHA_MOV BETWEEN \'1800/01/01\' AND \'31/12/2015\' AND ESTADO_MOV = \'P\' --AND N_COMP = \'R000600003767\'\n\n/*Guardamos una copia de STA14*/\n--SELECT * INTO STA14_PREV_REM_FAC FROM STA14\n--SELECT * FROM STA14_PREV_REM_FAC', '', 1, '2026-04-02 15:40:31', '2026-04-02 15:40:31', NULL),
