(507, 1, 765, NULL, 'AXOFT - Script para cambiar Nivel de Compatibilidad', 'use master;\ngo\n\nDECLARE UserDatabases_CTE_Cursor Cursor\nFOR\n\n-- Selecting user database names.\nselect name as DatabaseName\nfrom sys.sysdatabases\nwhere ([dbid] > 4) and ([name] not like \'$\') and ([name] not like \'ReportServer%\') and ([name] not like \'TMP_axSQLDoctor%\') and ([name] not like \'DIKTERSA\')\n\nOPEN UserDatabases_CTE_Cursor\nDECLARE @dbName varchar(100);\n\nDECLARE @compatQuery varchar(500);\n\nFetch NEXT FROM UserDatabases_CTE_Cursor INTO @dbName\nWhile (@@FETCH_STATUS <> -1)\n\nBEGIN\n-- set database compatibility level\n/*\n120 2014\n110 Para SQL server 2012 El nivel de compatibilidad requerido\n100 2008\n90~~2005\n*/\nset @compatQuery =~~\'ALTER DATABASE \' + \'[\' + @dbName + \']\' +\' SET COMPATIBILITY_LEVEL = 110;\'\n\n-- Print SQL statement\nprint @compatQuery\n\n-- Execute compatability script\nEXEC (@compatQuery)\n\n-- Get next database\nFetch NEXT FROM UserDatabases_CTE_Cursor INTO @dbName\nEND\n\nCLOSE UserDatabases_CTE_Cursor\nDEALLOCATE UserDatabases_CTE_Cursor\nGO', '', 1, '2026-04-02 15:40:32', '2026-04-02 15:40:32', NULL),
