(513, 1, 765, NULL, 'AXOFT - BackUp y Restauración automática en otra base', 'Crear un archivo .bat -> BckyRestDIKSLDSAST.bat\n\ndel d:\\BackUp\\xxxDIKTERSA_SLDS_ASTOR.bak\nosql -S SVRTANGO -U sa -Pxxxxxxxxxx -i \"d:\\Tango\\ReAxion\\BckyRestDIKSLDSAST.sql\"\n\nCrear un archivo .sql -> BckyRestDIKSLDSAST.sql\n\nbackup database [DIKTERSA_SLDS_ASTOR]\nto disk = \'d:\\BackUp\\xxxDIKTERSA_SLDS_ASTOR.bak\'\nWITH NOINIT, DESCRIPTION = N\'Copia de seguridad Automatizada\',\nNOUNLOAD, NAME = N\'Copia de Seguridad DIKTERSA_SLDS_ASTOR\',\nNOSKIP, STATS = 10, NOFORMAT\ngo\nRESTORE DATABASE [DIKTERSA_SLDS_GERMAN]\n~~~~FROM DISK = \'d:\\BackUp\\xxxDIKTERSA_SLDS_ASTOR.bak\'\nWITH REPLACE,\nSTATS = 10,\nMOVE \'9_70_000_TangoDefGVAR\'~~~~ TO \'D:\\DatosAxoft\\DIKTERSA_SLDS_GERMAN_Data.mdf\',\nMOVE \'9_70_000_TangoDefGVAR_Log\' TO \'D:\\DatosAxoft\\DIKTERSA_SLDS_GERMAN_Log.ldf\'\ngo\n\nPara saber los nombres lógicos:\n\nRESTORE FILELISTONLY FROM DISK =\'d:\\BackUp\\xxxDIKTERSA_SLDS_ASTOR.bak\'', '', 1, '2026-04-02 15:40:32', '2026-04-02 15:40:32', NULL),
