(522, 1, 765, NULL, 'MACOWENS - Tango 037151/002 23.01.000 CUOTAS', 'Estimado cliente:\nLos códigos de cuota que a continuación se detallan corresponden al sistema:\nNúmero de llave:~037151/002\n\nTerminales:5\n\nVersión:23.01.000\n\nMódulos:Contabilidad Astor - Live web. - Sueldos Astor\n\nNexo:~Tango Backup: Si - Tango Clientes: Si - Tango Connect: Si - Tango Empleados: Si - Tango Fichadas: Si - Tango Update: Si - Tango Reportes: Si - Espacio Nexo: 4000 Mb - Espacio Backup: -1 Mb - Tango Tablero: Si\n~\nVea aquí como ingresar su cuota\n\nSi no puede ver este video, acceda al instructivo desde aquí.\n~\ncuotas@axoft.com\nCuota:\nCódigo:\n 1-80257859   27.02 x mail a Johanna  \n 2-34365590   11.04 x mail a Johanna\n 3-97701097   21.05 x mail a Johanna\n 4-48269756   02.07 x mail a Johanna\n 5-78554709   12.08 x mail a Johanna\n 6-37354314   23.09 x mail a Johanna\n 7-25296135   04.11 x mail a Johanna\n 8-04360125   16.12 x mail a Pablo\n 9-95888380   27.01 x mail a Rocio\n10-82470598  10.03 x mail a Johanna\n11-40854836  21.04 x mail a Johanna\n12-46766961  30.05 x mail a Johanna', '', 1, '2026-04-02 15:40:32', '2026-04-02 15:40:32', NULL),
(523, 1, 800, NULL, 'AXOFT - Shrink base de datos', '/*Reducir log de una base de datos*/\nDBCC SHRINKDATABASE (FILTRON_SRL_Data)\nGO', '', 1, '2026-04-02 15:40:32', '2026-04-02 15:40:32', NULL),
(524, 1, 800, NULL, 'AXOFT - Copia de Diccionario roto a uno nuevo', 'Sergio, en este caso la manera más simple sería configurar el servidor con el diccionario anterior, hacer la exportación de las consultas externas desde el administrador de consultas externas, luego configurar el servidor con el diccionario actual e importarlas masivamente. Si no, se puede hacer el pasaje mediante un script, pero hay que pasar todo del diccionario anterior al nuevo para que quede todo relacionado. Te paso el script . Cualquier cosa avisame.\n\nYaroslav Baklan\n\n/*\n\nEJECUTAR SIEMPRE CONECTADO AL DICCIO ORIGINAL\nSETEAR LAS VARIABLES @FILTROS , @LIVE EN S SI QUIEREN PASAR LA INFO DE FILTROS O LIVE RESPECTIVAMENTE\nlo mismo para el tablero de control @tablero = \'S\'\n\nATENCIÓN: SI POSEE MÁS DE UN SERVIDOR DE BASES DE DATOS, AL FINALIZAR EL TRASPAZO, HAY QUE AGREGAR LOS SERVIDORES\nA LA TABLA SERVER, COMPLETAR LA TABLA SERVERDOMINIO Y POR ÚLTIMO CORRER LO SIGUIENTE:\n\nUPDATE [DICCIONUEVO].[DBO].EMPRESA SET IDSERVER = E2.IDSERVER, USUARIOBD = E2.USUARIOBD, CLAVEBD = E2.CLAVEBD\nFROM [DICCIONUEVO].[DBO].EMPRESA JOIN EMPRESA E2 ON NOMBREBD = E2.NOMBREBD\n\n*/\n\nDECLARE @FILTROS VARCHAR(1) , @LIVE VARCHAR(1) , @TABLERO VARCHAR(1)\nSET @FILTROS = \'S\'\nSET @LIVE = \'S\'\nSET @TABLERO = \'N\'\n\nSET NOCOUNT ON\n\nDELETE [DICCIONUEVO].[DBO].BUSCARENCAMPO WHERE IDCAMPO IN (SELECT IDCAMPO FROM [DICCIONUEVO].[DBO].CAMPOADICIONAL WHERE IDEMPRESA IN (SELECT IDEMPRESA FROM [DICCIONUEVO].[DBO].EMPRESA))\nDELETE [DICCIONUEVO].[DBO].REQUERIDOS WHERE IDCAMPO IN (SELECT IDCAMPO FROM [DICCIONUEVO].[DBO].CAMPOADICIONAL WHERE IDEMPRESA IN (SELECT IDEMPRESA FROM [DICCIONUEVO].[DBO].EMPRESA))\nDELETE [DICCIONUEVO].[DBO].CAMPOADICIONAL WHERE IDEMPRESA IN (SELECT IDEMPRESA FROM [DICCIONUEVO].[DBO].EMPRESA)\nDELETE [DICCIONUEVO].[DBO].CAMPO WHERE CAMPO LIKE \'CA[_]%\' AND IDCAMPO NOT IN (SELECT IDCAMPO FROM [DICCIONUEVO].[DBO].CAMPOADICIONAL)\nDELETE [DICCIONUEVO].[DBO].DOMINIO WHERE DOMINIO LIKE \'CA[_]%\' AND DOMINIO NOT IN (SELECT CAMPO FROM [DICCIONUEVO].[DBO].CAMPO)\nDELETE [DICCIONUEVO].[DBO].PERMISO\nDELETE [DICCIONUEVO].[DBO].VARIABLEMASCARAEMPRESA\nDELETE [DICCIONUEVO].[DBO].CONFIGURACIONEMPRESA\nUPDATE [DICCIONUEVO].[DBO].USUARIO SET IDEMPRESA = NULL\nDELETE [DICCIONUEVO].[DBO].EMPRESA\n\nINSERT INTO [DICCIONUEVO].[DBO].[EMPRESA]\n~~~~~~~~~~ ([IDEMPRESA]\n~~~~~~~~~~ ,[IDDOMINIOCUENTA]\n~~~~~~~~~~ ,[IDSERVER]\n~~~~~~~~~~ ,[NOMBREEMPRESA]\n~~~~~~~~~~ ,[NOMBREBD]\n~~~~~~~~~~ ,[TIPOBD]\n~~~~~~~~~~ ,[USUARIOBD]\n~~~~~~~~~~ ,[CLAVEBD]\n~~~~~~~~~~ ,[HABILITA]\n~~~~~~~~~~ ,[CENTRALIZA])\nSELECT IDEMPRESA\n~~~~~~~~~~ ,[IDDOMINIOCUENTA]\n~~~~~~~~~~ ,1\n~~~~~~~~~~ ,[NOMBREEMPRESA]\n~~~~~~~~~~ ,[NOMBREBD]\n~~~~~~~~~~ ,[TIPOBD]\n~~~~~~~~~~ ,[USUARIOBD]\n~~~~~~~~~~ ,[CLAVEBD]\n~~~~~~~~~~ ,[HABILITA]\n~~~~~~~~~~ ,[CENTRALIZA] FROM EMPRESA\n\nINSERT INTO [DICCIONUEVO].[DBO].[USUARIO]\n~~~~~~ ([IDUSUARIO]\n~~~~~~ ,[IDEMPRESA]\n~~~~~~ ,[IDDOMINIOCUENTA]\n~~~~~~ ,[NOMBREUSUARIO]\n~~~~~~ ,[NOMBRECOMPLETO]\n~~~~~~ ,[CLAVE]\n~~~~~~ ,[CONSULTASIMPLE]\n~~~~~~ ,[USUARIODERED]\n~~~~~~ ,[EMAIL])\nSELECT [IDUSUARIO]\n~~~~~~ ,[IDEMPRESA]\n~~~~~~ ,[IDDOMINIOCUENTA]\n~~~~~~ ,[NOMBREUSUARIO]\n~~~~~~ ,[NOMBRECOMPLETO]\n~~~~~~ ,[CLAVE]\n~~~~~~ ,[CONSULTASIMPLE]\n~~~~~~ ,[USUARIODERED]\n~~~~~~ ,[EMAIL] FROM USUARIO WHERE IDUSUARIO <> 1\n~~~~~~\nIF EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE COLUMN_NAME = \'NEXOUSUARIO\' AND TABLE_NAME = \'USUARIO\')\nBEGIN\nDECLARE @SQLUSUARIO VARCHAR(MAX)\nSET @SQLUSUARIO = \'UPDATE USUARIO SET NEXOTOKEN = U2.NEXOTOKEN, NEXOUSUARIO = U2.NEXOUSUARIO, NEXOHABILITADO = U2.NEXOHABILITADO\nFROM USUARIO JOIN [DICCIONUEVO].[DBO].USUARIO U2 ON IDUSUARIO = U2.IDUSUARIO\'\nEXEC (@SQLUSUARIO)\nEND\n~~~~~~~~~~\nUPDATE [DICCIONUEVO].[DBO].[USUARIO] SET CLAVE = (SELECT CLAVE FROM USUARIO WHERE IDUSUARIO =1 ) WHERE IDUSUARIO = 1~~~~~~~~~~\n\nINSERT INTO [DICCIONUEVO].[DBO].[ATRIBUTOMENUADMINISTRADOR]\n~~~~~~~~~~ ([IDOPCIONMENU]\n~~~~~~~~~~ ,[IDATRIBUTO]\n~~~~~~~~~~ ,[IDUSUARIO])\nSELECT [IDOPCIONMENU]\n~~~~~~~~~~ ,[IDATRIBUTO]\n~~~~~~~~~~ ,[IDUSUARIO] FROM ATRIBUTOMENUADMINISTRADOR WHERE IDUSUARIO <> 1\n\nINSERT INTO [DICCIONUEVO].[DBO].[ROL]\n~~~~~~~~~~ ([IDROL]\n~~~~~~~~~~ ,[IDDOMINIOCUENTA]\n~~~~~~~~~~ ,[NOMBREROL]\n~~~~~~~~~~ ,[DESCRIPCIONROL]\n~~~~~~~~~~ ,[ACCESOTOTAL]\n~~~~~~~~~~ ,[BUSCARMAXIMO]\n~~~~~~~~~~ ,[FILTROVERTICAL]\n~~~~~~~~~~ ,[CANTREGISTROBUSCAR]\n~~~~~~~~~~ ,[CANTREGISTROMULTIDIMENSIONAL]\n~~~~~~~~~~ ,[TAMANIOREPORTE])\nSELECT [IDROL]\n~~~~~~~~~~ ,[IDDOMINIOCUENTA]\n~~~~~~~~~~ ,[NOMBREROL]\n~~~~~~~~~~ ,[DESCRIPCIONROL]\n~~~~~~~~~~ ,[ACCESOTOTAL]\n~~~~~~~~~~ ,[BUSCARMAXIMO]\n~~~~~~~~~~ ,[FILTROVERTICAL]\n~~~~~~~~~~ ,[CANTREGISTROBUSCAR]\n~~~~~~~~~~ ,[CANTREGISTROMULTIDIMENSIONAL]\n~~~~~~~~~~ ,[TAMANIOREPORTE] FROM ROL WHERE IDROL <>1\n\nINSERT INTO [DICCIONUEVO].[DBO].[ROLATRIBUTO]\n~~~~~~~~~~ ([IDROL]\n~~~~~~~~~~ ,[IDOPCIONMENU]\n~~~~~~~~~~ ,[IDATRIBUTO])\nSELECT [IDROL]\n~~~~~~~~~~ ,[IDOPCIONMENU]\n~~~~~~~~~~ ,[IDATRIBUTO] FROM ROLATRIBUTO WHERE IDOPCIONMENU IN (SELECT IDOPCIONMENU FROM [DICCIONUEVO]..OPCIONMENU)\n\nINSERT INTO [DICCIONUEVO].[DBO].[PERMISO]\n~~~~~~~~~~ ([IDROL]\n~~~~~~~~~~ ,[IDEMPRESA]\n~~~~~~~~~~ ,[IDUSUARIO])\nSELECT [IDROL]\n~~~~~~~~~~ ,[IDEMPRESA]\n~~~~~~~~~~ ,[IDUSUARIO] FROM PERMISO\n\n/* ESTA PARTE ES PARA FILTROS DE SEGURIDAD */\nIF (@FILTROS = \'S\')\nBEGIN\nPRINT \'PASO LOS FILTROS\'\nINSERT INTO [DICCIONUEVO]..[CONSULTAUSU]\n~~ ([IDCONSULTA]\n~~ ,[IDEMPRESA]\n~~ ,[CONSULTAUSU]\n~~ ,[GENERABLE]\n~~ ,[ORDERBY]\n~~ ,[ORDERBYTYPE]\n~~ ,[VISIBLETODOS]\n~~ ,[FILTROSQL]\n~~ ,[FECHADEUSO]\n~~ ,[ESFILTROTEMPORAL]\n~~ ,[ORDEN])\nSELECT [IDCONSULTA]\n~~ ,[IDEMPRESA]\n~~ ,[CONSULTAUSU]\n~~ ,[GENERABLE]\n~~ ,[ORDERBY]\n~~ ,[ORDERBYTYPE]\n~~ ,[VISIBLETODOS]\n~~ ,[FILTROSQL]\n~~ ,[FECHADEUSO]\n~~ ,[ESFILTROTEMPORAL]\n~~ ,[ORDEN] FROM CONSULTAUSU\n~~~~~~~~~~\nINSERT INTO [DICCIONUEVO].[DBO].[SELECTS]\n~~ ([IDLINK]\n~~ ,[ORDEN]\n~~ ,[IDCONSULTAUSU]\n~~ ,[IDCAMPO])\nSELECT [IDLINK]\n~~ ,[ORDEN]\n~~ ,[IDCONSULTAUSU]\n~~ ,[IDCAMPO] FROM SELECTS WHERE IDCONSULTAUSU IN (SELECT IDCONSULTAUSU FROM [DICCIONUEVO]..CONSULTAUSU)\nEND\n/* FIN ---- ESTA PARTE ES PARA FILTROS DE SEGURIDAD */\n\n/* CONSULTAS EXTERNAS , FAVORITOS, COMPARTIDAS, EXTERNAS */\nIF (@LIVE = \'S\')\nBEGIN\nPRINT \'PASO LAS CONSULTAS LIVE CONFIGURADAS, EXTERNAS, FAVORITOS Y COMPARTIDAS\'\nSET IDENTITY_INSERT [DICCIONUEVO]..tlcarpetaconsulta ON\nINSERT INTO [DICCIONUEVO].[DBO].[TLCARPETACONSULTA]\n~~ ([id_carpetaconsulta]\n~~ ,[ID_PADRE_CARPETACONSULTA]\n~~ ,[DESC_CARPETACONSULTA]\n~~ ,[ORDEN_CARPETACONSULTA]\n~~ ,[ORDEN_NIVEL_CARPETACONSULTA]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ATRIBUTOS_CARPETACONSULTA])\nSELECT [id_carpetaconsulta]\n,[ID_PADRE_CARPETACONSULTA]\n~~ ,[DESC_CARPETACONSULTA]\n~~ ,[ORDEN_CARPETACONSULTA]\n~~ ,[ORDEN_NIVEL_CARPETACONSULTA]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ATRIBUTOS_CARPETACONSULTA] FROM TLCARPETACONSULTA WHERE ID_CARPETACONSULTA <> 1\nSET IDENTITY_INSERT [DICCIONUEVO]..tlcarpetaconsulta OFF\n\nSET IDENTITY_INSERT [DICCIONUEVO]..TLCARPETACONSULTAEXTERNA ON\nINSERT INTO [DICCIONUEVO].[DBO].[TLCARPETACONSULTAEXTERNA]\n~~ ([ID_CARPETACONSULTAEXTERNA]\n~~ ,[ID_PADRE_CARPETACONSULTAEXTERNA]\n~~ ,[DESC_CARPETACONSULTAEXTERNA]\n~~ ,[ORDEN_CARPETACONSULTAEXTERNA]\n~~ ,[ORDEN_NIVEL_CARPETACONSULTAEXTERNA]\n~~ ,[GUID_CARPETACONSULTAEXTERNA])\nSELECT [ID_CARPETACONSULTAEXTERNA]\n~~ ,[ID_PADRE_CARPETACONSULTAEXTERNA]\n~~ ,[DESC_CARPETACONSULTAEXTERNA]\n~~ ,[ORDEN_CARPETACONSULTAEXTERNA]\n~~ ,[ORDEN_NIVEL_CARPETACONSULTAEXTERNA]\n~~ ,[GUID_CARPETACONSULTAEXTERNA] FROM TLCARPETACONSULTAEXTERNA\nSET IDENTITY_INSERT [DICCIONUEVO]..TLCARPETACONSULTAEXTERNA OFF\n\nINSERT INTO [DICCIONUEVO].[DBO].[TLCARPETAFAVORITO]\n~~ ([ID_PADRE_CARPETAFAVORITO]\n~~ ,[DESC_CARPETAFAVORITO]\n~~ ,[ORDEN_CARPETAFAVORITO]\n~~ ,[ORDEN_NIVEL_CARPETAFAVORITO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA])\nSELECT [ID_PADRE_CARPETAFAVORITO]\n~~ ,[DESC_CARPETAFAVORITO]\n~~ ,[ORDEN_CARPETAFAVORITO]\n~~ ,[ORDEN_NIVEL_CARPETAFAVORITO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA] FROM TLCARPETAFAVORITO\n~~~~~~~~~~\nINSERT INTO [DICCIONUEVO].[DBO].[TLCONEXIONEXTERNA]\n~~ ([TIPO_CONEXIONEXTERNA]\n~~ ,[SERVIDOR_CONEXIONEXTERNA]\n~~ ,[USUARIO_CONEXIONEXTERNA]\n~~ ,[CLAVE_CONEXIONEXTERNA]\n~~ ,[BASEDATOS_CONEXIONEXTERNA]\n~~ ,[NOMBREODBC_CONEXIONEXTERNA])\nSELECT [TIPO_CONEXIONEXTERNA]\n~~ ,[SERVIDOR_CONEXIONEXTERNA]\n~~ ,[USUARIO_CONEXIONEXTERNA]\n~~ ,[CLAVE_CONEXIONEXTERNA]\n~~ ,[BASEDATOS_CONEXIONEXTERNA]\n~~ ,[NOMBREODBC_CONEXIONEXTERNA] FROM TLCONEXIONEXTERNA\n~~~~~~~~~~\nINSERT INTO [DICCIONUEVO].[DBO].[TLCONSULTAEXTERNA]\n~~ ([ID_CONEXIONEXTERNA]\n~~ ,[ID_CARPETACONSULTAEXTERNA]\n~~ ,[ID_EMPRESA]\n~~ ,[TITULO_CONSULTAEXTERNA]\n~~ ,[CONSULTASQL_CONSULTAEXTERNA]\n~~ ,[ORDEN_CONSULTAEXTERNA]\n~~ ,[DESCRIPCION_CONSULTAEXTERNA]\n~~ ,[MODOVISUALIZACION_CONSULTAEXTERNA]\n~~ ,[PREFERENCIASPIVOT_CONSULTAEXTERNA]\n~~ ,[PREFERENCIASTABLA_CONSULTAEXTERNA]\n~~ ,[ORIGEN_CONSULTAEXTERNA]\n~~ ,[AUTOR_CONSULTAEXTERNA]\n~~ ,[SOPORTE_CONSULTAEXTERNA]\n~~ ,[GUID_CONSULTAEXTERNA])\nSELECT [ID_CONEXIONEXTERNA]\n~~ ,[ID_CARPETACONSULTAEXTERNA]\n~~ ,[ID_EMPRESA]\n~~ ,[TITULO_CONSULTAEXTERNA]\n~~ ,[CONSULTASQL_CONSULTAEXTERNA]\n~~ ,[ORDEN_CONSULTAEXTERNA]\n~~ ,[DESCRIPCION_CONSULTAEXTERNA]\n~~ ,[MODOVISUALIZACION_CONSULTAEXTERNA]\n~~ ,[PREFERENCIASPIVOT_CONSULTAEXTERNA]\n~~ ,[PREFERENCIASTABLA_CONSULTAEXTERNA]\n~~ ,[ORIGEN_CONSULTAEXTERNA]\n~~ ,[AUTOR_CONSULTAEXTERNA]\n~~ ,[SOPORTE_CONSULTAEXTERNA]\n~~ ,[GUID_CONSULTAEXTERNA] FROM TLCONSULTAEXTERNA\n~~~~~~~~~~\nSET IDENTITY_INSERT [DICCIONUEVO]..TLCONSULTAUSUARIO ON\nINSERT INTO [DICCIONUEVO].[DBO].[TLCONSULTAUSUARIO]\n~~ ([ID_CONSULTAUSUARIO]\n~~ ,[ID_CARPETACONSULTA]\n~~ ,[ID_CONSULTA]\n~~ ,[TITULO_CONSULTAUSUARIO]\n~~ ,[SUB_TITULO_CONSULTAUSUARIO]\n~~ ,[ORDEN_CONSULTAUSUARIO]\n~~ ,[PARAMETROS_CONSULTAUSUARIO]\n~~ ,[AGRUPACION_CONSULTAUSUARIO]\n~~ ,[ORDENAMIENTO_CONSULTAUSUARIO]\n~~ ,[REG_POR_PAGINA_CONSULTAUSUARIO]\n~~ ,[CANTIDAD_RANK_CONSULTAUSUARIO]\n~~ ,[MODOVISUALIZACION_CONSULTAUSUARIO]\n~~ ,[ESTADO_CONSULTAUSUARIO])\nSELECT [ID_CONSULTAUSUARIO]\n~~ ,[ID_CARPETACONSULTA]\n~~ ,[ID_CONSULTA]\n~~ ,[TITULO_CONSULTAUSUARIO]\n~~ ,[SUB_TITULO_CONSULTAUSUARIO]\n~~ ,[ORDEN_CONSULTAUSUARIO]\n~~ ,[PARAMETROS_CONSULTAUSUARIO]\n~~ ,[AGRUPACION_CONSULTAUSUARIO]\n~~ ,[ORDENAMIENTO_CONSULTAUSUARIO]\n~~ ,[REG_POR_PAGINA_CONSULTAUSUARIO]\n~~ ,[CANTIDAD_RANK_CONSULTAUSUARIO]\n~~ ,[MODOVISUALIZACION_CONSULTAUSUARIO]\n~~ ,[ESTADO_CONSULTAUSUARIO] FROM TLCONSULTAUSUARIO\nSET IDENTITY_INSERT [DICCIONUEVO]..TLCONSULTAUSUARIO OFF\n\nINSERT INTO [DICCIONUEVO].[DBO].[TLCONSULTAUSUARIOUSUARIOS]\n~~ ([ID_CONSULTAUSUARIO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA])\nSELECT [ID_CONSULTAUSUARIO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA] FROM TLCONSULTAUSUARIOUSUARIOS\n~~~~~~~~~~\nINSERT INTO [DICCIONUEVO].[DBO].[TLFAVORITO]\n~~ ([ID_CONSULTAUSUARIO]\n~~ ,[ID_CONSULTAEXTERNA]\n~~ ,[ID_CONSULTACOMPUESTA]\n~~ ,[ID_CARPETAFAVORITO]\n~~ ,[ID_CONSULTA]\n~~ ,[ID_EMPRESA]\n~~ ,[ID_USUARIO]\n~~ ,[TITULO_FAVORITO]\n~~ ,[ORDEN_FAVORITO]\n~~ ,[VERENPRINCIPAL_FAVORITO]\n~~ ,[CONTENEDOR_FAVORITO])\nSELECT [ID_CONSULTAUSUARIO]\n~~ ,[ID_CONSULTAEXTERNA]\n~~ ,[ID_CONSULTACOMPUESTA]\n~~ ,[ID_CARPETAFAVORITO]\n~~ ,[ID_CONSULTA]\n~~ ,[ID_EMPRESA]\n~~ ,[ID_USUARIO]\n~~ ,[TITULO_FAVORITO]\n~~ ,[ORDEN_FAVORITO]\n~~ ,[VERENPRINCIPAL_FAVORITO]\n~~ ,[CONTENEDOR_FAVORITO] FROM TLFAVORITO\n\nINSERT INTO [DICCIONUEVO].[DBO].[TLINICIO]\n~~ ([NOMBRE_INICIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ID_USUARIO])\nSELECT [NOMBRE_INICIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ID_USUARIO] FROM TLINICIO\n~~~~~~~~~~\nINSERT INTO [DICCIONUEVO].[DBO].[TLORDENMODULOUSUARIO]\n~~ ([ID_MODULO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ORDEN_ORDENMODULOUSUARIO]\n~~ ,[VISIBLE_ORDENMODULOUSUARIO]\n~~ ,[POSICION_ORDENMODULOUSUARIO])\nSELECT [ID_MODULO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ORDEN_ORDENMODULOUSUARIO]\n~~ ,[VISIBLE_ORDENMODULOUSUARIO]\n~~ ,[POSICION_ORDENMODULOUSUARIO] FROM TLORDENMODULOUSUARIO\n~~~~~~~~~~\nINSERT INTO [DICCIONUEVO].[DBO].[TLPREFERENCIAUSUARIO]\n~~ ([ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[PREFERENCIA_PREFERENCIAUSUARIO])\nSELECT [ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[PREFERENCIA_PREFERENCIAUSUARIO] FROM TLPREFERENCIAUSUARIO\n\nINSERT INTO [DICCIONUEVO].[DBO].[TLCONSULTACOMPARTIDA]\n~~ ([ID_CONSULTAUSUARIO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ATRIBUTO_CONSULTACOMPARTIDA])\nSELECT~~~~~~[ID_CONSULTAUSUARIO]\n~~ ,[ID_USUARIO]\n~~ ,[ID_EMPRESA]\n~~ ,[ATRIBUTO_CONSULTACOMPARTIDA] FROM TLCONSULTACOMPARTIDA~~~~\nEND ~~\n/* FIN CONSULTAS EXTERNAS, FAVORITOS, COMPARTIDAS*/\n\n/* TABLERO DE CONTROL CON SUS INDICADORES */\nif (@tablero = \'S\')\nBEGIN\nPRINT \'PASO LOS TABLEROS, PANELES, INDICADORES\'\nDECLARE @TABLA AS VARCHAR(MAX), @FK AS VARCHAR(MAX), @SQLTABLERO AS VARCHAR(MAX)\nDECLARE RS CURSOR LOCAL FOR\nselect table_name, constraint_name from information_schema.constraint_table_usage\nwhere table_name in (\'indicador\',\'tablero\',\'panel\',\'historicoindicador\',\'indicadorporpublicacion\',\'publicacion\',\'seguridadindicador\',\'variableindicador\',\'variablepublicacion\')\nand constraint_name like \'fk[_]%\'\nOPEN RS\nFETCH NEXT FROM RS INTO @TABLA, @FK\nWHILE @@FETCH_STATUS = 0\nBEGIN\nSET @SQLTABLERO = \'alter table [DICCIONUEVO].[DBO].\'+@TABLA+\' DROP CONSTRAINT \'+@FK\n--PRINT @SQLTABLERO\nEXEC (@SQLTABLERO)\nFETCH NEXT FROM RS INTO @TABLA, @FK\nEND\nCLOSE RS\nDEALLOCATE RS\n\nDELETE [DICCIONUEVO].[DBO].INDICADOR\nDELETE [DICCIONUEVO].[DBO].TABLERO\nDELETE [DICCIONUEVO].[DBO].PANEL\nDELETE [DICCIONUEVO].[DBO].HISTORICOINDICADOR\nDELETE [DICCIONUEVO].[DBO].INDICADORPORPUBLICACION\nDELETE [DICCIONUEVO].[DBO].PUBLICACION\nDELETE [DICCIONUEVO].[DBO].SEGURIDADINDICADOR\nDELETE [DICCIONUEVO].[DBO].VARIABLEINDICADOR\nDELETE [DICCIONUEVO].[DBO].VARIABLEPUBLICACION\n\nINSERT INTO [DICCIONUEVO].[DBO].INDICADOR (GUIDINDICADOR,GUIDFRECUENCIAAHISTORICO,GUIDVALORINDICADOR,GUIDVALORANTERIORINDICADOR,CODIGOTIPOINDICADOR,GUIDPANEL,CODIGOINDICADOR,NOMBREINDICADOR,PARAMININDICADOR,RESUMENDEFINICIONINDICADOR,FILTROFILTRARINDICADOR,FILTROCOLUMNAINDICADOR,FILTROCONDICION1INDICADOR,FILTROVALOR1INDICADOR,FILTRONEXOINDICADOR,FILTROCONDICION2INDICADOR,FILTROVALOR2INDICADOR,RESULTADOOPERACIONINDICADOR,RESULTADOFORMATOINDICADOR,RESULTADOCOLUMNAINDICADOR,RESULTADOCOLUMNASALIDAINDICADOR,RESULTADOTIPOINDICADOR,RESULTADOPOSITIVOINDICADOR,RESULTADOUSAVREFINFINDICADOR,RESULTADOUSAVREFSUPINDICADOR,RESULTADOUSAVREFMEDINDICADOR,ORDENINDICADOR,ACCESORESTRINGIDOINDICADOR,CANTREGHISTORICOINDICADOR)\nSELECT GUIDINDICADOR,GUIDFRECUENCIAAHISTORICO,GUIDVALORINDICADOR,GUIDVALORANTERIORINDICADOR,CODIGOTIPOINDICADOR,GUIDPANEL,CODIGOINDICADOR,NOMBREINDICADOR,PARAMININDICADOR,RESUMENDEFINICIONINDICADOR,FILTROFILTRARINDICADOR,FILTROCOLUMNAINDICADOR,FILTROCONDICION1INDICADOR,FILTROVALOR1INDICADOR,FILTRONEXOINDICADOR,FILTROCONDICION2INDICADOR,FILTROVALOR2INDICADOR,RESULTADOOPERACIONINDICADOR,RESULTADOFORMATOINDICADOR,RESULTADOCOLUMNAINDICADOR,RESULTADOCOLUMNASALIDAINDICADOR,RESULTADOTIPOINDICADOR,RESULTADOPOSITIVOINDICADOR,RESULTADOUSAVREFINFINDICADOR,RESULTADOUSAVREFSUPINDICADOR,RESULTADOUSAVREFMEDINDICADOR,ORDENINDICADOR,ACCESORESTRINGIDOINDICADOR,CANTREGHISTORICOINDICADOR FROM INDICADOR\n\nINSERT INTO [DICCIONUEVO].[DBO].TABLERO (GUIDTABLERO,NOMBRETABLERO,ACTIVOTABLERO,TIPONOTIFERRORTABLERO,NOMUSUPROBTABLERO,EMAILUSUPROBTABLERO,SERVIDORSMTP,USUARIOSMTP,CONTRASENASMTP,REMITENTESMTP,ORDENTABLERO)\nSELECT GUIDTABLERO,NOMBRETABLERO,ACTIVOTABLERO,TIPONOTIFERRORTABLERO,NOMUSUPROBTABLERO,EMAILUSUPROBTABLERO,SERVIDORSMTP,USUARIOSMTP,CONTRASENASMTP,REMITENTESMTP,ORDENTABLERO FROM TABLERO\n\nINSERT INTO [DICCIONUEVO].[DBO].PANEL (GUIDPANEL,GUIDTABLERO,NOMBREPANEL,ACTIVOPANEL,EMPRESA,USUARIO,ORDENPANEL)\nSELECT GUIDPANEL,GUIDTABLERO,NOMBREPANEL,ACTIVOPANEL,EMPRESA,USUARIO,ORDENPANEL FROM PANEL\n\nSET IDENTITY_INSERT [DICCIONUEVO].[DBO].HISTORICOINDICADOR ON\nINSERT INTO [DICCIONUEVO].[DBO].HISTORICOINDICADOR (IDHISTORICOINDICADOR,GUIDINDICADOR,FINULTIMAEJECUCIONINDICADOR,VARIACIONINDICADOR,RESULTADOVALORINDICADOR,RESULTADOFUNCIONOINDICADOR,RESUMENEJECUCIONINDICADOR,REFERENCIAVALORMINIMOINDICADOR,REFERENCIAVALORMAXIMOINDICADOR,REFERENCIAVALORMEDIOINDICADOR,INICIOULTIMAEJECUCIONINDICADOR)\nSELECT IDHISTORICOINDICADOR,GUIDINDICADOR,FINULTIMAEJECUCIONINDICADOR,VARIACIONINDICADOR,RESULTADOVALORINDICADOR,RESULTADOFUNCIONOINDICADOR,RESUMENEJECUCIONINDICADOR,REFERENCIAVALORMINIMOINDICADOR,REFERENCIAVALORMAXIMOINDICADOR,REFERENCIAVALORMEDIOINDICADOR,INICIOULTIMAEJECUCIONINDICADOR FROM HISTORICOINDICADOR\nSET IDENTITY_INSERT [DICCIONUEVO].[DBO].HISTORICOINDICADOR OFF\n\nINSERT INTO [DICCIONUEVO].[DBO].INDICADORPORPUBLICACION (GUIDPUBLICACION,GUIDINDICADOR)\nSELECT GUIDPUBLICACION,GUIDINDICADOR FROM INDICADORPORPUBLICACION\n\nINSERT INTO [DICCIONUEVO].[DBO].PUBLICACION (GUIDPUBLICACION,GUIDVARIABLEPUBLICACION,CODIGOTIPOPUBLICACION,GUIDPANEL,NOMBREPUBLICACION,ACTIVOPUBLICACION,PARAMINPUBLICACION,RESUMENDEFINICIONPUBLICACION,SELINDPUBLICACION,SOLOSIISOBREUMBPUBLICACION,SOLOSIIBAJOUMBPUBLICACION)\nSELECT GUIDPUBLICACION,GUIDVARIABLEPUBLICACION,CODIGOTIPOPUBLICACION,GUIDPANEL,NOMBREPUBLICACION,ACTIVOPUBLICACION,PARAMINPUBLICACION,RESUMENDEFINICIONPUBLICACION,SELINDPUBLICACION,SOLOSIISOBREUMBPUBLICACION,SOLOSIIBAJOUMBPUBLICACION FROM PUBLICACION\n\nINSERT INTO [DICCIONUEVO].[DBO].SEGURIDADINDICADOR (GUIDINDICADOR,NOMBREUSUARIOSEGURIDADINDICADOR)\nSELECT GUIDINDICADOR,NOMBREUSUARIOSEGURIDADINDICADOR FROM SEGURIDADINDICADOR\n\nINSERT INTO [DICCIONUEVO].[DBO].VARIABLEINDICADOR (GUIDVARIABLEINDICADOR,GUIDINDICADOR,INICIOULTIMAEJECUCIONINDICADOR,FINULTIMAEJECUCIONINDICADOR,VARIACIONINDICADOR,RESULTADOVALORINDICADOR,RESULTADOFUNCIONOINDICADOR,RESUMENEJECUCIONINDICADOR,REFERENCIAVALORMINIMOINDICADOR,REFERENCIAVALORMAXIMOINDICADOR,REFERENCIAVALORMEDIOINDICADOR)\nSELECT GUIDVARIABLEINDICADOR,GUIDINDICADOR,INICIOULTIMAEJECUCIONINDICADOR,FINULTIMAEJECUCIONINDICADOR,VARIACIONINDICADOR,RESULTADOVALORINDICADOR,RESULTADOFUNCIONOINDICADOR,RESUMENEJECUCIONINDICADOR,REFERENCIAVALORMINIMOINDICADOR,REFERENCIAVALORMAXIMOINDICADOR,REFERENCIAVALORMEDIOINDICADOR FROM VARIABLEINDICADOR\n\nINSERT INTO [DICCIONUEVO].[DBO].VARIABLEPUBLICACION (GUIDVARIABLEPUBLICACION,GUIDPUBLICACION,RESUMENEJECUCIONPUBLICACION,RESULTADOPUBLICACION,ULTEJEC_INICIO,ULTEJEC_FIN)\nSELECT GUIDVARIABLEPUBLICACION,GUIDPUBLICACION,RESUMENEJECUCIONPUBLICACION,RESULTADOPUBLICACION,ULTEJEC_INICIO,ULTEJEC_FIN FROM VARIABLEPUBLICACION\n\nINSERT INTO [DICCIONUEVO]..[PTA03]\n~~~~~~~~~~ ([FILLER]\n~~~~~~~~~~ ,[COD_FRECU]\n~~~~~~~~~~ ,[DESC_FRECU]\n~~~~~~~~~~ ,[EJECUCION]\n~~~~~~~~~~ ,[ED_CADA]\n~~~~~~~~~~ ,[ES_CADA]\n~~~~~~~~~~ ,[ES_LUN]\n~~~~~~~~~~ ,[ES_MAR]\n~~~~~~~~~~ ,[ES_MIE]\n~~~~~~~~~~ ,[ES_JUE]\n~~~~~~~~~~ ,[ES_VIE]\n~~~~~~~~~~ ,[ES_SAB]\n~~~~~~~~~~ ,[ES_DOM]\n~~~~~~~~~~ ,[EM_TIPO]\n~~~~~~~~~~ ,[EM_F_DIA]\n~~~~~~~~~~ ,[EM_F_CADA]\n~~~~~~~~~~ ,[EM_R_ORD]\n~~~~~~~~~~ ,[EM_R_DIA]\n~~~~~~~~~~ ,[EM_R_CADA]\n~~~~~~~~~~ ,[EJE_TIPO]\n~~~~~~~~~~ ,[EJE_U_HORA]\n~~~~~~~~~~ ,[EJE_R_CADA]\n~~~~~~~~~~ ,[EJE_R_TIPO]\n~~~~~~~~~~ ,[EJE_R_HINI]\n~~~~~~~~~~ ,[EJE_R_HFIN]\n~~~~~~~~~~ ,[VIG_INI]\n~~~~~~~~~~ ,[VIG_FIN]\n~~~~~~~~~~ ,[VIG_SINFIN]\n~~~~~~~~~~ ,[GUID_FRECU]\n~~~~~~~~~~ ,[DEFECTO])\n~~~~ Select\n~~~~~~~~~~ [FILLER]\n~~~~~~~~~~ ,[COD_FRECU]\n~~~~~~~~~~ ,[DESC_FRECU]\n~~~~~~~~~~ ,[EJECUCION]\n~~~~~~~~~~ ,[ED_CADA]\n~~~~~~~~~~ ,[ES_CADA]\n~~~~~~~~~~ ,[ES_LUN]\n~~~~~~~~~~ ,[ES_MAR]\n~~~~~~~~~~ ,[ES_MIE]\n~~~~~~~~~~ ,[ES_JUE]\n~~~~~~~~~~ ,[ES_VIE]\n~~~~~~~~~~ ,[ES_SAB]\n~~~~~~~~~~ ,[ES_DOM]\n~~~~~~~~~~ ,[EM_TIPO]\n~~~~~~~~~~ ,[EM_F_DIA]\n~~~~~~~~~~ ,[EM_F_CADA]\n~~~~~~~~~~ ,[EM_R_ORD]\n~~~~~~~~~~ ,[EM_R_DIA]\n~~~~~~~~~~ ,[EM_R_CADA]\n~~~~~~~~~~ ,[EJE_TIPO]\n~~~~~~~~~~ ,[EJE_U_HORA]\n~~~~~~~~~~ ,[EJE_R_CADA]\n~~~~~~~~~~ ,[EJE_R_TIPO]\n~~~~~~~~~~ ,[EJE_R_HINI]\n~~~~~~~~~~ ,[EJE_R_HFIN]\n~~~~~~~~~~ ,[VIG_INI]\n~~~~~~~~~~ ,[VIG_FIN]\n~~~~~~~~~~ ,[VIG_SINFIN]\n~~~~~~~~~~ ,[GUID_FRECU]\n~~~~~~~~~~ ,[DEFECTO] from pta03 where cod_frecu not in (select cod_frecu from [DICCIONUEVO]..pta03)\n\nINSERT INTO [DICCIONUEVO]..[PTA02]\n~~ ([FILLER]\n~~ ,[COD_TAREA]\n~~ ,[DESC_TAREA]\n~~ ,[COD_TTARE]\n~~ ,[PAR_TAREA]\n~~ ,[ACT_TAREA]\n~~ ,[BORR_TAREA]\n~~ ,[ORD_TAREA]\n~~ ,[TIPO_PROCE]\n~~ ,[NOM_PROCE]\n~~ ,[HOST])\n\nselect [FILLER]\n~~ ,[COD_TAREA]\n~~ ,[DESC_TAREA]\n~~ ,[COD_TTARE]\n~~ ,[PAR_TAREA]\n~~ ,[ACT_TAREA]\n~~ ,[BORR_TAREA]\n~~ ,[ORD_TAREA]\n~~ ,[TIPO_PROCE]\n~~ ,[NOM_PROCE]\n~~ ,[HOST] from pta02 where cod_tarea not in (select cod_tarea from [DICCIONUEVO]..pta02)\nand COD_TTARE in (select cod_ttare from pta05 where DESC_TTARE in (\'Tablero de control\',\'Exportación automatizada\',\'Generación automatizada\',\'Importación automatizada\'))\n\nINSERT INTO [DICCIONUEVO]..[PTA04]\n~~ ([FILLER]\n~~ ,[COD_TAREA]\n~~ ,[COD_FRECU]\n~~ ,[ULT_EJECU]\n~~ ,[ULT_HEJECU])\nselect [FILLER]\n~~ ,[COD_TAREA]\n~~ ,[COD_FRECU]\n~~ ,[ULT_EJECU]\n~~ ,[ULT_HEJECU] from pta04 where cod_tarea not in (select cod_tarea from [DICCIONUEVO]..pta04)\nand cod_tarea in (select cod_tarea from pta02 where cod_ttare in (select cod_ttare from pta05 where DESC_TTARE in (\'Tablero de control\',\'Exportación automatizada\',\'Generación automatizada\',\'Importación automatizada\')))\n\nalter table [DICCIONUEVO].[DBO].HISTORICOINDICADOR\n~~ add constraint FK_HISTORICOINDICADOR_RELINDICADORHISTORICOINDICADOR_INDICADOR foreign key (GUIDINDICADOR)\n~~references INDICADOR (GUIDINDICADOR)\n\nalter table [DICCIONUEVO].[DBO].INDICADOR\n~~ add constraint FK_INDICADOR_RELATIONSHIP_17_VARIABLEINDICADOR foreign key (GUIDVALORANTERIORINDICADOR)\n~~references VARIABLEINDICADOR (GUIDVARIABLEINDICADOR)\n\nalter table [DICCIONUEVO].[DBO].INDICADOR\n~~ add constraint FK_INDICADOR_RELPANELINDICADOR_PANEL foreign key (GUIDPANEL)\n~~references PANEL (GUIDPANEL)\n\nalter table [DICCIONUEVO].[DBO].INDICADOR\n~~ add constraint FK_INDICADOR_RELTIPOINDICADORINDICADOR_TIPOINDICADOR foreign key (CODIGOTIPOINDICADOR)\n~~references TIPOINDICADOR (CODIGOTIPOINDICADOR)\n\nalter table [DICCIONUEVO].[DBO].INDICADOR\n~~ add constraint FK_INDICADOR_REL_IND_VARIND_VARIABLEINDICADOR foreign key (GUIDVALORINDICADOR)\n~~references VARIABLEINDICADOR (GUIDVARIABLEINDICADOR)\n\nalter table [DICCIONUEVO].[DBO].INDICADORPORPUBLICACION\n~~ add constraint FK_INDICADORPORPUBLICACION_INDICADORPORPUBLICACION_PUBLICACION foreign key (GUIDPUBLICACION)\n~~references PUBLICACION (GUIDPUBLICACION)\n\nalter table [DICCIONUEVO].[DBO].INDICADORPORPUBLICACION\n~~ add constraint FK_INDICADORPORPUBLICACION_INDICADORPORPUBLICACION2_INDICADOR foreign key (GUIDINDICADOR)\n~~references INDICADOR (GUIDINDICADOR)\n\nalter table [DICCIONUEVO].[DBO].PANEL\n~~ add constraint FK_PANEL_RELTABLEROPANEL_TABLERO foreign key (GUIDTABLERO)\n~~references TABLERO (GUIDTABLERO)\n\nalter table [DICCIONUEVO].[DBO].PUBLICACION\n~~ add constraint FK_PUBLICACION_RELPANELPUBLICACION_PANEL foreign key (GUIDPANEL)\n~~references PANEL (GUIDPANEL)\n\nalter table [DICCIONUEVO].[DBO].PUBLICACION\n~~ add constraint FK_PUBLICACION_RELTIPOPUBLICACIONPUBLICACION_TIPOPUBLICACION foreign key (CODIGOTIPOPUBLICACION)\n~~references TIPOPUBLICACION (CODIGOTIPOPUBLICACION)\n\nalter table [DICCIONUEVO].[DBO].PUBLICACION\n~~ add constraint FK_PUBLICACION_RELVARPUBPUBLICACION_VARIABLEPUBLICACION foreign key (GUIDVARIABLEPUBLICACION)\n~~references VARIABLEPUBLICACION (GUIDVARIABLEPUBLICACION)\n\nalter table [DICCIONUEVO].[DBO].SEGURIDADINDICADOR\n~~ add constraint FK_SEGURIDADINDICADOR_RELATIONSHIP_12_INDICADOR foreign key (GUIDINDICADOR)\n~~references INDICADOR (GUIDINDICADOR)\n\nalter table [DICCIONUEVO].[DBO].VARIABLEINDICADOR\n~~ add constraint FK_VARIABLEINDICADOR_RELATIONSHIP_15_INDICADOR foreign key (GUIDINDICADOR)\n~~references INDICADOR (GUIDINDICADOR)\n\nalter table [DICCIONUEVO].[DBO].VARIABLEPUBLICACION\n~~ add constraint FK_VARIABLEPUBLICACION_RELATIONSHIP_18_PUBLICACION foreign key (GUIDPUBLICACION)\n~~references PUBLICACION (GUIDPUBLICACION)\n\nEND\n/* FIN TABLERO DE CONTROL CON SUS INDICADORES */\n\nDECLARE @SQL AS VARCHAR (1000), @IDEMPRESA VARCHAR (100)\nDECLARE RS CURSOR LOCAL FOR\nSELECT IDEMPRESA FROM [DICCIONUEVO]..EMPRESA WHERE IDEMPRESA NOT IN (SELECT IDEMPRESA FROM [DICCIONUEVO]..CONFIGURACIONEMPRESA)\nOPEN RS\nFETCH NEXT FROM RS INTO @IDEMPRESA\nWHILE @@FETCH_STATUS = 0\nBEGIN\nSET @SQL= \'INSERT INTO [DICCIONUEVO]..[CONFIGURACIONEMPRESA] ([SIGNODECIMAL],[SEPARADORMIL],[SEPARADORFECHA],[COLORNUMERONEGATIVO]\n,[FORMATONUMERONEGATIVO],[FORMATOPORCENTAJEPOSITIVO],[FORMATOPORCENTAJENEGATIVO],[FORMATOIMPORTEPOSITIVO]\n,[FORMATOIMPORTENEGATIVO],[FORMATOFECHA],[IDEMPRESA])\nVALUES (\'\'.\'\', \'\',\'\' ,\'\'/\'\' ,0 ,0 ,1 ,1 ,0 ,0 ,\'\'@GBLFECHACORTA\'\', \'+@IDEMPRESA+\')\'\nEXEC (@SQL)\nFETCH NEXT FROM RS INTO @IDEMPRESA\nEND\nCLOSE RS\nDEALLOCATE RS\n\n--DECLARE @IDEMPRESA VARCHAR(3), @SQL VARCHAR(MAX)\nDECLARE RS CURSOR LOCAL FOR\nSELECT IDEMPRESA FROM [DICCIONUEVO]..EMPRESA\nOPEN RS\nFETCH NEXT FROM RS INTO @IDEMPRESA\nWHILE @@FETCH_STATUS= 0\nBEGIN\nSET @SQL = \'INSERT INTO [DICCIONUEVO]..VARIABLEMASCARAEMPRESA (DIGITOOBLIGATORIO, CANTDIGITOS,IDEMPRESA,IDVARIABLEMASCARA)\nSELECT OBLIGATORIOPORDEFECTO AS DIGITOOBLIGATORIO, CANTIDADPORDEFECTO AS CANTDIGITOS, \'+@IDEMPRESA+\' , IDVARIABLEMASCARA\nFROM [DICCIONUEVO]..VARIABLEMASCARA WHERE IDVARIABLEMASCARA NOT IN\n(SELECT IDVARIABLEMASCARA FROM [DICCIONUEVO]..VARIABLEMASCARAEMPRESA WHERE IDEMPRESA IN (\'+@IDEMPRESA+\'))\n\'\n--PRINT @SQL\nEXEC (@SQL)\nFETCH NEXT FROM RS INTO @IDEMPRESA\nEND\nCLOSE RS\nDEALLOCATE RS\n\nDELETE [DICCIONUEVO]..providerid\nGO\nUPDATE [DICCIONUEVO]..EMPRESA SET USUARIOBD = S.USUARIOBD , CLAVEBD = S.CLAVEBD FROM [DICCIONUEVO]..EMPRESA E JOIN [DICCIONUEVO]..SERVER S ON E.IDSERVER = S.IDSERVER\nGO\n~\n~\nComentarios', '', 1, '2026-04-02 15:40:32', '2026-04-02 15:40:32', NULL),
