(580, 1, 695, NULL, 'AXOFT - Error Perfil Facturador POS', 'Perfiles de facturador POS (PERFIL_FACTURA_POS)-(TTabla.PutRecord)-(A column insert or update conflicts with a rule imposed by a previous CREATE RULE statement. The statement was terminated. The conflict occurred in database \'NUEVA_MUNTAL_SA\', table \'dbo.PERFIL_FACTURA_POS\', column \'ID_PERFIL_FACTURA_POS\')-(Locked)-( | IX_0=000001)\n\nDe: Ignacio Martín Campo [mailto:soportecanal@axoft.com]\nEnviado el: lunes, 03 de julio de 2017 16:52\nPara:~walter.a.gimenez@gmail.com\nCC:~soporte@reaxion.com.ar\nAsunto: [#MUD-223-56807]: Perfiles de Facturación\n\nWalter, te voy a pedir que ejecutes este script que te adjunto contra la base de datos y vuelvas a probar.\nSaludos.\nIgnacio Campo\nSoporte Canal\nDpto. Clientes\nSoporteCanal@axoft.com\n+54 (011) 4816-2620\n\n- - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -\n\nDECLARE @ID INT\nSET @ID = (SELECT ISNULL(MAX(ID_PERFIL_FACTURA_POS),1) FROM PERFIL_FACTURA_POS)\nINSERT INTO PERFIL_FACTURA_POS (ID_PERFIL_FACTURA_POS, COD_PERFIL, PERMITE_CERRAR_SIN_AUTORIZACION, PERMITE_ELIMINAR_SIN_AUTORIZACION, EDITA_COTIZACION)\nselect RANK() OVER (ORDER BY COD_PERFIL) + @ID , COD_PERFIL, 1 ,1 , \'E\' from GVA51 WHERE COD_PERFIL NOT IN (SELECT COD_PERFIL FROM PERFIL_FACTURA_POS)\nGO\nDELETE PROVIDERID WHERE TABLA = \'PERFIL_FACTURA_POS\'\nGO', '', 1, '2026-04-02 15:40:33', '2026-04-02 15:40:33', NULL),
