(749, 1, 947, NULL, 'AXOFT - Script para copiar empresas - 17.01', '/*** Pegar el siguiente script en una nueva consulta y Reemplazar XXXXXXXXXXXXXXX por el nombre de la base de datos ***/\n\nuse XXXXXXXXXXXXXXX\ngo\n\n/****** Talonarios de compra ******/\nDELETE FROM CPA56\nINSERT INTO CPA56(FILLER, DESCRIPCIO, DESTINO, EDITA_NRO, N_TYP, NRO_DESDE, NRO_HASTA, PROXIMO, RENGLONES, SUCURSAL, TALONARIO, TIPO_COMP, DOC_ELECTR, MET_CON_DE, IMP_DE, T_DOC_DTE, DI_IMG_TYP,\n~~~~~~~~~~~~~~~~~~~~~~~~ IMG_PATH_PDF, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF)\nSELECT~~FILLER, DESCRIPCIO, DESTINO, EDITA_NRO, N_TYP, NRO_DESDE, NRO_HASTA, PROXIMO, RENGLONES, SUCURSAL, TALONARIO, TIPO_COMP, DOC_ELECTR, MET_CON_DE, IMP_DE, T_DOC_DTE, DI_IMG_TYP,\n~~~~~~~~~~~~~~~~~~~~~~~~ IMG_PATH_PDF, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF~~~~~~~~~~\nFROM [XXXXXXXXXXXXXXX].[dbo].[CPA56]\nGO\n\n/****** Copia Talonarios de Ventas ******/\nDELETE FROM GVA43\nINSERT INTO GVA43(FILLER, CAI, CF_COPIAS, COMPROB, CONT_FISCA, DESCRIP, DESTINO, DUPLICA, EDITA_NRO, FECHA_VTO, MODELO_CF, NRO_DESDE, NRO_HASTA, PROXIMO, RENGLONES, SUCURSAL, T_FORM, TALONARIO,\n~~~~~~~~~~~~~~~~~~~~~~~~ TIPO, EXCLUSIVO, COD_CAJA, T_MANUAL, NROAUTORIZ, LLAVE1, LLAVE2, FECH_AVISO, VAL_FECHA, DOC_ELECTR, MET_CON_DE, DI_IMG_TYP, DESTINO_DE, IMP_DE, MAIL_DE, EXPORTA, T_DOC_DTE,\n~~~~~~~~~~~~~~~~~~~~~~~~ SUCURSAL_DESTINO, USA_TGIMPRE, IMG_PATH_PDF, UTILIZA_BONO_FISCAL, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF, TIPO_TALONARIO, OBSERVACIONES, NUMERACION_PREIMPRESA,\n~~~~~~~~~~~~~~~~~~~~~~~~ IMPRESION_COMPROBANTES, CON_CBU_INFORMADO, RECIBO, USA_USB)\nSELECT~~FILLER, CAI, CF_COPIAS, COMPROB, CONT_FISCA, DESCRIP, DESTINO, DUPLICA, EDITA_NRO, FECHA_VTO, MODELO_CF, NRO_DESDE, NRO_HASTA, PROXIMO, RENGLONES, SUCURSAL, T_FORM, TALONARIO,\n~~~~~~~~~~~~~~~~~~~~~~~~ TIPO, EXCLUSIVO, COD_CAJA, T_MANUAL, NROAUTORIZ, LLAVE1, LLAVE2, FECH_AVISO, VAL_FECHA, DOC_ELECTR, MET_CON_DE, DI_IMG_TYP, DESTINO_DE, IMP_DE, MAIL_DE, EXPORTA, T_DOC_DTE,\n~~~~~~~~~~~~~~~~~~~~~~~~ SUCURSAL_DESTINO, USA_TGIMPRE, IMG_PATH_PDF, UTILIZA_BONO_FISCAL, GUARDA_COPIA_PDF, PATH_PDF, TIPO_PATH_PDF, TIPO_TALONARIO, OBSERVACIONES, NUMERACION_PREIMPRESA,\n~~~~~~~~~~~~~~~~~~~~~~~~ IMPRESION_COMPROBANTES, CON_CBU_INFORMADO, RECIBO, USA_USB~~~~~~~~~~\nFROM [XXXXXXXXXXXXXXX].[dbo].[GVA43]\nGO\n\n/****** Formatos de impresión ******/\n\nIF~~EXISTS (SELECT * FROM sys.foreign_keys WHERE object_id = OBJECT_ID(N\'[dbo].[FK_SBA02_TYPS]\') AND parent_object_id = OBJECT_ID(N\'[dbo].[SBA02]\'))\nALTER TABLE [dbo].[SBA02] DROP CONSTRAINT [FK_SBA02_TYPS]\n\nSET IDENTITY_INSERT TYPS ON\nDELETE FROM TYPS\nINSERT INTO TYPS(ID_TYPS, FILLER, MEMO_TYP, NOMBRE_TYP, ID_PROCESO, OBSERVACIONES, DESC_TYPS)\nSELECT ID_TYPS, FILLER, MEMO_TYP, NOMBRE_TYP, ID_PROCESO, OBSERVACIONES, DESC_TYPS\nFROM [XXXXXXXXXXXXXXX].[dbo].[TYPS]\nGO\nSET IDENTITY_INSERT TYPS OFF\nGo\nALTER TABLE DBO.SBA02\n~~ ADD CONSTRAINT FK_SBA02_TYPS FOREIGN KEY (ID_TYPS)\n~~~~~~REFERENCES DBO.TYPS (ID_TYPS)\nGO\n\n/****** Parámetros de Ventas ******/\nDELETE FROM GVA16\nINSERT INTO GVA16(FILLER, ACCESO_COT, ACEPTA_COT, ACTIVA_APR, AGRART_REM, ALTACLACLI, ALTACLAPOT, ALTACLIENT, ALTAPRECIO, APRUEBA_PE, APRUE_CANT, APRUE_COND, APRUE_PREC, AUTORIZ_CO, CAJON_CF,\n~~~~~~~~~~~~~~~~~~~~~~~~ CANCELA, CIERRE_FAC, CIERRE_REC, COD_CLI_AU, COD_POT_AU, COND_POTEN, CONVER_CLI, COTIZ, COTI_FECHA, CRE_FECHA, CTACTE_CF, CTR_BONIF, CTR_CONVTA, CTR_DEPO, CTR_LISTA, CTR_TRANS, CTR_VEND,\n~~~~~~~~~~~~~~~~~~~~~~~~ CUIT, DEB_FECHA, DES_CLASI1, DES_CLASI2, DES_FECHA1, DES_FECHA2, DESC_ANTIG, DIA_FECHA1, DIA_FECHA2, DIAS_VIGEN, EDI_PER_IB, EMITE_ALTA, EMI_COT_AP, F_ALIC_IVA, F_IVA_PERC, F_C_IVA_FL, F_C_IVA_IN,\n~~~~~~~~~~~~~~~~~~~~~~~~ FAC_FECHA, FAC_STK, IB_L, II_D, II_L, IMP_FACCRE, IVA_D, IVA_L, LEY_MON_CT, LEY_MON_EX, LIB, LONG_FAM_C, LON_GRUP_C, LONG_IND_C, MANT_COT, MANT_PED, MANT_D_ADI, MODO_SHOP, MOD_REC_FC,\n~~~~~~~~~~~~~~~~~~~~~~~~ NRO_FC_GEN, NINT_FCTER, NRO_REM_AU, PAGO_CF, PED_APR_CO, PED_AUT_CO, PED_FECHA, PR