(806, 1, 981, NULL, 'DEVILLE - Script Central', 'USE [CENTRALIZADORA]\nGO\n/****** Object:~~StoredProcedure [dbo].[PDP]~~~~Script Date: 04/08/2015 19:40:08 ******/\nSET ANSI_NULLS ON\nGO\nSET QUOTED_IDENTIFIER ON\nGO\n\n--Si es requerido crear cambiar ALTER por CREATE--\nALTER procedure [dbo].[PDP] as\nBEGIN\n--------------------------------------------------------------------------------------------------------------------------------------------------\n--------------------------- DE LA TABLA GVA14 - Clientes SOLO NECESITO EL CODIGO DE CLIENTE Y EL % DE DESCUENTO ------------------------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\nDECLARE @GVA_14_COD_CLIENT varchar(6)\nDECLARE @GVA_14_PORC_DESC [dbo].[DECIMAL_TG]\nDECLARE @GVA_14_RAZON_SOCIAL varchar(60)\n----------------------------------------------------------------------------------------------------------------------------------------------------\n-------------------- Declaro todas las variables que voy a pasar desde/hasta EN LA TABLA GVA21 - Encabezamientos de pedidos ------------------------\n-------------------- Este Script fue modificado por Charly y adaptado a las nuevas tablas de T15 ------------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\nDECLARE @FILLER varchar(20)\nDECLARE @APRUEBA varchar(30)\nDECLARE @CIRCUITO dbo.[ENTERO_TG]\nDECLARE @COD_CLIENT varchar(6)\nDECLARE @COD_SUCURS varchar(2)\nDECLARE @COD_TRANSP varchar(10)\nDECLARE @COD_VENDED varchar(10)\nDECLARE @COMENTARIO varchar(30)\nDECLARE @COMP_STK bit\nDECLARE @COND_VTA dbo.[ENTERO_TG]\nDECLARE @COTIZ dbo.[DECIMAL_TG]\nDECLARE @ESTADO dbo.[ENTERO_TG]\nDECLARE @EXPORTADO bit\nDECLARE @FECHA_APRU datetime\nDECLARE @FECHA_ENTR datetime\nDECLARE @FECHA_PEDI datetime\nDECLARE @HORA_APRUE varchar(4)\nDECLARE @ID_EXTERNO varchar(20)\nDECLARE @LEYENDA_1 varchar(60)\nDECLARE @LEYENDA_2 varchar(60)\nDECLARE @LEYENDA_3 varchar(60)\nDECLARE @LEYENDA_4 varchar(60)\nDECLARE @LEYENDA_5 varchar(60)\nDECLARE @MON_CTE bit\nDECLARE @N_LISTA dbo.[ENTERO_TG]\nDECLARE @N_REMITO varchar(13)\nDECLARE @NRO_O_COMP varchar(14)\nDECLARE @NRO_PEDIDO varchar(13)\nDECLARE @NRO_SUCURS dbo.[ENTERO_TG]\nDECLARE @ORIGEN varchar(1)\nDECLARE @PORC_DESC dbo.[DECIMAL_TG]\nDECLARE @REVISO_FAC varchar(1)\nDECLARE @REVISO_PRE varchar(1)\nDECLARE @REVISO_STK varchar(1)\nDECLARE @TALONARIO dbo.[ENTERO_TG]\nDECLARE @TALON_PED dbo.[ENTERO_TG]\nDECLARE @TOTAL_PEDI dbo.[DECIMAL_TG]\nDECLARE @TIPO_ASIEN varchar(2)\nDECLARE @MOTIVO varchar(3)\nDECLARE @HORA varchar(6)\nDECLARE @COD_CLASIF varchar(6)\nDECLARE @ID_ASIENTO_MODELO_GV dbo.[D_ID]\nDECLARE @TAL_PE_ORI dbo.[ENTERO_TG]\nDECLARE @NRO_PE_ORI varchar(13)\nDECLARE @FECHA_INGRESO [datetime]\nDECLARE @HORA_INGRESO [varchar](6)\nDECLARE @USUARIO_INGRESO [varchar](120)\nDECLARE @TERMINAL_INGRESO [varchar](255)\nDECLARE @FECHA_ULTIMA_MODIFICACION [datetime]\nDECLARE @HORA_ULTIMA_MODIFICACION [varchar](6)~~\nDECLARE @USUA_ULTIMA_MODIFICACION [varchar](120)\nDECLARE @TERM_ULTIMA_MODIFICACION [varchar](255)\nDECLARE @ID_DIRECCION_ENTREGA dbo.[D_ID]\nDECLARE @ES_PEDIDO_WEB bit\n--Nuevo T15\nDECLARE @WEB_ORDER_ID int\nDECLARE @FECHA_O_COMP [datetime]\nDECLARE @ACTIVIDAD_COMPROBANTE_AFIP [varchar](1)\nDECLARE @ID_ACTIVIDAD_EMPRESA_AFIP dbo.[D_ID]\nDECLARE @TIPO_DOCUMENTO_PAGADOR dbo.[ENTERO_TG]\nDECLARE @NUMERO_DOCUMENTO_PAGADOR [varchar](20)\n--Optimización fecha--\nDECLARE @OPT_FECHA_FAC_FIN [datetime]\nDECLARE @OPT_FECHA_PEDI_INI [datetime]\n--Valor para verificar--\nDECLARE @NRO_PED_HIS varchar(13)\nDECLARE @ESTADOB dbo.[ENTERO_TG]\n----------------------------------------------------------------------------------------------------------------------------------------------------\n-------------------- Declaro todas las variables que voy a pasar desde/hasta EN LA TABLA GVA03 - Renglones de pedidos ------------------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\nDECLARE @GVA_03_FILLER varchar(20)\nDECLARE @GVA_03_CAN_EQUI_V dbo.[DECIMAL_TG]\nDECLARE @GVA_03_CANT_A_DES dbo.[DECIMAL_TG]\nDECLARE @GVA_03_CANT_A_FAC dbo.[DECIMAL_TG]\nDECLARE @GVA_03_CANT_PEDID dbo.[DECIMAL_TG]\nDECLARE @GVA_03_CANT_PEN_D dbo.[DECIMAL_TG]\nDECLARE @GVA_03_CANT_PEN_F dbo.[DECIMAL_TG]\nDECLARE @GVA_03_COD_ARTICU varchar(15)\nDECLARE @GVA_03_DESCUENTO dbo.[DECIMAL_TG]\nDECLARE @GVA_03_N_RENGLON dbo.[T_D_RENGLON]\nDECLARE @GVA_03_NRO_PEDIDO varchar(13)\nDECLARE @GVA_03_PEN_REM_FC dbo.[DECIMAL_TG]\nDECLARE @GVA_03_PEN_FAC_RE dbo.[DECIMAL_TG]\nDECLARE @GVA_03_PRECIO dbo.[DECIMAL_TG]\nDECLARE @GVA_03_TALON_PED dbo.[ENTERO_TG]\nDECLARE @GVA_03_COD_CLASIF varchar(6)\nDECLARE @GVA_03_CANT_A_DES_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_CANT_A_FAC_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_CANT_PEDID_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_CANT_PEN_D_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_CANT_PEN_F_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_PEN_REM_FC_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_PEN_FAC_RE_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_ID_MEDIDA_VENTAS [dbo].[D_ID]\nDECLARE @GVA_03_ID_MEDIDA_STOCK_2 [dbo].[D_ID]\nDECLARE @GVA_03_ID_MEDIDA_STOCK [dbo].[D_ID]\nDECLARE @GVA_03_UNIDAD_MEDIDA_SELECCIONADA [char](1)\n--Nuevo T15\nDECLARE @GVA_03_COD_ARTICU_KIT varchar(15)\nDECLARE @GVA_03_RENGL_PADR [dbo].[T_D_RENGLON]\nDECLARE @GVA_03_PROMOCION bit\nDECLARE @GVA_03_PRECIO_ADICIONAL_KIT [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_KIT_COMPLETO bit\nDECLARE @GVA_03_INSUMO_KIT_SEPARADO bit\n--Controlar\nDECLARE @GVA03_ACTUAL dbo.[T_D_RENGLON]\nDECLARE @GVA_03_NUM_RENGLON dbo.[T_D_RENGLON]\n--Revisar\nDECLARE @GVA_03_CANTIDAD_ENTREGADA [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_CANTIDAD_ENTREGADA_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_CANTIDAD_FACTURADA [dbo].[DECIMAL_TG]\nDECLARE @GVA_03_CANTIDAD_FACTURADA_2 [dbo].[DECIMAL_TG]\n\n----------------------------------------------------------------------------------------------------------------------------------------------------\n-------------------- Declaro todas las variables que voy a leer de la tabla GVA55 - Relación pedidos / facturas y remitos---------------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\nDECLARE @GVA_55_FILLER varchar(20)\nDECLARE @GVA_55_COD_CLIENT varchar(6)\nDECLARE @GVA_55_FECHA_PEDI datetime\nDECLARE @GVA_55_N_COMP varchar(13)\nDECLARE @GVA_55_NRO_PEDIDO varchar(13)\nDECLARE @GVA_55_T_COMP varchar(3)\nDECLARE @GVA_55_TALON_PED [dbo].[ENTERO_TG]\n----------------------------------------------------------------------------------------------------------------------------------------------------\n-------------------- Declaro todas las variables que voy a leer de la tabla GVA106 - Relación renglón pedido / renglón remito ----------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\nDECLARE @GVA_106_ID_GVA106 int\nDECLARE @GVA_106_FILLER varchar(20)\nDECLARE @GVA_106_CANT_REM [dbo].[DECIMAL_TG]\nDECLARE @GVA_106_FECHA_PED datetime\nDECLARE @GVA_106_FECHA_REM datetime\nDECLARE @GVA_106_NCOMP_IN_S varchar(8)\nDECLARE @GVA_106_N_RENG_PED [dbo].[T_D_RENGLON]\nDECLARE @GVA_106_N_RENGL_S [dbo].[T_D_RENGLON]\nDECLARE @GVA_106_NRO_PEDIDO varchar(13)\nDECLARE @GVA_106_TALON_PED [dbo].[ENTERO_TG]\nDECLARE @GVA_106_TCOMP_IN_S varchar(2)\nDECLARE @GVA_106_CANT_REM_2 [dbo].[DECIMAL_TG]\nDECLARE @GVA_106_CANTIDAD_PEDIDO [dbo].[DECIMAL_TG]\nDECLARE @GVA_106_CANTIDAD_PEDIDO_2 [dbo].[DECIMAL_TG]\n----------------------------------------------------------------------------------------------------------------------------------------------------\n------------------ Declaro y seteo todas las variables que voy a ocupar para hacer el ingreso a la tabla de control -------------------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\nDECLARE @NRO_FACTURA_ORIGEN varchar(13)~~~~~~~~ DECLARE @NRO_PEDIDO_ORIGINAL varchar(13)~~~~~~~~~~~~~~~~DECLARE @version int\nDECLARE @NRO_PEDIDO_EMPREB~~varchar(13)~~~~~~~~ DECLARE @NRO_PEDIDO_DEVILLE varchar(13) declare @controlBucles int\nDECLARE @NRO_PEDIDO_ELLIVED2011~~varchar(13)\n----------------------------------------------------------------------------------------------------------------------------------------------------\n-------------------- Declaro y seteo todas las variables que voy a ocupar para hacer las interacciones entre empresas ------------------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\n-- SECCION DE ARMADORES -- declaracion de talonarios --Declaraciones de sucursales\nDECLARE @SUCURSAL_PED varchar(20) DECLARE @TALON_EMPREB dbo.[ENTERO_TG] DECLARE @SUC_EMPREB varchar(6)\nDECLARE @NUMERO_PED nvarchar(20) DECLARE @TALON_DEVILLESH dbo.[ENTERO_TG] DECLARE @SUC_DEVILLESH varchar(6)\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~DECLARE @TALON_ELLIVED2011 dbo.[ENTERO_TG] ~~~~~~~~ DECLARE @SUC_ELLIVED2011 varchar(6)\nSET @TALON_ELLIVED2011 = 111 SET @SUC_ELLIVED2011 = \' 0000\'\nDECLARE @CUANTO_PEDIDO FLOAT SET @TALON_EMPREB = 111 SET @SUC_EMPREB = \' 0000\'\nDECLARE @PORCEN_CLIENTE FLOAT SET @TALON_DEVILLESH = 111 SET @SUC_DEVILLESH = \' 0000\'\nDECLARE @TOTALDELPEDIDO dbo.[DECIMAL_TG] DECLARE @ControlNumeracionPedidos BIGINT declare @controlPedidos nvarchar(2)\n----------------------------------------------------------------------------------------------------------------------------------------------------\n-------------------- Inicio While principal donde busco el pedido asociado al remito que va a original el movimiento~~------------------------------\n----------------------------------------------------------------------------------------------------------------------------------------------------\n--OPTMIZACIÓN para que no busque y compare de más en la tabla GVA55 SE TRAE el valor de FECHA pedi para agregar al BETWEEN--\nSET @OPT_FECHA_FAC_FIN = (select~~ [CENTRALIZADORA].[dbo].[GVA43].[OBSERVACIONES] from [CENTRALIZADORA].[dbo].[GVA43] WHERE [CENTRALIZADORA].[dbo].[GVA43].[TALONARIO] = 1)\nSET @OPT_FECHA_PEDI_INI = (select~~ [CENTRALIZADORA].[dbo].[GVA43].[OBSERVACIONES] from [CENTRALIZADORA].[dbo].[GVA43] WHERE [CENTRALIZADORA].[dbo].[GVA43].[TALONARIO] = 111)\nSET @NRO_PED_HIS = (select top 1 [CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO]~~from [CENTRALIZADORA].[dbo].[GVA55]~~WHERE FECHA_PEDI BETWEEN @OPT_FECHA_PEDI_INI AND @OPT_FECHA_FAC_FIN AND([CENTRALIZADORA].[dbo].[GVA55].[TALON_PED] = 111)AND [CENTRALIZADORA].[dbo].[GVA55].[N_COMP] NOT IN(SELECT [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] FROM [CENTRALIZADORA].[dbo].[Reax_control_Pedidos]))\nset @controlBucles = (SELECT~~COUNT([CENTRALIZADORA].[dbo].[GVA55].[N_COMP]) FROM [CENTRALIZADORA].[dbo].[GVA55] LEFT OUTER JOIN [CENTRALIZADORA].[dbo].[Reax_control_Pedidos] ON [CENTRALIZADORA].[dbo].[GVA55].[N_COMP] = [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] where ([CENTRALIZADORA].[dbo].[GVA55].[N_COMP] NOT IN~~(select [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] from [CENTRALIZADORA].[dbo].[Reax_control_Pedidos] where [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_PEDIDO_ORIGINAL] = @NRO_PED_HIS)) AND ([CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[DBO].[GVA55].[TALON_PED] = 111 ))\nWHILE~~(@controlBucles <> 0)\nBEGIN\n~~~~--------------------------------------BUSCO EL NUMERO ACTUAL DE SUCURSAL DEL PEDIDO--------------------------------------------\n~~~~SET @SUCURSAL_PED = (SELECT RIGHT((SELECT REVERSE((select top 1 [CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO]~~from [CENTRALIZADORA].[dbo].[GVA55]~~WHERE FECHA_PEDI BETWEEN @OPT_FECHA_PEDI_INI AND @OPT_FECHA_FAC_FIN AND ([CENTRALIZADORA].[dbo].[GVA55].[TALON_PED] = 111)AND [CENTRALIZADORA].[dbo].[GVA55].[N_COMP] NOT IN(SELECT [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] FROM [CENTRALIZADORA].[dbo].[Reax_control_Pedidos])) )),5))\n\n--------------------------------------BUSCO EL NUMERO ACTUAL DE PEDIDO DEL PEDIDO----------------------------------------------\n~~\n~~~~SET @NUMERO_PED = (SELECT RIGHT((select top 1 [CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO]~~from [CENTRALIZADORA].[dbo].[GVA55]~~WHERE FECHA_PEDI BETWEEN @OPT_FECHA_PEDI_INI AND @OPT_FECHA_FAC_FIN AND ([CENTRALIZADORA].[dbo].[GVA55].[TALON_PED] = 111)AND [CENTRALIZADORA].[dbo].[GVA55].[N_COMP] NOT IN(SELECT [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] FROM [CENTRALIZADORA].[dbo].[Reax_control_Pedidos])) ,6))\n~~~~--------------------------------------BUSCO EL PORCENTAJE DE DESCUENTO DEL CLIENTE---------------------------------------------\nSET @GVA_14_PORC_DESC = (SELECT [CENTRALIZADORA].[DBO].[GVA14].[PORC_DESC] FROM [CENTRALIZADORA].[DBO].[GVA14] where [CENTRALIZADORA].[DBO].[GVA14].[cod_client] = any (SELECT [CENTRALIZADORA].[DBO].[GVA55].[COD_CLIENT] FROM [CENTRALIZADORA].[DBO].[GVA55] WHERE [CENTRALIZADORA].[DBO].[GVA55].[NRO_PEDIDO] = @NRO_PED_HIS AND[CENTRALIZADORA].[DBO].[GVA55].[TALON_PED] = 111~~))\n~~~~SET @GVA_14_RAZON_SOCIAL =~~(SELECT [CENTRALIZADORA].[DBO].[GVA14].[RAZON_SOCI] FROM [CENTRALIZADORA].[DBO].[GVA14] where [CENTRALIZADORA].[DBO].[GVA14].[cod_client] = any (SELECT [CENTRALIZADORA].[DBO].[GVA55].[COD_CLIENT] FROM [CENTRALIZADORA].[DBO].[GVA55] WHERE [CENTRALIZADORA].[DBO].[GVA55].[NRO_PEDIDO] = @NRO_PED_HIS AND[CENTRALIZADORA].[DBO].[GVA55].[TALON_PED] = 111~~))\n\n~~~~\n~~~~-------------------------------------------------------------------------------------------------------------------------------\n~~~~--------------REALIZO UNA COPIA DE TODOS LOS VALORES ACTUALES DEL PEDIDO DE LA EMPRESA CENTRALIZADORA--------------------------\n~~~~---------------------------DE LA TABLA TABLA GVA21 - Encabezamientos de pedidos------------------------------------------------\n\n~~~~SET @NRO_PED_HIS = (select top 1 [CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO]~~from [CENTRALIZADORA].[dbo].[GVA55]~~WHERE FECHA_PEDI BETWEEN @OPT_FECHA_PEDI_INI AND @OPT_FECHA_FAC_FIN AND ([CENTRALIZADORA].[dbo].[GVA55].[TALON_PED] = 111)AND [CENTRALIZADORA].[dbo].[GVA55].[N_COMP] NOT IN(SELECT [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] FROM [CENTRALIZADORA].[dbo].[Reax_control_Pedidos]))\nSET @NRO_PEDIDO_ORIGINAL~~~~= @NRO_PED_HIS\nSET @NRO_FACTURA_ORIGEN~~~~ = (SELECT~~ [CENTRALIZADORA].[dbo].[GVA55].[N_COMP] FROM [CENTRALIZADORA].[dbo].[GVA55] LEFT OUTER JOIN [CENTRALIZADORA].[dbo].[Reax_control_Pedidos] ON [CENTRALIZADORA].[dbo].[GVA55].[N_COMP] = [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] where ([CENTRALIZADORA].[dbo].[GVA55].[N_COMP] NOT IN (select [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_FACTURA_ORIGEN] from [CENTRALIZADORA].[dbo].[Reax_control_Pedidos] where [CENTRALIZADORA].[dbo].[Reax_control_Pedidos].[NRO_PEDIDO_ORIGINAL] = @NRO_PED_HIS)) AND ([CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[DBO].[GVA55].[TALON_PED] = 111 ))\nSET @FILLER = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[FILLER] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @APRUEBA = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[APRUEBA] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @CIRCUITO = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[CIRCUITO] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COD_CLIENT = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COD_CLIENT] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COD_SUCURS = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COD_SUCURS] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COD_TRANSP = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COD_TRANSP] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COD_VENDED = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COD_VENDED] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COMENTARIO = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COMENTARIO] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COMP_STK = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COMP_STK] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COND_VTA = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COND_VTA] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @COTIZ = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[COTIZ] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nIF (@GVA_14_PORC_DESC = 99)\n~~~~~~~~BEGIN\n~~~~~~~~~~~~ SET @ESTADOB = (SELECT 5)\n~~~~~~~~END ELSE\n~~~~~~~~BEGIN\n~~~~~~~~~~~~ SET @ESTADOB = (SELECT 2)\n~~~~~~~~END\nSET @ESTADO = (select 2)\nSET @EXPORTADO = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[EXPORTADO] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @FECHA_APRU = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[FECHA_APRU] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @FECHA_ENTR = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[FECHA_ENTR] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @FECHA_PEDI = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[FECHA_PEDI] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @HORA_APRUE = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[HORA_APRUE] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @ID_EXTERNO = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[ID_EXTERNO] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @LEYENDA_1 = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[LEYENDA_1] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @LEYENDA_2 = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[LEYENDA_2] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @LEYENDA_3 = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[LEYENDA_3] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @LEYENDA_4 = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[LEYENDA_4] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @LEYENDA_5 = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[LEYENDA_5] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @MON_CTE = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[MON_CTE] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @N_LISTA = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[N_LISTA] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @N_REMITO = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[N_REMITO] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @NRO_O_COMP = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[NRO_O_COMP] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @NRO_PEDIDO = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @NRO_SUCURS = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[NRO_SUCURS] from [CENTRA