from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @TERMINAL_INGRESO = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[TERMINAL_INGRESO] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @FECHA_ULTIMA_MODIFICACION = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[FECHA_ULTIMA_MODIFICACION] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @HORA_ULTIMA_MODIFICACION = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[HORA_ULTIMA_MODIFICACION] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @USUA_ULTIMA_MODIFICACION = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[USUA_ULTIMA_MODIFICACION] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @TERM_ULTIMA_MODIFICACION = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[TERM_ULTIMA_MODIFICACION] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @ES_PEDIDO_WEB = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[ES_PEDIDO_WEB] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\n--Nuevas T15\nSET @WEB_ORDER_ID = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[WEB_ORDER_ID] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @FECHA_O_COMP = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[FECHA_O_COMP] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @ACTIVIDAD_COMPROBANTE_AFIP = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[ACTIVIDAD_COMPROBANTE_AFIP] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @ID_ACTIVIDAD_EMPRESA_AFIP = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[ID_ACTIVIDAD_EMPRESA_AFIP] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @TIPO_DOCUMENTO_PAGADOR = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[TIPO_DOCUMENTO_PAGADOR] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\nSET @NUMERO_DOCUMENTO_PAGADOR = (select~~ [CENTRALIZADORA].[dbo].[GVA21].[NUMERO_DOCUMENTO_PAGADOR] from [CENTRALIZADORA].[dbo].[GVA21] WHERE (([CENTRALIZADORA].[dbo].[GVA21].[NRO_PEDIDO] = @NRO_PED_HIS) AND ([CENTRALIZADORA].[dbo].[GVA21].[TALON_PED] = 111)))\n------------------------------------------------------------------------------------------------------------------\n---------- control de numeracion para tabla de auditoria, valido para todas las empresas relacionadas~~-----------\n------------------------------------------------------------------------------------------------------------------\n\nset @ControlNumeracionPedidos = (select count([CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO]) from [CENTRALIZADORA].[dbo].[GVA55] WHERE ([CENTRALIZADORA].[dbo].[GVA55].[NRO_PEDIDO] = @NRO_PED_HIS)AND (TALON_PED = 111))\nIF (@ControlNumeracionPedidos < 10)\nBEGIN\nIF (@ControlNumeracionPedidos = 0)\nBEGIN\nset @controlPedidos = \'00\'\nEND\nIF (@ControlNumeracionPedidos = 1)\nBEGIN\nset @controlPedidos = \'01\'\nEND\nIF (@ControlNumeracionPedidos = 2)\nBEGIN\n~~set @controlPedidos = \'02\'\nEND\nIF (@ControlNumeracionPedidos = 3)\nBEGIN\n~~set @controlPedidos = \'03\'\nEND\nIF (@ControlNumeracionPedidos = 4)\nBEGIN\n~~set @controlPedidos = \'04\'\nEND\nIF (@ControlNumeracionPedidos = 5)\nBEGIN\n~~set @controlPedidos = \'05\'\nEND\nIF (@ControlNumeracionPedidos = 6)\nBEGIN\n~~set @controlPedidos = \'06\'\nEND\nIF (@ControlNumeracionPedidos = 7)\nBEGIN\n~~set @controlPedidos = \'07\'\nEND\nIF (@ControlNumeracionPedidos = 8)\nBEGIN\n~~set @controlPedidos = \'08\'\nEND\nIF (@ControlNumeracionPedidos = 9)\nBEGIN\n~~set @controlPedidos = \'09\'\nEND\nEND\nELSE~~\nBEGIN\nSET @controlPedidos = (select CAST(@ControlNumeracionPedidos as NVARCHAR(2)))\nEND\nset @version = @controlPedidos\n\n------------------------------------------------------------------------------------------------------------------\n------ insercion del pedido en el talonario 111 y sucursal 0000 EMPRESA EMPREB en Encabezamientos de pedidos -----\n------------------------------ EN LA TABLA GVA21 - Encabezamientos de pedidos-------------------------------------\n\nSET @ESTADOB =\nCASE\nWHEN (@GVA_14_PORC_DESC = 99) THEN (SELECT 5)~~ -- 99% -> 100% para DEVILLE SH - Anulado en EmpreB\nWHEN (@GVA_14_PORC_DESC = 75) THEN (SELECT 5) -- 75% -> 100% ELLIVED 2011 - Anulado en EmpreB\nWHEN (@GVA_14_PORC_DESC = 50) THEN (SELECT 2)~~~~~~~~~~~~~~~~~~~~~~~~~~ -- 50% - Mitad para DEVILLE SH y Mitad para EMPRE_B\nWHEN (@GVA_14_PORC_DESC = 25) THEN (SELECT 2)~~~~~~~~~~~~~~~~~~~~~~~~~~ -- 25% - Mitad para ELLIVED 2011 y Mitad para EMPRE_B\nWHEN (@GVA_14_PORC_DESC = 0)~~THEN (SELECT 2)~~~~~~~~~~~~~~~~~~~~~~ -- 0% -> 100% Para EMPRE_B\nELSE (SELECT 2)\nEND\nSET @NRO_PEDIDO = @SUC_EMPREB+@NUMERO_PED+@controlPedidos\nSET @TALON_PED = @TALON_EMPREB\nSET @TOTAL_PEDI = 0\nINSERT INTO [EmpreB].[dbo].[GVA21] (\n[EmpreB].[dbo].[GVA21].[FILLER]~~~~, [EmpreB].[dbo].[GVA21].[APRUEBA] ,[EmpreB].[dbo].[GVA21].[CIRCUITO]~~, [EmpreB].[dbo].[GVA21].[COD_CLIENT],\n[EmpreB].[dbo].[GVA21].[COD_SUCURS], [EmpreB].[dbo].[GVA21].[COD_TRANSP] ,[EmpreB].[dbo].[GVA21].[COD_VENDED], [EmpreB].[dbo].[GVA21].[COMENTARIO],\n[EmpreB].[dbo].[GVA21].[COMP_STK]~~, [EmpreB].[dbo].[GVA21].[COND_VTA] ,[EmpreB].[dbo].[GVA21].[COTIZ]~~~~ , [EmpreB].[dbo].[GVA21].[ESTADO]~~~~,\n[EmpreB].[dbo].[GVA21].[EXPORTADO] , [EmpreB].[dbo].[GVA21].[FECHA_APRU] ,[EmpreB].[dbo].[GVA21].[FECHA_ENTR], [EmpreB].[dbo].[GVA21].[FECHA_PEDI],\n[EmpreB].[dbo].[GVA21].[HORA_APRUE], [EmpreB].[dbo].[GVA21].[ID_EXTERNO] ,[EmpreB].[dbo].[GVA21].[LEYENDA_1] , [EmpreB].[dbo].[GVA21].[LEYENDA_2] ,\n[EmpreB].[dbo].[GVA21].[LEYENDA_3] , [EmpreB].[dbo].[GVA21].[LEYENDA_4] ,[EmpreB].[dbo].[GVA21].[LEYENDA_5] , [EmpreB].[dbo].[GVA21].[MON_CTE]~~ ,\n[EmpreB].[dbo].[GVA21].[N_LISTA]~~ , [EmpreB].[dbo].[GVA21].[N_REMITO] ,[EmpreB].[dbo].[GVA21].[NRO_O_COMP], [EmpreB].[dbo].[GVA21].[NRO_PEDIDO],\n[EmpreB].[dbo].[GVA21].[NRO_SUCURS], [EmpreB].[dbo].[GVA21].[ORIGEN] ,[EmpreB].[dbo].[GVA21].[PORC_DESC] , [EmpreB].[dbo].[GVA21].[REVISO_FAC],\n[EmpreB].[dbo].[GVA21].[REVISO_PRE], [EmpreB].[dbo].[GVA21].[REVISO_STK] ,[EmpreB].[dbo].[GVA21].[TALONARIO] , [EmpreB].[dbo].[GVA21].[TALON_PED] ,\n[EmpreB].[dbo].[GVA21].[TOTAL_PEDI], [EmpreB].[dbo].[GVA21].[TIPO_ASIEN]~~~~~~~~~~,[EmpreB].[dbo].[GVA21].[MOTIVO]~~~~, [EmpreB].[dbo].[GVA21].[HORA]~~~~~~,\n[EmpreB].[dbo].[GVA21].[COD_CLASIF], [EmpreB].[dbo].[GVA21].[ID_ASIENTO_MODELO_GV],[EmpreB].[dbo].[GVA21].[TAL_PE_ORI], [EmpreB].[dbo].[GVA21].[NRO_PE_ORI],\n--Nuevo T14 --\n[EmpreB].[dbo].[GVA21].[FECHA_INGRESO],\n[EmpreB].[dbo].[GVA21].[HORA_INGRESO],~~\n[EmpreB].[dbo].[GVA21].[USUARIO_INGRESO],\n[EmpreB].[dbo].[GVA21].[TERMINAL_INGRESO],\n[EmpreB].[dbo].[GVA21].[FECHA_ULTIMA_MODIFICACION],\n[EmpreB].[dbo].[GVA21].[HORA_ULTIMA_MODIFICACION],\n[EmpreB].[dbo].[GVA21].[USUA_ULTIMA_MODIFICACION],\n[EmpreB].[dbo].[GVA21].[TERM_ULTIMA_MODIFICACION],\n[EmpreB].[dbo].[GVA21].[ID_DIRECCION_ENTREGA],\n[EmpreB].[dbo].[GVA21].[ES_PEDIDO_WEB],\n-