ad para DEVILLE SH y Mitad para EMPRE_B\nWHEN (@GVA_14_PORC_DESC = 25) THEN (SELECT 2)~~~~~~~~~~~~~~~~~~~~~~~~~~ -- 25% - Mitad para ELLIVED 2011 y Mitad para EMPRE_B\nWHEN (@GVA_14_PORC_DESC = 0)~~THEN (SELECT 5)~~~~~~~~~~~~~~~~~~~~~~ -- 0% -> 100% Para EMPRE_B\nELSE (SELECT 2)\nEND\n\nSET @NRO_PEDIDO = @SUC_ELLIVED2011+@NUMERO_PED+@controlPedidos\nSET @NRO_PEDIDO_ELLIVED2011 = @NRO_PEDIDO\nSET @TALON_PED = @TALON_ELLIVED2011\nSET @TOTAL_PEDI = 0\nINSERT INTO [Ellived_2011].[dbo].[GVA21] (\n[Ellived_2011].[dbo].[GVA21].[FILLER]~~~~, [Ellived_2011].[dbo].[GVA21].[APRUEBA] ,[Ellived_2011].[dbo].[GVA21].[CIRCUITO]~~, [Ellived_2011].[dbo].[GVA21].[COD_CLIENT],\n[Ellived_2011].[dbo].[GVA21].[COD_SUCURS], [Ellived_2011].[dbo].[GVA21].[COD_TRANSP] ,[Ellived_2011].[dbo].[GVA21].[COD_VENDED], [Ellived_2011].[dbo].[GVA21].[COMENTARIO],\n[Ellived_2011].[dbo].[GVA21].[COMP_STK]~~, [Ellived_2011].[dbo].[GVA21].[COND_VTA] ,[Ellived_2011].[dbo].[GVA21].[COTIZ]~~~~ , [Ellived_2011].[dbo].[GVA21].[ESTADO]~~~~,\n[Ellived_2011].[dbo].[GVA21].[EXPORTADO] , [Ellived_2011].[dbo].[GVA21].[FECHA_APRU] ,[Ellived_2011].[dbo].[GVA21].[FECHA_ENTR], [Ellived_2011].[dbo].[GVA21].[FECHA_PEDI],\n[Ellived_2011].[dbo].[GVA21].[HORA_APRUE], [Ellived_2011].[dbo].[GVA21].[ID_EXTERNO] ,[Ellived_2011].[dbo].[GVA21].[LEYENDA_1] , [Ellived_2011].[dbo].[GVA21].[LEYENDA_2] ,\n[Ellived_2011].[dbo].[GVA21].[LEYENDA_3] , [Ellived_2011].[dbo].[GVA21].[LEYENDA_4] ,[Ellived_2011].[dbo].[GVA21].[LEYENDA_5] , [Ellived_2011].[dbo].[GVA21].[MON_CTE]~~ ,\n[Ellived_2011].[dbo].[GVA21].[N_LISTA]~~ , [Ellived_2011].[dbo].[GVA21].[N_REMITO] ,[Ellived_2011].[dbo].[GVA21].[NRO_O_COMP], [Ellived_2011].[dbo].[GVA21].[NRO_PEDIDO],\n[Ellived_2011].[dbo].[GVA21].[NRO_SUCURS], [Ellived_2011].[dbo].[GVA21].[ORIGEN] ,[Ellived_2011].[dbo].[GVA21].[PORC_DESC] , [Ellived_2011].[dbo].[GVA21].[REVISO_FAC],\n[Ellived_2011].[dbo].[GVA21].[REVISO_PRE], [Ellived_2011].[dbo].[GVA21].[REVISO_STK] ,[Ellived_2011].[dbo].[GVA21].[TALONARIO] , [Ellived_2011].[dbo].[GVA21].[TALON_PED] ,\n[Ellived_2011].[dbo].[GVA21].[TOTAL_PEDI], [Ellived_2011].[dbo].[GVA21].[TIPO_ASIEN]~~~~~~~~~~,[Ellived_2011].[dbo].[GVA21].[MOTIVO]~~~~, [Ellived_2011].[dbo].[GVA21].[HORA]~~~~~~,\n[Ellived_2011].[dbo].[GVA21].[COD_CLASIF], [Ellived_2011].[dbo].[GVA21].[ID_ASIENTO_MODELO_GV],[Ellived_2011].[dbo].[GVA21].[TAL_PE_ORI], [Ellived_2011].[dbo].[GVA21].[NRO_PE_ORI],\n--Nuevo T14 --\n[Ellived_2011].[dbo].[GVA21].[FECHA_INGRESO],\n[Ellived_2011].[dbo].[GVA21].[HORA_INGRESO],~~\n[Ellived_2011].[dbo].[GVA21].[USUARIO_INGRESO],\n[Ellived_2011].[dbo].[GVA21].[TERMINAL_INGRESO],\n[Ellived_2011].[dbo].[GVA21].[FECHA_ULTIMA_MODIFICACION],\n[Ellived_2011].[dbo].[GVA21].[HORA_ULTIMA_MODIFICACION],\n[Ellived_2011].[dbo].[GVA21].[USUA_ULTIMA_MODIFICACION],\n[Ellived_2011].[dbo].[GVA21].[TERM_ULTIMA_MODIFICACION],\n[Ellived_2011].[dbo].[GVA21].[ID_DIRECCION_ENTREGA],\n[Ellived_2011].[dbo].[GVA21].[ES_PEDIDO_WEB],\n--Nuevo T15--\n[Ellived_2011].[dbo].[GVA21].[WEB_ORDER_ID],\n[Ellived_2011].[dbo].[GVA21].[FECHA_O_COMP],\n[Ellived_2011].[dbo].[GVA21].[ACTIVIDAD_COMPROBANTE_AFIP],\n[Ellived_2011].[dbo].[GVA21].[ID_ACTIVIDAD_EMPRESA_AFIP],\n[Ellived_2011].[dbo].[GVA21].[TIPO_DOCUMENTO_PAGADOR],\n[Ellived_2011].[dbo].[GVA21].[NUMERO_DOCUMENTO_PAGADOR])\nVALUES (@FILLER, @APRUEBA, @CIRCUITO, @COD_CLIENT, @COD_SUCURS, @COD_TRANSP, @COD_VENDED, @COMENTARIO, @COMP_STK, @COND_VTA, @COTIZ,\n@ESTADOB, @EXPORTADO, @FECHA_APRU, @FECHA_ENTR, @FECHA_PEDI, @HORA_APRUE, @ID_EXTERNO, @LEYENDA_1, @LEYENDA_2, @LEYENDA_3,\n@LEYENDA_4, @LEYENDA_5, @MON_CTE, @N_LISTA, @N_REMITO, @NRO_O_COMP, @NRO_PEDIDO, @NRO_SUCURS, @ORIGEN, @PORC_DESC, @REVISO_FAC,\n@REVISO_PRE, @REVISO_STK, @TALONARIO, @TALON_PED, @TOTAL_PEDI, @TIPO_ASIEN, @MOTIVO, @HORA, @COD_CLASIF, @ID_ASIENTO_MODELO_GV,\n@TAL_PE_ORI, @NRO_PE_ORI,\n--T14 agregado--\n@FECHA_INGRESO,\n@HORA_INGRESO,\n@USUARIO_INGRESO,\n@TERMINAL_INGRESO,\n@FECHA_ULTIMA_MODIFICACION,\n@HORA_ULTIMA_MODIFICACION,\n@USUA_ULTIMA_MODIFICACION,\n@TERM_ULTIMA_MODIFICACION,\n@ID_DIRECCION_ENTREGA,\n@ES_PEDIDO_WEB,\n--T15 agregado--\n~~~~~~~~@WEB_ORDER_ID,\n~~~~~~~~@FECHA_O_COMP,\n~~~~~~~~@ACTIVIDAD_COMPROBANTE_AFIP,\n~~~~~~~~@ID_ACTIVIDAD_EMPRESA_AFIP,\n~~~~~~~~@TIPO_DOCUMENTO_PAGADOR,\n~~~~~~~~@NUMERO_DOCUMENTO_PAGADOR)\n\n------------------------------------------------------------------------------------------------------------------\n---- insercion del pedido en el talonario 111 y sucursal 0000 EMPRESA DEVILLESH en Encabezamientos de pedidos-----\n------------------------------ EN LA TABLA GVA21 - Encabezamientos de pedidos-------------------------------------\nSET @ESTADOB =\nCASE\nWHEN (@GVA_14_PORC_DESC = 99) THEN (SELECT 2)~~ -- 99% -> 100% para DEVILLE SH\nWHEN (@GVA_14_PORC_DESC = 75) THEN (SELECT 5) -- 75% -> 100% ELLIVED 2011\nWHEN (@GVA_14_PORC_DESC = 50) THEN (SELECT 2)~~~~~~~~~~~~~~~~~~~~~~~~~~ -- 50% - Mitad para DEVILLE SH y Mitad para EMPRE_B\nWHEN (@GVA_14_PORC_DESC = 25) THEN (SELECT 5)~~~~~~~~~~~~~~~~~~~~~~~~~~ -- 25% - Mitad para ELLIVED 2011 y Mitad para EMPRE_B\nWHEN (@GVA_14_PORC_DESC = 0)~~THEN (SELECT 5)~~~~~~~~~~~~~~~~~~~~~~ -- 0% -> 100% Para EMPRE_B\nELSE (SELECT 2)\nEND\nSET @NRO_PEDIDO = @SUC_DEVILLESH+@NUMERO_PED+@controlPedidos\nSET @NRO_PEDIDO_DEVILLE = @NRO_PEDIDO\nSET @TALON_PED = @TALON_DEVILLESH\nSET @TOTAL_PEDI = 0\nINSERT INTO [DevilleSH].[dbo].[GVA21] (\n[DevilleSH].[dbo].[GVA21].[FILLER], [DevilleSH].[dbo].[GVA21].[APRUEBA], [DevilleSH].[dbo].[GVA21].[CIRCUITO],\n[DevilleSH].[dbo].[GVA21].[COD_CLIENT], [DevilleSH].[dbo].[GVA21].[COD_SUCURS], [DevilleSH].[dbo].[GVA21].[COD_TRANSP],\n[DevilleSH].[dbo].[GVA21].[COD_VENDED], [DevilleSH].[dbo].[GVA21].[COMENTARIO], [DevilleSH].[dbo].[GVA21].[COMP_STK],\n[DevilleSH].[dbo].[GVA21].[COND_VTA], [DevilleSH].[dbo].[GVA21].[COTIZ], [DevilleSH].[dbo].[GVA21].[ESTADO],\n[DevilleSH].[dbo].[GVA21].[EXPORTADO], [DevilleSH].[dbo].[GVA21].[FECHA_APRU], [DevilleSH].[dbo].[GVA21].[FECHA_ENTR],\n[DevilleSH].[dbo].[GVA21].[FECHA_PEDI], [DevilleSH].[dbo].[GVA21].[HORA_APRUE], [DevilleSH].[dbo].[GVA21].[ID_EXTERNO],\n[DevilleSH].[dbo].[GVA21].[LEYENDA_1], [DevilleSH].[dbo].[GVA21].[LEYENDA_2], [DevilleSH].[dbo].[GVA21].[LEYENDA_3],\n[DevilleSH].[dbo].[GVA21].[LEYENDA_4], [DevilleSH].[dbo].[GVA21].[LEYENDA_5], [DevilleSH].[dbo].[GVA21].[MON_CTE],\n[DevilleSH].[dbo].[GVA21].[N_LISTA], [DevilleSH].[dbo].[GVA21].[N_REMITO], [DevilleSH].[dbo].[GVA21].[NRO_O_COMP],\n[DevilleSH].[dbo].[GVA21].[NRO_PEDIDO], [DevilleSH].[dbo].[GVA21].[NRO_SUCURS], [DevilleSH].[dbo].[GVA21].[ORIGEN],\n[DevilleSH].[dbo].[GVA21].[PORC_DESC], [DevilleSH].[dbo].[GVA21].[REVISO_FAC], [DevilleSH].[dbo].[GVA21].[REVISO_PRE],\n[DevilleSH].[dbo].[GVA21].[REVISO_STK], [DevilleSH].[dbo].[GVA21].[TALONARIO], [DevilleSH].[dbo].[GVA21].[TALON_PED],\n[DevilleSH].[dbo].[GVA21].[TOTAL_PEDI], [DevilleSH].[dbo].[GVA21].[TIPO_ASIEN], [DevilleSH].[dbo].[GVA21].[MOTIVO],\n[DevilleSH].[dbo].[GVA21].[HORA], [DevilleSH].[dbo].[GVA21].[COD_CLASIF], [DevilleSH].[dbo].[GVA21].[ID_ASIENTO_MODELO_GV],\n[DevilleSH].[dbo].[GVA21].[TAL_PE_ORI], [DevilleSH].[dbo].[GVA21].[NRO_PE_ORI],\n--Nuevo T14 --\n[DevilleSH].[dbo].[GVA21].[FECHA_INGRESO],\n[DevilleSH].[dbo].[GVA21].[HORA_INGRESO],~~\n[DevilleSH].[dbo].[GVA21].[USUARIO_INGRESO],\n[DevilleSH].[dbo].[GVA21].[TERMINAL_INGRESO],\n[DevilleSH].[dbo].[GVA21].[FECHA_ULTIMA_MODIFICACION],\n[DevilleSH].[dbo].[GVA21].[HORA_ULTIMA_MODIFICACION],\n[DevilleSH].[dbo].[GVA21].[USUA_ULTIMA_MODIFICACION],\n[DevilleSH].[dbo].[GVA21].[TERM_ULTIMA_MODIFICACION],\n[DevilleSH].[dbo].[GVA21].[ID_DIRECCION_ENTREGA],\n[DevilleSH].[dbo].[GVA21].[ES_PEDIDO_WEB],\n--Nuevo T15--\n[DevilleSH].[dbo].[GVA21].[WEB_ORDER_ID],\n[DevilleSH].[dbo].[GVA21].[FECHA_O_COMP],\n[DevilleSH].[dbo].[GVA21].[ACTIVIDAD_COMPROBANTE_AFIP],\n[DevilleSH].[dbo].[GVA21].[ID_ACTIVIDAD_EMPRESA_AFIP],\n[DevilleSH].[dbo].[GVA21].[TIPO_DOCUMENTO_PAGADOR],\n[DevilleSH].[dbo].[GVA21].[NUMERO_DOCUMENTO_PAGADOR])\nVALUES (@FILLER, @APRUEBA, @CIRCUITO, @COD_CLIENT, @COD_SUCURS, @COD_TRANSP, @COD_VENDED, @COMENTARIO, @COMP_STK, @COND_VTA, @COTIZ,\n@ESTADOB, @EXPORTADO, @FECHA_APRU, @FECHA_ENTR, @FECHA_PEDI, @HORA_APRUE, @ID_EXTERNO, @LEYENDA_1, @LEYENDA_2, @LEYENDA_3,\n@LEYENDA_4, @LEYENDA_5, @MON_CTE, @N_LISTA, @N_REMITO, @NRO_O_COMP, @NRO_PEDIDO, @NRO_SUCURS, @ORIGEN, @PORC_DESC, @REVISO_FAC,\n@REVISO_PRE, @REVISO_STK, @TALONARIO, @TALON_PED, @TOTAL_PEDI, @TIPO_ASIEN, @MOTIVO, @HORA, @COD_CLASIF, @ID_ASIENTO_MODELO_GV,\n@TAL_PE_ORI, @NRO_PE_ORI,\n--T14 agregado--\n@FECHA_INGRESO,\n@HORA_INGRESO,\n@USUARIO_INGRESO,\n@TERMINAL_INGRESO,\n@FECHA_ULTIMA_MODIFICACION,\n@HORA_ULTIMA_MODIFICACION,\n@USUA_ULTIMA_MODIFICACION,\n@TERM_ULTIMA_MODIFICACION,\n@ID_DIRECCION_ENTREGA,\n@ES_PEDIDO_WEB,\n--T15 agregado--\n@WEB_ORDER_ID,\n@FECHA_O_COMP,\n@ACTIVIDAD_COMPROBANTE_AFIP,\n@ID_ACTIVIDAD_EMPRESA_AFIP,\n@TIPO_DOCUMENTO_PAGADOR,\n@NUMERO_DOCUMENTO_PAGADOR)\n\n------------------- Fin de inserciones de emcabezados de pedidos en la tabla GVA21------------------------------------\n\n~~~~~~~~----------------------------------------------------------------------------------------------------------------------\n--------------------- BUSCO EN EL PEDIDO ORIGINAL LA CANTIDAD DE RENGLONES PARA RECORRERLO ---------------------------\n------- PARA INSERTAR LOS VALORES CALCULADOS PARA EL PEDIDO CON TALONARIO~~111 y sucursal 0000 EMPRESA EMPREB---------\nSET @GVA_03_NUM_RENGLON = (SELECT~~~~ MAX(GVA03.N_RENGLON) AS Renglones FROM GVA03 INNER JOIN GVA105 ON GVA03.NRO_PEDIDO = GVA105.NRO_PEDIDO WHERE~~~~ (GVA03.NRO_PEDIDO = @NRO_PED_HIS) AND (GVA03.TALON_PED = 111) AND (GVA105.NCOMP_V = @NRO_FACTURA_ORIGEN))\nSET @GVA03_ACTUAL = 0\nSET @NRO_PEDIDO = @SUC_EMPREB+@NUMERO_PED+@controlPedidos\nSET @NRO_PEDIDO_EMPREB = @NRO_PEDIDO\n-- seteo los valores que insertare en la tabla GVA03 que es Renglones del pedido\n~~~~WHILE (@GVA03_ACTUAL <> @GVA_03_NUM_RENGLON)\n--PRECONDICION = MIENTRAS GVA03_ACTUAL SEA DISTINTO DEL MAXIMO DE RENGLONES ENTONCES\nBEGIN\nSET 