reB].[dbo].[GVA03].[CANT_PEN_F], [EmpreB].[dbo].[GVA03].[COD_ARTICU],\n[EmpreB].[dbo].[GVA03].[DESCUENTO] , [EmpreB].[dbo].[GVA03].[N_RENGLON] ,\n[EmpreB].[dbo].[GVA03].[NRO_PEDIDO], [EmpreB].[dbo].[GVA03].[PEN_REM_FC],\n[EmpreB].[dbo].[GVA03].[PEN_FAC_RE], [EmpreB].[dbo].[GVA03].[PRECIO],\n[EmpreB].[dbo].[GVA03].[TALON_PED] , [EmpreB].[dbo].[GVA03].[COD_CLASIF],\n--Nuevo T14---\n[EmpreB].[dbo].[GVA03].[CANT_A_DES_2],\n[EmpreB].[dbo].[GVA03].[CANT_A_FAC_2],\n[EmpreB].[dbo].[GVA03].[CANT_PEDID_2],\n[EmpreB].[dbo].[GVA03].[CANT_PEN_D_2],\n[EmpreB].[dbo].[GVA03].[CANT_PEN_F_2],\n[EmpreB].[dbo].[GVA03].[PEN_REM_FC_2],\n[EmpreB].[dbo].[GVA03].[PEN_FAC_RE_2],\n[EmpreB].[dbo].[GVA03].[ID_MEDIDA_VENTAS],\n[EmpreB].[dbo].[GVA03].[ID_MEDIDA_STOCK_2],\n[EmpreB].[dbo].[GVA03].[ID_MEDIDA_STOCK],\n[EmpreB].[dbo].[GVA03].[UNIDAD_MEDIDA_SELECCIONADA],\n--Nuevo T15--\n[EmpreB].[dbo].[GVA03].[COD_ARTICU_KIT],\n[EmpreB].[dbo].[GVA03].[RENGL_PADR],\n[EmpreB].[dbo].[GVA03].[PROMOCION],\n[EmpreB].[dbo].[GVA03].[PRECIO_ADICIONAL_KIT],\n[EmpreB].[dbo].[GVA03].[KIT_COMPLETO],\n[EmpreB].[dbo].[GVA03].[INSUMO_KIT_SEPARADO])\nVALUES (@GVA_03_FILLER,@GVA_03_CAN_EQUI_V,@GVA_03_CANT_A_DES,@GVA_03_CANT_A_FAC,@GVA_03_CANT_PEDID,@GVA_03_CANT_PEN_D,\n@GVA_03_CANT_PEN_F, @GVA_03_COD_ARTICU,@GVA_03_DESCUENTO,@GVA03_ACTUAL,@NRO_PEDIDO,@GVA_03_PEN_REM_FC,\n@GVA_03_PEN_FAC_RE,@GVA_03_PRECIO,@TALON_EMPREB,@GVA_03_COD_CLASIF,\n@GVA_03_CANT_A_DES_2,\n@GVA_03_CANT_A_FAC_2,\n@GVA_03_CANT_PEDID_2,\n@GVA_03_CANT_PEN_D_2,\n@GVA_03_CANT_PEN_F_2,\n@GVA_03_PEN_REM_FC_2,\n@GVA_03_PEN_FAC_RE_2,\n@GVA_03_ID_MEDIDA_VENTAS,\n@GVA_03_ID_MEDIDA_STOCK_2,\n@GVA_03_ID_MEDIDA_STOCK,\n@GVA_03_UNIDAD_MEDIDA_SELECCIONADA,\n--Nuevo T15\n@GVA_03_COD_ARTICU_KIT,\n@GVA_03_RENGL_PADR,\n@GVA_03_PROMOCION,\n@GVA_03_PRECIO_ADICIONAL_KIT,\n@GVA_03_KIT_COMPLETO,\n@GVA_03_INSUMO_KIT_SEPARADO)\nEND\n\n----------------------------------------------------------------------------------------------------------------------\n--------------------- BUSCO EN EL PEDIDO ORIGINAL LA CANTIDAD DE RENGLONES PARA RECORRERLO ---------------------------\n------- PARA INSERTAR LOS VALORES CALCULADOS PARA EL PEDIDO CON TALONARIO~~111 y sucursal 0000 EMPRESA DevilleSH------\n\nSET @GVA03_ACTUAL = 0\n------- Ocupo el mismo valor de la variable de numero de renglones @GVA_03_NUM_RENGLON para controlar con el while\nSET @NRO_PEDIDO = @SUC_DEVILLESH+@NUMERO_PED+@controlPedidos\nSET @NRO_PEDIDO_DEVILLE = @NRO_PEDIDO\nWHILE (@GVA03_ACTUAL <> @GVA_03_NUM_RENGLON)\n--PRECONDICION = MIENTRAS GVA03_ACTUAL SEA DISTINTO DEL MAXIMO DE RENGLONES ENTONCES\nBEGIN\nSET @GVA03_ACTUAL = (SELECT @GVA03_ACTUAL+1)\nSET @CUANTO_PEDIDO = (select [CENTRALIZADORA].[dbo].[GVA105].[CANT_FAC] FROM [CENTRALIZADORA].[dbo].[GVA105] WHERE (([CENTRALIZADORA].[dbo].[GVA105].[NRO_PEDIDO] = @NRO_PED_HIS) AND (([CENTRALIZADORA].[dbo].[GVA105].[TALON_PED] = 111)) AND ([CENTRALIZADORA].[dbo].[GVA105].[N_RENG_PED] = @GVA03_ACTUAL) AND ([CENTRALIZADORA].[dbo].[GVA105].[NCOMP_V] = @NRO_FACTURA_ORIGEN)))\nSET @GVA_03_FILLER = (select [CENTRALIZADORA].[dbo].[GVA03].[FILLER] FROM [CENTRALIZADORA].[dbo].[GVA03] WHERE (([CENTRALIZADORA].[dbo].[GVA03].[NRO_PEDIDO] = @NRO_PED_HIS)~~AND (([CENTRALIZADORA].[dbo].[GVA03].[TALON_PED] = 111)) AND ([CENTRALIZADORA].[dbo].[GVA03].[N_RENGLON] = @GVA03_ACTUAL)))\nSET @GVA_03_CAN_EQUI_V = (select [CENTRALIZADORA].[dbo].[GVA03].[CAN_EQUI_V] FROM [CENTRALIZADORA].[dbo].[GVA03] WHERE (([CENTRALIZADORA].[dbo].[GVA03].[NRO_PEDIDO] = @NRO_PED_HIS) AND (([CENTRALIZADORA].[dbo].[GVA03].[TALON_PED] = 111)) AND ([CENTRALIZADORA].[dbo].[GVA03].[N_RENGLON] = @GVA03_ACTUAL)))\n\nSET @GVA_03_CANT_A_DES =\nCASE\nWHEN (@GVA_14_PORC_DESC = 99) THEN (SELECT @CUANTO_PEDIDO)~~~~~~~~~~~~~~~~-- 99 significa 100% para DEVILLE SH\nWHEN (@GVA_14_PORC_DESC = 75) THEN (SELECT 0)~~~~~~~~~~~~~~~~~~~~~~~~~~~~ -- 75 significa 100% para ELLIVED_2011 o sea, 0 para DEVILLE SH\nWHEN (@GVA_14_PORC_DESC = 50) THEN (SELECT ROUND((@CUANTO_PEDIDO/2),0,1)) -- 50 significa