(57, 1, NULL, 1, 'Charly Yaciofani', 16057, '2026-04-08 10:15:00', '2026-04-08 11:10:00', 127, 'crm_clientes', 'ASOPROFARMA ASOCIACION PROPIETARIOS DE FARMACIAS COOPERATIVA', '30-53328511-9', 'edorfman@asoprofarma.com;personal@asoprofarma.com', 'Joel', 'X0065400007857', 'pendiente_envio_tango', 0, 17750, 'ASEHRS404', 'Asesoram. Inform Comercial CY', 0.00, 'ASESLD', NULL, 24, 2700, 'No se imputa, ases comercial: Se avisa a Joel que es necesario actualizar, que la versión actual del sistema está sin soporte, sería importante migrar cuanto antes. Se comenta que los menús y el sistema en general no varía, solo se migran diferentes ventanas al proceso web, pero que en esencia el sistema sigue siendo el mismo, se aguardará el ok para migrar.', 'No se imputa ases comercial, tiempo entre intercambios.', 3300, 600, 'success', NULL, '{\"FECHA_PEDIDO\":\"2026-04-08\",\"ID_GVA14\":130,\"ES_CLIENTE_HABITUAL\":true,\"NOTA_PEDIDO_WEB\":\"RXN_57\",\"ID_GVA43_TALON_PED\":45,\"ID_STA22\":1,\"ESTADO\":2,\"ID_GVA10\":1,\"ID_GVA23\":12,\"ID_GVA81\":24,\"ID_PERFIL_PEDIDO\":7,\"ID_MONEDA\":2,\"RENGLON_DTO\":[{\"ID_STA11\":4231,\"ARTICULO_CODIGO\":\"ASEHRS404\",\"CANTIDAD_PEDIDA\":0.1667,\"CANTIDAD_A_FACTURAR\":0.1667,\"CANTIDAD_PENDIENTE_A_FACTURAR\":0.1667,\"PRECIO\":0,\"PORCENTAJE_BONIFICACION\":0,\"DESCRIPCION_ARTICULO\":\"\",\"DESCRIPCION_ADICIONAL_ARTICULO\":\"\"}]}', '{\"status\":200,\"data\":{\"savedId\":27272,\"savedConcurrencyToken\":null,\"savedRecord\":null,\"recordPosition\":-1,\"recordAffectedCount\":6,\"printingDestinationModel\":null,\"file\":null,\"message\":null,\"exceptionInfo\":null,\"succeeded\":true}}', 27272, 'X00654-00007857', 2, '2026-04-19 11:07:00', 0.1667, NULL, NULL, NULL, '2026-04-10 18:21:50', '2026-04-19 14:07:00', NULL, 0, NULL, NULL, NULL),
