(86, 1, NULL, 8, 'Seba Mora', 16086, '2026-04-14 10:29:00', '2026-04-14 10:47:00', 171, 'crm_clientes', 'IRON GROUP S.A.', '33-70778442-9', 'iron.soporte@e-reaxion.com.ar', 'Carolina', 'X0066100002283', 'pendiente_envio_tango', 0, 18398, 'ASEHRS511', 'Asesoramiento Informatico  SM', 0.00, 'ASETGO', NULL, 37, 0, 'Carolina indica que no pueden emitir facturas - Se accede al servidor,con el usuario Administrador del equipo y Supervisor de Tango, se realiza la validación de los certificados y arroja el error que envía Carolina.  Se corrobora que las librerias afectadas no se encuentan.  Se verifica el AV que las eliminó por ser detectadas como amenazas. Se copian DLL, se verifica nuevamente, realiza la comunicación con éxito.  Se le pide que emita con CAE las facturas, logra hacerlo ok.  Luego se le explica el motivo por el cual sucedió esto y que se dejó excluida la carpeta de Tango para evitar estos inconvenientes', NULL, 1080, 1080, 'success', NULL, '{\"FECHA_PEDIDO\":\"2026-04-14\",\"ID_GVA14\":229,\"ES_CLIENTE_HABITUAL\":true,\"NOTA_PEDIDO_WEB\":\"RXN_86\",\"ID_GVA43_TALON_PED\":48,\"ID_STA22\":1,\"ESTADO\":2,\"ID_GVA10\":1,\"ID_GVA23\":10,\"ID_GVA81\":37,\"ID_PERFIL_PEDIDO\":10,\"ID_MONEDA\":2,\"RENGLON_DTO\":[{\"ID_STA11\":3899,\"ARTICULO_CODIGO\":\"ASEHRS511\",\"CANTIDAD_PEDIDA\":0.3,\"CANTIDAD_A_FACTURAR\":0.3,\"CANTIDAD_PENDIENTE_A_FACTURAR\":0.3,\"PRECIO\":0,\"PORCENTAJE_BONIFICACION\":0,\"DESCRIPCION_ARTICULO\":\"\",\"DESCRIPCION_ADICIONAL_ARTICULO\":\"\"}]}', '{\"status\":200,\"data\":{\"savedId\":27303,\"savedConcurrencyToken\":null,\"savedRecord\":null,\"recordPosition\":-1,\"recordAffectedCount\":6,\"printingDestinationModel\":null,\"file\":null,\"message\":null,\"exceptionInfo\":null,\"succeeded\":true}}', 27303, 'X00661-00002283', 2, '2026-04-19 11:07:00', 0.3000, NULL, NULL, NULL, '2026-04-14 17:54:10', '2026-04-19 14:07:00', NULL, 0, NULL, NULL, NULL),
(87, 1, NULL, 8, 'Seba Mora', 16087, '2026-04-14 11:05:00', '2026-04-14 11:12:00', 65, 'crm_clientes', 'BLEAR INTERNATIONAL S A', '30-69456925-7', 'blear.soporte@e-reaxion.com.ar', 'Belen', 'X0066100002284', 'pendiente_envio_tango', 0, 18398, 'ASEHRS511', 'Asesoramiento Informatico  SM', 0.00, 'ASETGO', NULL, 37, 0, 'Belen indica que Tango le arrojó un mensaje de que no tiene recursos. Se accede al servidor, se revisan servicios, componentes, estado de servidor, y está todo ok. Se le cierran las ventanas de Tango a Belen y se le pide que pruebe nuevamente.  Sin feedback', NULL, 420, 420, 'success', NULL, '{\"FECHA_PEDIDO\":\"2026-04-14\",\"ID_GVA14\":65,\"ES_CLIENTE_HABITUAL\":true,\"NOTA_PEDIDO_WEB\":\"RXN_87\",\"ID_GVA43_TALON_PED\":48,\"ID_STA22\":1,\"ESTADO\":2,\"ID_GVA10\":1,\"ID_GVA23\":10,\"ID_GVA81\":37,\"ID_PERFIL_PEDIDO\":10,\"ID_MONEDA\":2,\"RENGLON_DTO\":[{\"ID_STA11\":3899,\"ARTICULO_CODIGO\":\"ASEHRS511\",\"CANTIDAD_PEDIDA\":0.1167,\"CANTIDAD_A_FACTURAR\":0.1167,\"CANTIDAD_PENDIENTE_A_FACTURAR\":0.1167,\"PRECIO\":0,\"PORCENTAJE_BONIFICACION\":0,\"DESCRIPCION_ARTICULO\":\"\",\"DESCRIPCION_ADICIONAL_ARTICULO\":\"\"}]}', '{\"status\":200,\"data\":{\"savedId\":27304,\"savedConcurrencyToken\":null,\"savedRecord\":null,\"recordPosition\":-1,\"recordAffectedCount\":6,\"printingDestinationModel\":null,\"file\":null,\"message\":null,\"exceptionInfo\":null,\"succeeded\":true}}', 27304, 'X00661-00002284', 2, '2026-04-19 11:07:00', 0.1167, NULL, NULL, NULL, '2026-04-14 17:57:00', '2026-04-19 14:07:00', NULL, 0, NULL, NULL, NULL),
(88, 1, NULL, 8, 'Seba Mora', 16088, '2026-04-14 09:12:00', '2026-04-14 09:25:00', 421, 'crm_clientes', 'IMPES   S R L', '30-64639242-6', 'impes.soporte@e-reaxion.com.ar', 'Alejandro', 'X0066100002285', 'pendiente_envio_tango', 0, 18398, 'ASEHRS511', 'Asesoramiento Informatico  SM', 0.00, 'ASETGO', NULL, 37, 0, 'Alejandro indica que un equipo no logra actualizar Tango.  Se accede y se verifica que no ve las carpetas del servidor, lo cual es extraño, ya que si están en el dominio, los usuarios autentican mediante AD.  Alejandro coloca credenciales para que pueda ver las carpetas, se copia de manera manual el cliente Tango y logra actualizar y acceder correctamente.\r\nSe le sugiere a Alejandro que vuelva a unir el equipo a la red, ya que debería poder ver las carpetas del servidor Tango sin inconvenientes.', NULL, 780, 780, 'success', NULL, '{\"FECHA_PEDIDO\":\"2026-04-14\",\"ID_GVA14\":550,\"ES_CLIENTE_HABITUAL\":true,\"NOTA_PEDIDO_WEB\":\"RXN_88\",\"ID_GVA43_TALON_PED\":48,\"ID_STA22\":1,\"ESTADO\":2,\"ID_GVA10\":1,\"ID_GVA23\":10,\"ID_GVA81\":37,\"ID_PERFIL_PEDIDO\":10,\"ID_MONEDA\":2,\"RENGLON_DTO\":[{\"ID_STA11\":3899,\"ARTICULO_CODIGO\":\"ASEHRS511\",\"CANTIDAD_PEDIDA\":0.2167,\"CANTIDAD_A_FACTURAR\":0.2167,\"CANTIDAD_PENDIENTE_A_FACTURAR\":0.2167,\"PRECIO\":0,\"PORCENTAJE_BONIFICACION\":0,\"DESCRIPCION_ARTICULO\":\"\",\"DESCRIPCION_ADICIONAL_ARTICULO\":\"\"}]}', '{\"status\":200,\"data\":{\"savedId\":27305,\"savedConcurrencyToken\":null,\"savedRecord\":null,\"recordPosition\":-1,\"recordAffectedCount\":6,\"printingDestinationModel\":null,\"file\":null,\"message\":null,\"exceptionInfo\":null,\"succeeded\":true}}', 27305, 'X00661-00002285', 2, '2026-04-19 11:07:00', 0.2167, NULL, NULL, NULL, '2026-04-14 18:00:07', '2026-04-19 14:07:00', NULL, 0, NULL, NULL, NULL),
(89, 1, NULL, 8, 'Seba Mora', 16089, '2026-04-14 11:16:00', '2026-04-14 11:20:00', 421, 'crm_clientes', 'IMPES   S R L', '30-64639242-6', 'impes.soporte@e-reaxion.com.ar', 'Juan Carlos', 'X0066100002286', 'pendiente_envio_tango', 0, 17504, 'ASEHRS611', 'Asesoram. Inform. Telef.    SM', 0.00, 'ASERED', NULL, 32, 0, 'Intercambios vía Whatsapp con JC referidos a mejoras en el Hardware y Software para migrar el Server de Tango.\r\nSe envía link para que tenga los requerimientos solicitados por Axoft \r\nhttps://ayudas.axoft.com/25ar/instalacion/#requerimientos-tecnicos', NULL, 240, 240, 'success', NULL, '{\"FECHA_PEDIDO\":\"2026-04-14\",\"ID_GVA14\":550,\"ES_CLIENTE_HABITUAL\":true,\"NOTA_PEDIDO_WEB\":\"RXN_89\",\"ID_GVA43_TALON_PED\":48,\"ID_STA22\":1,\"ESTADO\":2,\"ID_GVA10\":1,\"ID_GVA23\":10,\"ID_GVA81\":32,\"ID_PERFIL_PEDIDO\":10,\"ID_MONEDA\":2,\"RENGLON_DTO\":[{\"ID_STA11\":3954,\"ARTICULO_CODIGO\":\"ASEHRS611\",\"CANTIDAD_PEDIDA\":0.0667,\"CANTIDAD_A_FACTURAR\":0.0667,\"CANTIDAD_PENDIENTE_A_FACTURAR\":0.0667,\"PRECIO\":0,\"PORCENTAJE_BONIFICACION\":0,\"DESCRIPCION_ARTICULO\":\"\",\"DESCRIPCION_ADICIONAL_ARTICULO\":\"\"}]}', '{\"status\":200,\"data\":{\"savedId\":27306,\"savedConcurrencyToken\":null,\"savedRecord\":null,\"recordPosition\":-1,\"recordAffectedCount\":6,\"printingDestinationModel\":null,\"file\":null,\"message\":null,\"exceptionInfo\":null,\"succeeded\":true}}', 27306, 'X00661-00002286', 2, '2026-04-19 11:07:00', 0.0667, NULL, NULL, NULL, '2026-04-14 18:04:32', '2026-04-19 14:07:00', NULL, 0, NULL, NULL, NULL);
