(44, 2, 16, '{\"page\":{\"size\":\"A4\",\"orientation\":\"portrait\",\"width_mm\":210,\"height_mm\":297,\"margin_top_mm\":0,\"margin_right_mm\":0,\"margin_bottom_mm\":0,\"margin_left_mm\":0},\"grid\":{\"enabled\":true,\"step_mm\":2,\"snap\":true},\"background\":{\"asset_id\":null,\"opacity\":1},\"defaults\":{\"font_family\":\"Arial, Helvetica, sans-serif\",\"font_size_pt\":12,\"color\":\"#111111\"}}', '[{\"id\":\"obj_title_text\",\"type\":\"text\",\"x_mm\":8,\"y_mm\":70,\"w_mm\":190,\"h_mm\":36,\"z_index\":10,\"content\":\"Recuerde que el <b>Detalle de las Tareas</b> es enviado al finalizar los trabajos, Ud. cuenta con 48 hs para efectuar cualquier consulta o reclamo. Puede solicitar el informe completo de las tareas cuando lo de desee.\",\"style\":{\"font_family\":\"Arial, Helvetica, sans-serif\",\"font_size_pt\":16,\"font_weight\":700,\"color\":\"#111111\",\"align\":\"left\"}},{\"id\":\"obj_body_text\",\"type\":\"text\",\"x_mm\":8,\"y_mm\":46,\"w_mm\":126,\"h_mm\":18,\"z_index\":10,\"content\":\"Estimado {cliente.nombre}, adjuntamos el detalle de tareas realizadas Nº {pedido.numero}\",\"style\":{\"font_family\":\"Arial, Helvetica, sans-serif\",\"font_size_pt\":12,\"font_weight\":400,\"color\":\"#333333\",\"align\":\"left\"}},{\"id\":\"obj_variable_1774901635485_6607\",\"type\":\"variable\",\"x_mm\":0,\"y_mm\":0,\"w_mm\":226,\"h_mm\":38,\"z_index\":10,\"source\":\"empresa.header_url\",\"style\":{\"font_family\":\"Arial, Helvetica, sans-serif\",\"font_size_pt\":12,\"font_weight\":400,\"color\":\"#111111\",\"align\":\"left\"}},{\"id\":\"obj_variable_1774901645637_722\",\"type\":\"variable\",\"x_mm\":0,\"y_mm\":138,\"w_mm\":214,\"h_mm\":40,\"z_index\":10,\"source\":\"empresa.footer_url\",\"style\":{\"font_family\":\"Arial, Helvetica, sans-serif\",\"font_size_pt\":12,\"font_weight\":400,\"color\":\"#111111\",\"align\":\"left\"}},{\"id\":\"obj_text_1775072647857_3201\",\"type\":\"text\",\"x_mm\":8,\"y_mm\":110,\"w_mm\":70,\"h_mm\":8,\"z_index\":10,\"content\":\"Desde ya, muchas gracias.\",\"style\":{\"font_family\":\"Arial, Helvetica, sans-serif\",\"font_size_pt\":12,\"font_weight\":400,\"color\":\"#111111\",\"align\":\"left\"}},{\"id\":\"obj_text_1775072663150_476\",\"type\":\"text\",\"x_mm\":8,\"y_mm\":126,\"w_mm\":70,\"h_mm\":8,\"z_index\":10,\"content\":\"<b>Dpto. Soporte y Capacitación</b>\",\"style\":{\"font_family\":\"Arial, Helvetica, sans-serif\",\"font_size_pt\":12,\"font_weight\":400,\"color\":\"#111111\",\"align\":\"left\"}}]', '{\"used\":[\"Arial, Helvetica, sans-serif\"]}', NULL, NULL, 1, '2026-04-03 15:31:42'),
